      function normalizeWorkspaceRevision(value) {
        const numeric = Number(value);
        return Number.isFinite(numeric) && numeric > 0 ? Math.round(numeric) : 0;
      }

      function setStartupSplashProgress(percent, stage, label) {
        const bar = document.querySelector("#startup-progress-bar");
        const value = document.querySelector("#startup-progress-value");
        const stageNode = document.querySelector("#startup-progress-stage");
        const labelNode = document.querySelector("#startup-progress-label");
        const clampedPercent = Math.max(0, Math.min(100, Math.round(percent || 0)));
        if (bar) {
          bar.style.setProperty("--startup-progress", clampedPercent + "%");
          bar.style.width = clampedPercent + "%";
        }
        if (value) {
          value.textContent = clampedPercent + "%";
        }
        if (stageNode && stage) {
          stageNode.textContent = stage;
        }
        if (labelNode && label) {
          labelNode.textContent = label;
        }
      }

      function clearStartupSplashTimers() {
        startupSplashTimers.forEach((timerId) => {
          window.clearTimeout(timerId);
        });
        startupSplashTimers = [];
      }

      function startStartupSplashSequence() {
        startupSplashFailed = false;
        setStartupSplashProgress(
          12,
          "Booting JADE Hummingbird systems",
          "Preparing your tournament workspace.",
        );
        clearStartupSplashTimers();
        STARTUP_PROGRESS_STEPS.forEach((step) => {
          const timerId = window.setTimeout(() => {
            setStartupSplashProgress(step.percent, step.stage, step.label);
          }, step.delay);
          startupSplashTimers.push(timerId);
        });
      }

      function dismissStartupSplash() {
        const splash = document.querySelector("#startup-splash");
        if (!splash || startupSplashDismissed) return;
        startupSplashDismissed = true;
        clearStartupSplashTimers();
        splash.classList.add("is-exiting");
        window.setTimeout(() => {
          splash.setAttribute("hidden", "hidden");
          splash.remove();
        }, STARTUP_SPLASH_EXIT_MS);
      }

      async function finishStartupSplash() {
        clearStartupSplashTimers();
        const splash = document.querySelector("#startup-splash");
        if (splash && !startupSplashFailed) {
          splash.classList.add("is-ready");
        }
        if (!startupSplashFailed) {
          setStartupSplashProgress(
            100,
            "Workspace ready",
            "Ready to open JADE Hummingbird.",
          );
        }
        const elapsed = Date.now() - STARTUP_SPLASH_STARTED_AT;
        const remaining = Math.max(0, STARTUP_SPLASH_MIN_MS - elapsed);
        if (remaining) {
          await new Promise((resolve) => window.setTimeout(resolve, remaining));
        }
        window.requestAnimationFrame(() => {
          dismissStartupSplash();
        });
      }

      function getEmptySession() {
        return {
          userEmail: "",
          cloudSessionToken: "",
          view: "overview",
          peopleSection: "hub",
          peopleAppointeeTournamentId: "",
          peopleDirectoryQuery: "",
          peopleDirectoryFilter: "all",
          peopleDirectoryPage: 1,
          peopleSignupQuery: "",
          peopleSignupFilter: "all",
          peopleSignupPage: 1,
          peopleAppointeeQuery: "",
          linksAccountQuery: "",
          linksAccountPage: 1,
          linksPortalQuery: "",
          linksPortalPage: 1,
          regionalStaffQuery: "",
          regionalStaffPage: 1,
          regionalReportsQuery: "",
          regionalReportsPage: 1,
          regionalFundingQuery: "",
          regionalFundingStatus: "all",
          regionalFundingPage: 1,
          selectedPeopleEmail: "",
          managedTournamentId: "",
          selectedTournamentId: "",
          selectedTournamentBoardTab: "overview",
          focusedTournamentSection: "spotlight",
          recentTournamentIds: [],
          recentViewKeys: [],
          recentParticipantKeys: [],
          tournamentQuery: "",
          tournamentFilter: "all",
          searchQuery: "",
          selectedParticipantKey: "",
        };
      }

      function normalizeEmail(value) {
        return String(value || "").trim().toLowerCase();
      }

      function normalizeTextKey(value) {
        return String(value || "").trim().toLowerCase();
      }

      function createWorkspaceContractError(context = "workspace", detail = "") {
        const error = new Error(
          "JADE Hummingbird blocked a workspace sync because the live data contract did not match the current system" +
            (detail ? ": " + detail : "."),
        );
        error.code = "workspace_contract_mismatch";
        error.context = context;
        return error;
      }

      function assertWorkspaceContract(candidate, context = "workspace", options = {}) {
        const requireVersion = options.requireVersion !== false;
        if (!candidate || typeof candidate !== "object" || Array.isArray(candidate)) {
          throw createWorkspaceContractError(context, "workspace data was not an object");
        }

        REQUIRED_WORKSPACE_ROOT_KEYS.forEach((key) => {
          if (!Object.prototype.hasOwnProperty.call(candidate, key)) {
            throw createWorkspaceContractError(context, `missing "${key}"`);
          }
        });

        const contractVersion = String(candidate.workspaceContractVersion || "").trim();
        if (requireVersion && contractVersion !== WORKSPACE_CONTRACT_VERSION) {
          throw createWorkspaceContractError(
            context,
            `expected contract ${WORKSPACE_CONTRACT_VERSION} but received ${contractVersion || "none"}`,
          );
        }

        const regionalOperations = candidate.regionalOperations;
        if (
          !regionalOperations ||
          typeof regionalOperations !== "object" ||
          Array.isArray(regionalOperations)
        ) {
          throw createWorkspaceContractError(context, "regional operations state was invalid");
        }

        REQUIRED_REGIONAL_OPERATIONS_KEYS.forEach((key) => {
          if (!Array.isArray(regionalOperations[key])) {
            throw createWorkspaceContractError(
              context,
              `regionalOperations.${key} must be an array`,
            );
          }
        });

        if (!Array.isArray(candidate.users)) {
          throw createWorkspaceContractError(context, "users must be an array");
        }
        if (!Array.isArray(candidate.tournaments)) {
          throw createWorkspaceContractError(context, "tournaments must be an array");
        }
        if (!Array.isArray(candidate.recoveryRequests)) {
          throw createWorkspaceContractError(context, "recoveryRequests must be an array");
        }

        const seenEmails = new Set();
        candidate.users.forEach((user, index) => {
          if (!user || typeof user !== "object" || Array.isArray(user)) {
            throw createWorkspaceContractError(context, `user ${index + 1} was invalid`);
          }
          REQUIRED_USER_CONTRACT_KEYS.forEach((key) => {
            if (!Object.prototype.hasOwnProperty.call(user, key)) {
              throw createWorkspaceContractError(
                context,
                `user ${index + 1} is missing "${key}"`,
              );
            }
          });
          const email = normalizeEmail(user.email);
          if (!email) {
            throw createWorkspaceContractError(context, `user ${index + 1} is missing an email`);
          }
          if (seenEmails.has(email)) {
            throw createWorkspaceContractError(context, `duplicate user email "${email}"`);
          }
          seenEmails.add(email);
        });

        const seenTournamentIds = new Set();
        candidate.tournaments.forEach((tournament, index) => {
          if (!tournament || typeof tournament !== "object" || Array.isArray(tournament)) {
            throw createWorkspaceContractError(context, `tournament ${index + 1} was invalid`);
          }
          const id = String(tournament.id || "").trim();
          if (!id) {
            throw createWorkspaceContractError(
              context,
              `tournament ${index + 1} is missing an id`,
            );
          }
          if (seenTournamentIds.has(id)) {
            throw createWorkspaceContractError(context, `duplicate tournament id "${id}"`);
          }
          seenTournamentIds.add(id);
        });

        return candidate;
      }

      function createId(prefix) {
        return prefix + "-" + Math.random().toString(36).slice(2, 10);
      }

      function normalizeStringList(value, max = 12) {
        if (!Array.isArray(value)) {
          return [];
        }

        return Array.from(
          new Set(
            value
              .map((item) => String(item || "").trim())
              .filter(Boolean),
          ),
        ).slice(0, max);
      }

      function isLocalAppRuntime() {
        const host = String(window.location.hostname || "").trim().toLowerCase();
        return (
          window.location.protocol === "file:" ||
          host === "localhost" ||
          host === "127.0.0.1"
        );
      }

      function requiresSharedBackend() {
        return !isLocalAppRuntime();
      }

      function getSharedBackendUnavailableMessage() {
        if (cloudRuntime.contractMismatch) {
          return "The shared JADE Hummingbird backend is running a different data contract. Redeploy the frontend and backend together before using shared accounts.";
        }
        return "The shared account service is unavailable right now. Please try again in a moment.";
      }

      function buildHostedBlankState() {
        return {
          workspaceContractVersion: WORKSPACE_CONTRACT_VERSION,
          version: 1,
          appSettings: clone(DEFAULT_SETTINGS),
          users: [],
          recoveryRequests: [],
          tournaments: [],
          regionalOperations: normalizeRegionalOperationsState(),
        };
      }

      function normalizeSessionRecord(record = {}) {
        return {
          userEmail: normalizeEmail(record.userEmail),
          cloudSessionToken: String(record.cloudSessionToken || "").trim(),
          view: String(record.view || "overview").trim() || "overview",
          peopleSection: "hub",
          peopleAppointeeTournamentId: String(record.peopleAppointeeTournamentId || "").trim(),
          peopleDirectoryQuery: String(record.peopleDirectoryQuery || "").trim(),
          peopleDirectoryFilter: normalizePeopleDirectoryFilter(record.peopleDirectoryFilter),
          peopleDirectoryPage: Math.max(1, Number.parseInt(record.peopleDirectoryPage, 10) || 1),
          peopleSignupQuery: String(record.peopleSignupQuery || "").trim(),
          peopleSignupFilter: normalizeSignupDashboardFilter(record.peopleSignupFilter),
          peopleSignupPage: Math.max(1, Number.parseInt(record.peopleSignupPage, 10) || 1),
          peopleAppointeeQuery: String(record.peopleAppointeeQuery || "").trim(),
          linksAccountQuery: String(record.linksAccountQuery || "").trim(),
          linksAccountPage: Math.max(1, Number.parseInt(record.linksAccountPage, 10) || 1),
          linksPortalQuery: String(record.linksPortalQuery || "").trim(),
          linksPortalPage: Math.max(1, Number.parseInt(record.linksPortalPage, 10) || 1),
          regionalStaffQuery: String(record.regionalStaffQuery || "").trim(),
          regionalStaffPage: Math.max(1, Number.parseInt(record.regionalStaffPage, 10) || 1),
          regionalReportsQuery: String(record.regionalReportsQuery || "").trim(),
          regionalReportsPage: Math.max(1, Number.parseInt(record.regionalReportsPage, 10) || 1),
          regionalFundingQuery: String(record.regionalFundingQuery || "").trim(),
          regionalFundingStatus: normalizeRegionalFundingStatusFilter(
            record.regionalFundingStatus,
          ),
          regionalFundingPage: Math.max(1, Number.parseInt(record.regionalFundingPage, 10) || 1),
          selectedPeopleEmail: normalizeEmail(record.selectedPeopleEmail),
          managedTournamentId: String(record.managedTournamentId || "").trim(),
          selectedTournamentId: String(record.selectedTournamentId || "").trim(),
          selectedTournamentBoardTab:
            String(record.selectedTournamentBoardTab || "overview").trim().toLowerCase() ||
            "overview",
          focusedTournamentSection:
            String(record.focusedTournamentSection || "spotlight").trim().toLowerCase() ||
            "spotlight",
          recentTournamentIds: normalizeStringList(record.recentTournamentIds, 8),
          recentViewKeys: normalizeStringList(record.recentViewKeys, 8),
          recentParticipantKeys: normalizeStringList(record.recentParticipantKeys, 8),
          tournamentQuery: String(record.tournamentQuery || "").trim(),
          tournamentFilter:
            String(record.tournamentFilter || "all").trim().toLowerCase() || "all",
          searchQuery: String(record.searchQuery || "").trim(),
          selectedParticipantKey: String(record.selectedParticipantKey || "").trim(),
        };
      }

      function normalizePeopleSection(value = "") {
        const normalized = String(value || "").trim().toLowerCase();
        if (["hub", "directory", "signups", "appointees", "access"].includes(normalized)) {
          return normalized;
        }
        return "hub";
      }

      function normalizePeopleDirectoryFilter(value = "") {
        const normalized = String(value || "").trim().toLowerCase();
        if (
          [
            "all",
            "active",
            "disabled",
            "staff",
            "regional",
            "manager_created",
            "self_signup",
          ].includes(normalized)
        ) {
          return normalized;
        }
        return "all";
      }

      function normalizeSignupDashboardFilter(value = "") {
        const normalized = String(value || "").trim().toLowerCase();
        if (["all", "self_signup", "manager_created", "registered", "active", "disabled"].includes(normalized)) {
          return normalized;
        }
        return "all";
      }

      function normalizeRegionalFundingStatusFilter(value = "") {
        const normalized = String(value || "").trim().toLowerCase();
        if (["all", "pending", "approved", "rejected", "paid"].includes(normalized)) {
          return normalized;
        }
        return "all";
      }

      function timestamp() {
        return new Date().toLocaleString();
      }

      function normalizeTimestampKey(value, fallbackText = "") {
        const numeric = Number(value);
        if (Number.isFinite(numeric) && numeric > 0) {
          return Math.round(numeric);
        }
        const parsed = Date.parse(String(fallbackText || "").trim());
        return Number.isFinite(parsed) && parsed > 0 ? parsed : 0;
      }

      function clearWorkspaceRouteParams(url) {
        if (!url) {
          return;
        }
        WORKSPACE_ROUTE_QUERY_KEYS.forEach((key) => {
          url.searchParams.delete(key);
        });
      }

      function requestSessionHistoryPush() {
        pendingSessionHistoryMode = "push";
      }

      function markUserInteraction() {
        lastUserInteractionAt = Date.now();
      }

      function shouldTrackFormDraft(form) {
        if (!form || form.tagName !== "FORM") {
          return false;
        }
        const formName = String(form.dataset.form || "").trim();
        if (!formName || SENSITIVE_FORM_DRAFTS.has(formName)) {
          return false;
        }
        return true;
      }

      function getFormDraftKey(form) {
        if (!shouldTrackFormDraft(form)) {
          return "";
        }
        const keyParts = [String(form.dataset.form || "").trim()];
        TRACKED_FORM_DRAFT_DATASET_KEYS.forEach((datasetKey) => {
          const value = String(form.dataset[datasetKey] || "").trim();
          if (value) {
            keyParts.push(datasetKey + ":" + value);
          }
        });
        return keyParts.join("|");
      }

      function escapeCssSelectorValue(value = "") {
        if (window.CSS && typeof window.CSS.escape === "function") {
          return window.CSS.escape(String(value || ""));
        }
        return String(value || "")
          .replaceAll("\\", "\\\\")
          .replaceAll('"', '\\"');
      }

      function normalizeDraftDatasetAttributeKey(datasetKey = "") {
        return "data-" + String(datasetKey || "").replace(/[A-Z]/g, (match) => "-" + match.toLowerCase());
      }

      function parseFormDraftKey(draftKey = "") {
        const normalized = String(draftKey || "").trim();
        if (!normalized) {
          return null;
        }
        const tokens = normalized.split("|").filter(Boolean);
        if (!tokens.length) {
          return null;
        }
        const formName = String(tokens[0] || "").trim();
        if (!formName) {
          return null;
        }
        const datasetValues = {};
        tokens.slice(1).forEach((token) => {
          const splitIndex = token.indexOf(":");
          if (splitIndex <= 0) {
            return;
          }
          const datasetKey = String(token.slice(0, splitIndex) || "").trim();
          if (!TRACKED_FORM_DRAFT_DATASET_KEYS.includes(datasetKey)) {
            return;
          }
          const datasetValue = String(token.slice(splitIndex + 1) || "").trim();
          if (!datasetValue) {
            return;
          }
          datasetValues[datasetKey] = datasetValue;
        });
        return {
          formName,
          datasetValues,
        };
      }

      function getTrackedFormElementByDraftKey(draftKey = "") {
        const parsed = parseFormDraftKey(draftKey);
        if (!parsed) {
          return null;
        }
        const selectorParts = [
          `form[data-form="${escapeCssSelectorValue(parsed.formName)}"]`,
        ];
        Object.entries(parsed.datasetValues).forEach(([datasetKey, datasetValue]) => {
          selectorParts.push(
            `[${normalizeDraftDatasetAttributeKey(datasetKey)}="${escapeCssSelectorValue(
              datasetValue,
            )}"]`,
          );
        });
        const selector = selectorParts.join("");
        const exactMatch = document.querySelector(selector);
        if (exactMatch && getFormDraftKey(exactMatch) === draftKey) {
          return exactMatch;
        }
        const scopedForms = document.querySelectorAll(
          `form[data-form="${escapeCssSelectorValue(parsed.formName)}"]`,
        );
        for (const form of scopedForms) {
          if (getFormDraftKey(form) === draftKey) {
            return form;
          }
        }
        return null;
      }

      function readFormDraftValues(form) {
        const values = {};
        const fields = form.querySelectorAll("input[name], textarea[name], select[name]");
        fields.forEach((field) => {
          if (!field.name || field.disabled || field.type === "file") {
            return;
          }
          const fieldName = String(field.name).trim();
          if (!fieldName) {
            return;
          }
          if (field.type === "radio") {
            if (field.checked) {
              values[fieldName] = String(field.value || "");
            }
            return;
          }
          if (field.type === "checkbox") {
            values[fieldName] = Boolean(field.checked);
            return;
          }
          if (field.tagName === "SELECT" && field.multiple) {
            values[fieldName] = Array.from(field.options)
              .filter((option) => option.selected)
              .map((option) => String(option.value || ""));
            return;
          }
          values[fieldName] = String(field.value || "");
        });
        return values;
      }

      function hasMeaningfulDraftValues(values = {}) {
        return Object.values(values).some((value) => {
          if (Array.isArray(value)) {
            return value.length > 0;
          }
          if (typeof value === "boolean") {
            return value;
          }
          return Boolean(String(value || "").trim());
        });
      }

      function rememberFormDraft(form) {
        const draftKey = getFormDraftKey(form);
        if (!draftKey) {
          return;
        }
        const values = readFormDraftValues(form);
        if (!hasMeaningfulDraftValues(values)) {
          dirtyFormDraftKeys.delete(draftKey);
          formDraftCache.delete(draftKey);
          return;
        }
        dirtyFormDraftKeys.add(draftKey);
        formDraftCache.set(draftKey, values);
      }

      function captureVisibleFormDrafts() {
        if (!dirtyFormDraftKeys.size) {
          return;
        }
        dirtyFormDraftKeys.forEach((draftKey) => {
          const form = getTrackedFormElementByDraftKey(draftKey);
          if (!form) {
            return;
          }
          rememberFormDraft(form);
        });
      }

      function applyDraftValueToField(field, value) {
        if (!field || field.disabled || field.type === "file") {
          return;
        }
        if (field.type === "radio") {
          field.checked = String(field.value || "") === String(value || "");
          return;
        }
        if (field.type === "checkbox") {
          field.checked = Boolean(value);
          return;
        }
        if (field.tagName === "SELECT" && field.multiple && Array.isArray(value)) {
          const selected = new Set(value.map((entry) => String(entry || "")));
          Array.from(field.options).forEach((option) => {
            option.selected = selected.has(String(option.value || ""));
          });
          return;
        }
        if (typeof value === "string" || typeof value === "number") {
          field.value = String(value);
        }
      }

      function restoreTrackedFormDrafts() {
        if (!dirtyFormDraftKeys.size || !formDraftCache.size) {
          return;
        }
        dirtyFormDraftKeys.forEach((draftKey) => {
          const form = getTrackedFormElementByDraftKey(draftKey);
          if (!form) {
            return;
          }
          const values = formDraftCache.get(draftKey);
          if (!values || typeof values !== "object") {
            return;
          }
          Object.entries(values).forEach(([fieldName, value]) => {
            const fields = Array.from(form.querySelectorAll("[name]")).filter(
              (field) => String(field.name || "") === String(fieldName || ""),
            );
            if (!fields.length) {
              return;
            }
            fields.forEach((field) => {
              applyDraftValueToField(field, value);
            });
          });
        });
      }

      function hasEditableFocus() {
        const active = document.activeElement;
        if (!active || active === document.body) {
          return false;
        }
        const tag = String(active.tagName || "").toLowerCase();
        if (tag === "textarea") {
          return !active.disabled && !active.readOnly;
        }
        if (tag === "select") {
          return !active.disabled;
        }
        if (tag === "input") {
          const type = String(active.type || "text").trim().toLowerCase();
          if (
            ["button", "submit", "reset", "radio", "checkbox", "file", "image", "color"].includes(
              type,
            )
          ) {
            return false;
          }
          return !active.disabled && !active.readOnly;
        }
        return Boolean(active.isContentEditable);
      }

      function canRunLiveSharedRefresh() {
        const now = Date.now();
        if (!getCurrentUser() || !session.cloudSessionToken) {
          return false;
        }
        if (document.visibilityState === "hidden") {
          return false;
        }
        if (now - lastUserInteractionAt < LIVE_SYNC_INTERACTION_COOLDOWN_MS) {
          return false;
        }
        if (dirtyFormDraftKeys.size) {
          return false;
        }
        const token = String(new URL(window.location.href).searchParams.get("token") || "").trim();
        if (token) {
          return false;
        }
        if (hasEditableFocus()) {
          return false;
        }
        return true;
      }

      async function refreshSharedStateIfIdle(options = {}) {
        const force = Boolean(options.force);
        if (!force && !canRunLiveSharedRefresh()) {
          return false;
        }
        const now = Date.now();
        if (!force && now - lastLiveSyncAt < LIVE_SYNC_MIN_GAP_MS) {
          return false;
        }
        lastLiveSyncAt = now;

        if (!force) {
          const latestRevision = await getCloudWorkspaceRevision();
          const currentRevision = normalizeWorkspaceRevision(cloudRuntime.revision);
          if (latestRevision > 0 && latestRevision === currentRevision) {
            return false;
          }
        }

        return refreshSharedStateSafely({
          skipRender: false,
          forceApply: true,
        }).catch(() => false);
      }

      function ensureLiveSyncLoop() {
        if (liveSyncTimer) {
          return;
        }
        liveSyncTimer = window.setInterval(() => {
          void refreshSharedStateIfIdle();
        }, LIVE_SYNC_INTERVAL_MS);
      }

      function escapeHtml(value) {
        return String(value ?? "")
          .replaceAll("&", "&amp;")
          .replaceAll("<", "&lt;")
          .replaceAll(">", "&gt;")
          .replaceAll('"', "&quot;")
          .replaceAll("'", "&#39;");
      }

      function escapeAttributeValue(value) {
        return escapeHtml(value).replaceAll("\n", "&#10;");
      }

      function checked(value) {
        return value ? "checked" : "";
      }

      function selected(value, current) {
        return String(value) === String(current) ? "selected" : "";
      }

      function normalizeGlobalRole(value = "member") {
        const normalized = String(value || "")
          .trim()
          .toLowerCase()
          .replaceAll(" ", "_")
          .replaceAll("-", "_");

        if (
          ["system_admin", "system_manager", "admin", "administrator"].includes(normalized)
        ) {
          return "system_admin";
        }

        if (normalized === "manager") {
          return "manager";
        }

        return "member";
      }

      function normalizeRegionalOperationsRole(value = "") {
        const normalized = String(value || "")
          .trim()
          .toLowerCase()
          .replaceAll(" ", "_")
          .replaceAll("-", "_");

        if (normalized === "regional_coordinator") {
          return "regional_coordinator";
        }

        if (normalized === "deputy_regional_coordinator") {
          return "deputy_regional_coordinator";
        }

        return "";
      }

      function normalizeRegionalRegion(value = "") {
        const raw = String(value || "").trim();
        if (!raw) {
          return "";
        }

        const normalized = normalizeTextKey(raw);
        const matchedRegion = REGIONAL_OPERATION_REGIONS.find(
          (region, index) =>
            normalizeTextKey(region) === normalized ||
            String(index + 1) === normalized ||
            normalizeTextKey("Region " + (index + 1)) === normalized,
        );

        return matchedRegion || raw;
      }

      const TOURNAMENT_PERMISSION_ROLE_CONFIGS = [
        {
          key: "tabDirectorEmails",
          access: "tab_director",
          label: "Tab Directors",
          assignmentLabel: "Tab Director",
        },
        {
          key: "caTeamEmails",
          access: "ca_team",
          label: "CA Team",
          assignmentLabel: "CA Team",
        },
        {
          key: "tournamentDirectorEmails",
          access: "tournament_director",
          label: "Tournament Directors",
          assignmentLabel: "Tournament Director",
        },
        {
          key: "convenorEmails",
          access: "convenor",
          label: "Convenors",
          assignmentLabel: "Convenor",
        },
        {
          key: "registrationOfficerEmails",
          access: "registration_officer",
          label: "Registration Officers",
          assignmentLabel: "Registration Officer",
        },
        {
          key: "financeOfficerEmails",
          access: "finance_officer",
          label: "Finance Officers",
          assignmentLabel: "Finance Officer",
        },
        {
          key: "equityOfficerEmails",
          access: "equity_officer",
          label: "Equity Officers",
          assignmentLabel: "Equity Officer",
        },
        {
          key: "judgeEmails",
          access: "judge",
          label: "Judges",
          assignmentLabel: "Judge",
        },
        {
          key: "debaterEmails",
          access: "debater",
          label: "Debaters",
          assignmentLabel: "Debater",
        },
      ];

      const LEGACY_TOURNAMENT_PERMISSION_ROLE_CONFIGS = [
        {
          key: "managerEmails",
          access: "tab_director",
          label: "Legacy Managers",
          assignmentLabel: "Legacy Manager",
        },
        {
          key: "tabManagerEmails",
          access: "tab_director",
          label: "Legacy Tab Managers",
          assignmentLabel: "Legacy Tab Manager",
        },
      ];

      function getTournamentPermissionRoleConfigs(options = {}) {
        return Boolean(options.includeLegacy)
          ? [...LEGACY_TOURNAMENT_PERMISSION_ROLE_CONFIGS, ...TOURNAMENT_PERMISSION_ROLE_CONFIGS]
          : [...TOURNAMENT_PERMISSION_ROLE_CONFIGS];
      }

      function getTournamentPermissionConfigByKey(key = "") {
        return (
          getTournamentPermissionRoleConfigs({ includeLegacy: true }).find(
            (config) => config.key === String(key || "").trim(),
          ) || null
        );
      }

      function getTournamentPermissionKeys(options = {}) {
        return getTournamentPermissionRoleConfigs(options).map((config) => config.key);
      }

      function normalizePermissionEmailList(value = []) {
        return Array.from(
          new Set(
            (Array.isArray(value) ? value : [])
              .map((entry) => normalizeEmail(entry))
              .filter(Boolean),
          ),
        );
      }

      function normalizeTournamentPermissions(record = {}) {
        const normalized = {};
        getTournamentPermissionKeys({ includeLegacy: true }).forEach((key) => {
          normalized[key] = normalizePermissionEmailList(record?.[key] || []);
        });
        return normalized;
      }

      function hasFullTournamentAdminAccess(access = "") {
        return ["manager", "system_admin", "tab_director", "ca_team"].includes(
          String(access || "").trim(),
        );
      }

      function hasTournamentOperationsAccess(access = "") {
        return (
          hasFullTournamentAdminAccess(access) ||
          [
            "tournament_director",
            "convenor",
            "registration_officer",
            "finance_officer",
          ].includes(String(access || "").trim())
        );
      }

      function hasTournamentBackstageAccess(access = "") {
        return (
          hasTournamentOperationsAccess(access) ||
          String(access || "").trim() === "equity_officer"
        );
      }

      function hasTournamentPeopleAccess(access = "") {
        return hasTournamentOperationsAccess(access) || hasFullTournamentAdminAccess(access);
      }

      function hasTournamentSanctionAccess(access = "") {
        return (
          hasFullTournamentAdminAccess(access) ||
          String(access || "").trim() === "equity_officer"
        );
      }

      function allowsWingBallotsForFormat(format = "") {
        return ["World Schools"].includes(String(format || "").trim());
      }

      function toTitleLabel(value) {
        return String(value || "")
          .trim()
          .replaceAll("_", " ")
          .replaceAll("-", " ")
          .replace(/\b[a-z]/g, (match) => match.toUpperCase());
      }

      function parseCsv(value) {
        return String(value || "")
          .split(",")
          .map((item) => item.trim())
          .filter(Boolean);
      }

      function boolFromForm(formData, key) {
        return formData.get(key) === "on";
      }

      function numberFromForm(formData, key, fallback) {
        const value = Number(formData.get(key));
        return Number.isFinite(value) ? value : fallback;
      }

      function optionalNumberFromForm(formData, key, fallback = null) {
        const rawValue = String(formData.get(key) ?? "").trim();
        if (!rawValue) {
          return fallback;
        }
        const value = Number(rawValue);
        return Number.isFinite(value) ? value : fallback;
      }

      function normalizeOptionalCount(value, fallback = null, max = 8) {
        const number = Number(value);
        if (!Number.isFinite(number)) {
          return fallback;
        }
        return Math.min(max, Math.max(1, Math.round(number)));
      }

      function normalizeOptionalBreakSize(value, fallback = null) {
        const number = Number(value);
        if (!Number.isFinite(number)) {
          return fallback;
        }
        return Math.min(64, Math.max(0, Math.round(number)));
      }

      function hasConfiguredValue(value) {
        return !(
          value === null ||
          value === undefined ||
          (typeof value === "string" && !value.trim())
        );
      }

      function getConfiguredStructureValue(value, fallbackLabel) {
        return hasConfiguredValue(value) ? String(value) : fallbackLabel;
      }

      async function hashPassword(password) {
        const bytes = new TextEncoder().encode(String(password || ""));
        const digest = await crypto.subtle.digest("SHA-256", bytes);
        return Array.from(new Uint8Array(digest))
          .map((item) => item.toString(16).padStart(2, "0"))
          .join("");
      }

      function bytesToHex(bytes) {
        return Array.from(bytes || [])
          .map((item) => Number(item || 0).toString(16).padStart(2, "0"))
          .join("");
      }

      function hexToBytes(hex) {
        const normalized = String(hex || "").trim().toLowerCase();
        if (!normalized || normalized.length % 2 !== 0) {
          return new Uint8Array();
        }

        const bytes = new Uint8Array(normalized.length / 2);
        for (let index = 0; index < normalized.length; index += 2) {
          bytes[index / 2] = Number.parseInt(normalized.slice(index, index + 2), 16);
        }
        return bytes;
      }

      function createPasswordSalt() {
        return bytesToHex(crypto.getRandomValues(new Uint8Array(PASSWORD_SALT_BYTES)));
      }

      function normalizeDevicePasswordVault(record = {}) {
        return Object.fromEntries(
          Object.entries(record || {})
            .map(([email, value]) => [
              normalizeEmail(email),
              {
                iv: String(value?.iv || "").trim(),
                cipher: String(value?.cipher || "").trim(),
                updatedAt: String(value?.updatedAt || "").trim(),
              },
            ])
            .filter(
              ([email, value]) =>
                email &&
                /^[a-f0-9]+$/i.test(value.iv) &&
                /^[a-f0-9]+$/i.test(value.cipher),
            ),
        );
      }

      function loadDevicePasswordVault() {
        const saved = localStorage.getItem(DEVICE_PASSWORD_VAULT_STORAGE_KEY);
        if (!saved) {
          return {};
        }

        try {
          return normalizeDevicePasswordVault(JSON.parse(saved));
        } catch (error) {
          localStorage.removeItem(DEVICE_PASSWORD_VAULT_STORAGE_KEY);
          return {};
        }
      }

      function saveDevicePasswordVault(vault) {
        localStorage.setItem(
          DEVICE_PASSWORD_VAULT_STORAGE_KEY,
          JSON.stringify(normalizeDevicePasswordVault(vault)),
        );
      }

      async function getDevicePasswordCryptoKey() {
        const savedKey = localStorage.getItem(DEVICE_PASSWORD_KEY_STORAGE_KEY);
        if (savedKey) {
          try {
            return await crypto.subtle.importKey(
              "jwk",
              JSON.parse(savedKey),
              { name: "AES-GCM" },
              false,
              ["encrypt", "decrypt"],
            );
          } catch (error) {
            localStorage.removeItem(DEVICE_PASSWORD_KEY_STORAGE_KEY);
          }
        }

        const generatedKey = await crypto.subtle.generateKey(
          {
            name: "AES-GCM",
            length: 256,
          },
          true,
          ["encrypt", "decrypt"],
        );
        const exportedKey = await crypto.subtle.exportKey("jwk", generatedKey);
        localStorage.setItem(
          DEVICE_PASSWORD_KEY_STORAGE_KEY,
          JSON.stringify(exportedKey),
        );
        return generatedKey;
      }

      async function savePasswordToDeviceVault(email, password) {
        const normalizedEmail = normalizeEmail(email);
        if (!normalizedEmail) {
          return;
        }

        const key = await getDevicePasswordCryptoKey();
        const iv = crypto.getRandomValues(new Uint8Array(12));
        const cipherBuffer = await crypto.subtle.encrypt(
          { name: "AES-GCM", iv },
          key,
          new TextEncoder().encode(String(password || "")),
        );
        const vault = loadDevicePasswordVault();
        vault[normalizedEmail] = {
          iv: bytesToHex(iv),
          cipher: bytesToHex(new Uint8Array(cipherBuffer)),
          updatedAt: timestamp(),
        };
        saveDevicePasswordVault(vault);
        authAutofill = {
          email: normalizedEmail,
          password: String(password || ""),
        };
      }

      async function getPasswordFromDeviceVault(email) {
        const normalizedEmail = normalizeEmail(email);
        if (!normalizedEmail) {
          return "";
        }

        const vault = loadDevicePasswordVault();
        const entry = vault[normalizedEmail];
        if (!entry) {
          return "";
        }

        try {
          const key = await getDevicePasswordCryptoKey();
          const plainBuffer = await crypto.subtle.decrypt(
            {
              name: "AES-GCM",
              iv: hexToBytes(entry.iv),
            },
            key,
            hexToBytes(entry.cipher),
          );
          return new TextDecoder().decode(plainBuffer);
        } catch (error) {
          delete vault[normalizedEmail];
          saveDevicePasswordVault(vault);
          return "";
        }
      }

      function removePasswordFromDeviceVault(email) {
        const normalizedEmail = normalizeEmail(email);
        if (!normalizedEmail) {
          return;
        }

        const vault = loadDevicePasswordVault();
        delete vault[normalizedEmail];
        saveDevicePasswordVault(vault);
        if (normalizeEmail(authAutofill.email) === normalizedEmail) {
          authAutofill = {
            email: "",
            password: "",
          };
        }
      }

      async function hydrateAuthAutofill(email = authPrefs?.rememberedEmail) {
        const normalizedEmail = normalizeEmail(email);
        if (!normalizedEmail) {
          authAutofill = {
            email: "",
            password: "",
          };
          return;
        }

        const password = await getPasswordFromDeviceVault(normalizedEmail);
        authAutofill = {
          email: normalizedEmail,
          password,
        };
      }

      async function deriveSecurePasswordHash(
        password,
        salt,
        iterations = PASSWORD_HASH_ITERATIONS,
      ) {
        const keyMaterial = await crypto.subtle.importKey(
          "raw",
          new TextEncoder().encode(String(password || "")),
          "PBKDF2",
          false,
          ["deriveBits"],
        );
        const derivedBits = await crypto.subtle.deriveBits(
          {
            name: "PBKDF2",
            salt: hexToBytes(salt),
            iterations: Number(iterations) || PASSWORD_HASH_ITERATIONS,
            hash: "SHA-256",
          },
          keyMaterial,
          256,
        );

        return bytesToHex(new Uint8Array(derivedBits));
      }

      async function buildSecurePasswordRecord(password) {
        const passwordSalt = createPasswordSalt();
        return {
          passwordHash: await deriveSecurePasswordHash(password, passwordSalt),
          passwordSalt,
          passwordIterations: PASSWORD_HASH_ITERATIONS,
          passwordVersion: PASSWORD_HASH_VERSION,
        };
      }

      function hasSecurePasswordRecord(user = {}) {
        return (
          String(user.passwordVersion || "").trim() === PASSWORD_HASH_VERSION &&
          /^[a-f0-9]{16,}$/i.test(String(user.passwordSalt || "").trim())
        );
      }

      async function verifyUserPassword(user, password) {
        if (hasSecurePasswordRecord(user)) {
          const computedHash = await deriveSecurePasswordHash(
            password,
            user.passwordSalt,
            user.passwordIterations,
          );
          return {
            ok: computedHash === user.passwordHash,
            needsUpgrade: false,
          };
        }

        const legacyHash = await hashPassword(password);
        const matches = legacyHash === user.passwordHash;
        return {
          ok: matches,
          needsUpgrade: matches,
        };
      }

      function normalizeRegionalReportEntry(entry = {}) {
        const createdAt = String(entry.createdAt || timestamp()).trim();
        return {
          id: String(entry.id || createId("regional-report")).trim(),
          region: normalizeRegionalRegion(entry.region),
          school: String(entry.school || entry.schoolName || "").trim(),
          reportingWindowStart: String(entry.reportingWindowStart || "").trim(),
          reportingWindowEnd: String(entry.reportingWindowEnd || "").trim(),
          summary: String(entry.summary || "").trim(),
          highlights: String(entry.highlights || "").trim(),
          challenges: String(entry.challenges || "").trim(),
          supportNeeded: String(entry.supportNeeded || "").trim(),
          submittedByEmail: normalizeEmail(entry.submittedByEmail || entry.authorEmail),
          submittedByName: String(entry.submittedByName || entry.authorName || "").trim(),
          submittedByRole: normalizeRegionalOperationsRole(
            entry.submittedByRole || entry.authorRole,
          ),
          createdAt,
          createdAtKey: normalizeTimestampKey(entry.createdAtKey, createdAt),
        };
      }

      function normalizeRegionalFundingStatus(value = "pending") {
        const normalized = String(value || "")
          .trim()
          .toLowerCase()
          .replaceAll(" ", "_")
          .replaceAll("-", "_");

        if (["approved", "rejected", "paid"].includes(normalized)) {
          return normalized;
        }

        return "pending";
      }

      function normalizeRegionalBankingInfo(record = {}) {
        const next = record && typeof record === "object" ? record : {};
        const normalizedBank = String(next.bankName || next.bank || "").trim();
        const knownBank =
          JAMAICA_MAJOR_BANKS.find(
            (bank) => normalizeTextKey(bank) === normalizeTextKey(normalizedBank),
          ) || normalizedBank;

        return {
          bankName: knownBank,
          accountName: String(
            next.accountName || next.accountHolderName || next.accountHolder || "",
          ).trim(),
          accountNumber: String(next.accountNumber || next.accountNo || "").trim(),
          branchName: String(next.branchName || next.branch || "").trim(),
        };
      }

      function hasRegionalBankingInfo(record = {}) {
        const banking = normalizeRegionalBankingInfo(record);
        return Boolean(
          banking.bankName || banking.accountName || banking.accountNumber || banking.branchName,
        );
      }

      function maskRegionalAccountNumber(value = "") {
        const raw = String(value || "").trim();
        if (!raw) {
          return "Not added";
        }
        const visible = raw.slice(-4);
        return "•••• " + visible;
      }

      function getRegionalBankingSummary(record = {}, options = {}) {
        const banking = normalizeRegionalBankingInfo(record);
        const maskAccount = options.maskAccount !== false;
        const parts = [];

        if (banking.bankName) {
          parts.push(banking.bankName);
        }
        if (banking.accountName) {
          parts.push(banking.accountName);
        }
        if (banking.accountNumber) {
          parts.push(maskAccount ? maskRegionalAccountNumber(banking.accountNumber) : banking.accountNumber);
        }
        if (banking.branchName) {
          parts.push(banking.branchName);
        }

        return parts.join(" • ");
      }

      function normalizeRegionalFundingRequestEntry(entry = {}) {
        const createdAt = String(entry.createdAt || timestamp()).trim();
        const normalizedBank = String(entry.bankName || entry.bank || "").trim();
        const knownBank =
          JAMAICA_MAJOR_BANKS.find(
            (bank) => normalizeTextKey(bank) === normalizeTextKey(normalizedBank),
          ) || normalizedBank;

        return {
          id: String(entry.id || createId("regional-funding")).trim(),
          region: normalizeRegionalRegion(entry.region),
          school: String(entry.school || entry.schoolName || "").trim(),
          tripDate: String(entry.tripDate || "").trim(),
          amountJmd: Math.max(0, Number(entry.amountJmd || entry.amount || 0) || 0),
          bankName: knownBank,
          accountName: String(
            entry.accountName || entry.accountHolderName || entry.accountHolder || "",
          ).trim(),
          accountNumber: String(entry.accountNumber || entry.accountNo || "").trim(),
          branchName: String(entry.branchName || entry.branch || "").trim(),
          justification: String(entry.justification || "").trim(),
          status: normalizeRegionalFundingStatus(entry.status),
          managerNote: String(entry.managerNote || "").trim(),
          submittedByEmail: normalizeEmail(entry.submittedByEmail || entry.authorEmail),
          submittedByName: String(entry.submittedByName || entry.authorName || "").trim(),
          submittedByRole: normalizeRegionalOperationsRole(
            entry.submittedByRole || entry.authorRole,
          ),
          reviewedByEmail: normalizeEmail(entry.reviewedByEmail || ""),
          reviewedAt: String(entry.reviewedAt || "").trim(),
          createdAt,
          createdAtKey: normalizeTimestampKey(entry.createdAtKey, createdAt),
        };
      }

      function normalizeRegionalOperationsState(record = {}) {
        const next = record && typeof record === "object" ? clone(record) : {};
        next.reports = Array.isArray(next.reports)
          ? next.reports
              .map((entry) => normalizeRegionalReportEntry(entry))
              .sort((left, right) => Number(right.createdAtKey) - Number(left.createdAtKey))
          : [];
        next.transportRequests = Array.isArray(next.transportRequests)
          ? next.transportRequests
              .map((entry) => normalizeRegionalFundingRequestEntry(entry))
              .sort((left, right) => Number(right.createdAtKey) - Number(left.createdAtKey))
          : [];
        return next;
      }

      function normalizeUserRecord(user = {}) {
        const createdAt = String(user.createdAt || timestamp()).trim();
        return {
          id: String(user.id || createId("user")).trim(),
          name: String(user.name || "").trim(),
          email: normalizeEmail(user.email),
          passwordHash: String(user.passwordHash || "").trim(),
          passwordSalt: String(user.passwordSalt || "").trim(),
          passwordVersion: String(user.passwordVersion || "").trim(),
          passwordIterations: Number(user.passwordIterations || 0) || PASSWORD_HASH_ITERATIONS,
          globalRole: normalizeGlobalRole(user.globalRole || "member"),
          createdAt,
          createdAtKey: normalizeTimestampKey(user.createdAtKey, createdAt),
          createdSource: String(user.createdSource || user.source || "registered").trim() || "registered",
          createdBy: normalizeEmail(user.createdBy),
          lastLoginAt: String(user.lastLoginAt || "").trim(),
          active: user.active !== false,
          privateAccessToken: String(
            user.privateAccessToken || user.accessToken || createId("access"),
          ).trim(),
          privateAccessIssuedAt: String(user.privateAccessIssuedAt || createdAt).trim(),
          lastPrivateAccessAt: String(user.lastPrivateAccessAt || "").trim(),
          pinnedTournamentIds: normalizeStringList(user.pinnedTournamentIds, 12),
          registeredTournamentIds: normalizeStringList(user.registeredTournamentIds, 200),
          regionalRole: normalizeRegionalOperationsRole(user.regionalRole),
          regionalRegion: normalizeRegionalRegion(user.regionalRegion),
          regionalBanking: normalizeRegionalBankingInfo(user.regionalBanking || user.regionalBank || {}),
          themePreset: String(user.themePreset || "jade_classic").trim() || "jade_classic",
          preferredLandingView:
            String(user.preferredLandingView || "overview").trim() || "overview",
        };
      }

      async function buildUser(name, email, globalRole, password, metadata = {}) {
        return normalizeUserRecord({
          id: createId("user"),
          name,
          email: normalizeEmail(email),
          ...(await buildSecurePasswordRecord(password)),
          globalRole: normalizeGlobalRole(globalRole),
          createdAt: timestamp(),
          createdAtKey: Date.now(),
          createdSource: metadata.createdSource || "registered",
          createdBy: metadata.createdBy || "",
          lastLoginAt: "",
          active: true,
          regionalRole: metadata.regionalRole || "",
          regionalRegion: metadata.regionalRegion || "",
          regionalBanking: normalizeRegionalBankingInfo(metadata.regionalBanking || {}),
        });
      }

      function getCurrentUser() {
        return getUserByEmail(session.userEmail);
      }

      function getUserByEmail(email) {
        const target = normalizeEmail(email);
        if (!target) {
          return null;
        }
        return state?.users.find((user) => user.email === target) || null;
      }

      function synchronizeUserTournamentHistory(users = state?.users || [], tournaments = state?.tournaments || []) {
        const historyByEmail = new Map();

        tournaments.forEach((tournament) => {
          const tournamentId = String(tournament?.id || "").trim();
          if (!tournamentId) {
            return;
          }

          const remember = (email) => {
            const normalizedEmail = normalizeEmail(email);
            if (!normalizedEmail) {
              return;
            }
            if (!historyByEmail.has(normalizedEmail)) {
              historyByEmail.set(normalizedEmail, new Set());
            }
            historyByEmail.get(normalizedEmail).add(tournamentId);
          };

          (tournament?.participants || []).forEach((participant) => remember(participant?.email));
          (tournament?.judges || []).forEach((judge) => remember(judge?.email));
          getTournamentPermissionKeys({ includeLegacy: true }).forEach((key) => {
            (tournament?.permissions?.[key] || []).forEach(remember);
          });
        });

        return (users || []).map((user) =>
          normalizeUserRecord({
            ...user,
            registeredTournamentIds: normalizeStringList(
              [
                ...(user?.registeredTournamentIds || []),
                ...Array.from(historyByEmail.get(normalizeEmail(user?.email)) || []),
              ],
              200,
            ),
          }),
        );
      }

      function rememberTournamentHistoryForEmail(email, tournamentId) {
        const target = normalizeEmail(email);
        const normalizedTournamentId = String(tournamentId || "").trim();
        if (!target || !normalizedTournamentId || !Array.isArray(state?.users)) {
          return;
        }

        state.users = state.users.map((user) =>
          normalizeEmail(user.email) === target
            ? normalizeUserRecord({
                ...user,
                registeredTournamentIds: normalizeStringList(
                  [...(user.registeredTournamentIds || []), normalizedTournamentId],
                  200,
                ),
              })
            : normalizeUserRecord(user),
        );
      }

      function rememberTournamentHistoryForEmails(emails = [], tournamentId) {
        normalizeStringList(emails, 200).forEach((email) => {
          rememberTournamentHistoryForEmail(email, tournamentId);
        });
      }

      function hasHistoricalTournamentAccess(tournament, email = session.userEmail) {
        const user = getUserByEmail(email);
        const tournamentId = String(tournament?.id || "").trim();
        if (!user || !tournamentId) {
          return false;
        }
        return normalizeStringList(user.registeredTournamentIds, 200).includes(tournamentId);
      }

      function getCurrentRole() {
        return getCurrentUser()?.globalRole || "guest";
      }

      function isManager(email = session.userEmail) {
        return normalizeEmail(email) === normalizeEmail(MANAGER_EMAIL);
      }

      function hasSystemAdminAccounts(users = state?.users || []) {
        return (users || []).some((entry) => {
          const role = normalizeGlobalRole(entry?.globalRole || "");
          return (
            entry?.active !== false &&
            (normalizeEmail(entry?.email) === normalizeEmail(MANAGER_EMAIL) ||
              role === "system_admin" ||
              role === "manager")
          );
        });
      }

      function isProtectedSystemManagerEmail(email, users = state?.users || []) {
        const target = normalizeEmail(email);
        if (!target) {
          return false;
        }

        const activeSystemManagerEmails = (users || [])
          .filter((entry) => {
            const role = normalizeGlobalRole(entry?.globalRole || "");
            return (
              entry?.active !== false &&
              (normalizeEmail(entry?.email) === normalizeEmail(MANAGER_EMAIL) ||
                role === "system_admin" ||
                role === "manager")
            );
          })
          .map((entry) => normalizeEmail(entry.email));

        return activeSystemManagerEmails.length === 1 && activeSystemManagerEmails[0] === target;
      }

      function needsLocalBootstrapManagerSetup() {
        return !requiresSharedBackend() && !hasSystemAdminAccounts(state?.users || []);
      }

      function isSystemAdmin(email = session.userEmail) {
        const user = state?.users.find((entry) => entry.email === normalizeEmail(email));
        const role = normalizeGlobalRole(user?.globalRole || "");
        return isManager(email) || role === "system_admin" || role === "manager";
      }

      function getRegionalOperationsRoleForEmail(email = session.userEmail) {
        return normalizeRegionalOperationsRole(getUserByEmail(email)?.regionalRole || "");
      }

      function canAccessRegionalOperations(email = session.userEmail) {
        return Boolean(isSystemAdmin(email) || getRegionalOperationsRoleForEmail(email));
      }

      function getRegionalAssignmentForEmail(email = session.userEmail) {
        return normalizeRegionalRegion(getUserByEmail(email)?.regionalRegion || "");
      }

      function canCreateTournaments() {
        return isSystemAdmin();
      }

      function canAccessGlobalSettings() {
        return isSystemAdmin();
      }

      function getTournamentAccess(tournament, email = session.userEmail) {
        const target = normalizeEmail(email);
        if (!target) return "viewer";
        if (isManager(target)) return "manager";
        if (isSystemAdmin(target)) return "system_admin";
        const permissions = normalizeTournamentPermissions(tournament?.permissions || {});
        if (permissions.caTeamEmails.includes(target)) return "ca_team";
        if (
          permissions.tabDirectorEmails.includes(target) ||
          permissions.managerEmails.includes(target) ||
          permissions.tabManagerEmails.includes(target)
        ) {
          return "tab_director";
        }
        if (permissions.tournamentDirectorEmails.includes(target)) return "tournament_director";
        if (permissions.convenorEmails.includes(target)) return "convenor";
        if (permissions.registrationOfficerEmails.includes(target)) return "registration_officer";
        if (permissions.financeOfficerEmails.includes(target)) return "finance_officer";
        if (permissions.equityOfficerEmails.includes(target)) return "equity_officer";
        if (
          permissions.judgeEmails.includes(target) ||
          (tournament.judges || []).some((judge) => normalizeEmail(judge.email) === target)
        ) {
          return "judge";
        }
        if (
          permissions.debaterEmails.includes(target) ||
          tournament.participants.some((participant) => participant.email === target)
        ) {
          return "debater";
        }
        if (hasHistoricalTournamentAccess(tournament, target)) {
          return "registered_member";
        }
        return "viewer";
      }

      function canManageTournament(tournament) {
        return hasFullTournamentAdminAccess(getTournamentAccess(tournament));
      }

      function canSanctionTournamentParticipants(tournament) {
        return hasTournamentSanctionAccess(getTournamentAccess(tournament));
      }

      function canViewManagerOnlyTournamentFeedback(tournament) {
        return hasFullTournamentAdminAccess(getTournamentAccess(tournament));
      }

      function canJudgeTournament(tournament) {
        return getTournamentAccess(tournament) === "judge";
      }

      function canSeeTournament(tournament, email = session.userEmail) {
        const access = getTournamentAccess(tournament, email);
        return (
          hasTournamentBackstageAccess(access) ||
          access === "judge" ||
          access === "debater" ||
          access === "registered_member" ||
          tournament.publication.dashboardListed
        );
      }

      function isTournamentArchived(tournament) {
        return String(tournament?.status || "").trim().toLowerCase() === "archived";
      }

      function getVisibleTournaments(email = session.userEmail) {
        return state.tournaments.filter((tournament) => canSeeTournament(tournament, email));
      }

      function getActiveVisibleTournaments(email = session.userEmail) {
        return getVisibleTournaments(email).filter((tournament) => !isTournamentArchived(tournament));
      }

      function getArchivedVisibleTournaments(email = session.userEmail) {
        return getVisibleTournaments(email).filter((tournament) => isTournamentArchived(tournament));
      }

      function getParticipantForUser(tournament, email = session.userEmail) {
        const target = normalizeEmail(email);
        return (
          (tournament.participants || []).find(
            (participant) => normalizeEmail(participant.email) === target,
          ) || null
        );
      }

      function getDebaterTournaments(email = session.userEmail) {
        const target = normalizeEmail(email);
        return state.tournaments.filter(
          (tournament) => getTournamentAccess(tournament, target) === "debater",
        );
      }

      function getParticipantIdentityKey(participant) {
        const email = normalizeEmail(participant?.email);
        if (email) {
          return "email:" + email;
        }
        return (
          "name:" +
          normalizeTextKey(participant?.name) +
          "::" +
          normalizeTextKey(participant?.institution)
        );
      }

      function getTournamentDisplayTimestamp(tournament) {
        return (
          String(tournament?.createdAt || "").trim() ||
          String(tournament?.auditLog?.[tournament.auditLog.length - 1]?.at || "").trim() ||
          "Recorded"
        );
      }

      function getParticipantHistoryRecords(identityKey, email = session.userEmail) {
        const targetKey = String(identityKey || "").trim();
        if (!targetKey) {
          return [];
        }

        return getVisibleTournaments(email)
          .flatMap((tournament, orderIndex) =>
            (tournament.participants || [])
              .filter((participant) => getParticipantIdentityKey(participant) === targetKey)
              .map((participant) => {
                const standing = findStandingForParticipant(tournament, participant);
                const speakerStanding = getSpeakerStandingForParticipant(tournament, participant);
                const speakerScore = getParticipantComputedSpeakerScore(tournament, participant);
                const feedbackEntries = getOfficialParticipantFeedbackEntries(
                  tournament,
                  participant,
                );
                const drawEntries = getParticipantDrawEntries(tournament, participant);
                const team = participant.teamId
                  ? getTournamentTeams(tournament).find((entry) => entry.id === participant.teamId) ||
                    null
                  : findTournamentTeamByName(tournament, participant.teamName || "");
                const topSpeaker = getSpeakerStandings(tournament)[0] || null;
                const progressShare = topSpeaker?.speakerScore
                  ? Math.max(
                      8,
                      Math.min(
                        100,
                        Math.round((Number(speakerScore || 0) / Number(topSpeaker.speakerScore || 1)) * 100),
                      ),
                    )
                  : 0;

                return {
                  identityKey: targetKey,
                  tournament,
                  tournamentId: tournament.id,
                  tournamentName: tournament.name,
                  tournamentCode: tournament.code,
                  tournamentStatus: tournament.status,
                  tournamentFormat: getFormatLabel(tournament),
                  tournamentStamp: getTournamentDisplayTimestamp(tournament),
                  participant,
                  participantId: participant.id,
                  team,
                  teamName: participant.teamName || team?.name || "Independent",
                  institution: participant.institution || team?.institution || "",
                  standing,
                  speakerStanding,
                  speakerScore,
                  drawEntries,
                  feedbackEntries,
                  orderIndex,
                  progressShare,
                };
              }),
          )
          .sort((left, right) => Number(left.orderIndex) - Number(right.orderIndex));
      }

      function getParticipantDirectoryRecords(email = session.userEmail) {
        const catalog = new Map();

        getVisibleTournaments(email).forEach((tournament) => {
          (tournament.participants || []).forEach((participant) => {
            const identityKey = getParticipantIdentityKey(participant);
            if (!catalog.has(identityKey)) {
              catalog.set(identityKey, {
                identityKey,
                name: participant.name,
                email: normalizeEmail(participant.email),
                institutions: new Set(),
                teams: new Set(),
              });
            }
            const record = catalog.get(identityKey);
            if (participant.institution) {
              record.institutions.add(String(participant.institution || "").trim());
            }
            if (participant.teamName) {
              record.teams.add(String(participant.teamName || "").trim());
            }
          });
        });

        return Array.from(catalog.values())
          .map((record) => {
            const history = getParticipantHistoryRecords(record.identityKey, email);
            const latest = history[0] || null;
            const bestSpeakerRank = history.reduce((best, entry) => {
              if (!entry.speakerStanding?.speakerRank) {
                return best;
              }
              return best === null || entry.speakerStanding.speakerRank < best
                ? entry.speakerStanding.speakerRank
                : best;
            }, null);
            const averageSpeakerScore = history.length
              ? roundScoreValue(
                  history.reduce((sum, entry) => sum + Number(entry.speakerScore || 0), 0) /
                    history.length,
                )
              : 0;

            return {
              identityKey: record.identityKey,
              name: latest?.participant?.name || record.name,
              email: latest?.participant?.email || record.email,
              institutions: Array.from(record.institutions).filter(Boolean),
              teams: Array.from(record.teams).filter(Boolean),
              history,
              latest,
              tournamentsCount: history.length,
              bestSpeakerRank,
              averageSpeakerScore,
            };
          })
          .sort(
            (left, right) =>
              String(left.name || left.email).localeCompare(String(right.name || right.email)) ||
              String(left.email).localeCompare(String(right.email)),
          );
      }

      function getParticipantProfileByKey(identityKey, email = session.userEmail) {
        return (
          getParticipantDirectoryRecords(email).find(
            (record) => record.identityKey === String(identityKey || "").trim(),
          ) || null
        );
      }

      function getParticipantTeamJourney(profile) {
        const journey = new Map();
        (profile?.history || []).forEach((entry, index) => {
          const teamLabel = String(entry.teamName || "Independent").trim() || "Independent";
          if (!journey.has(teamLabel)) {
            journey.set(teamLabel, {
              teamName: teamLabel,
              tournaments: [],
              bestRank: null,
              latestIndex: index,
            });
          }
          const record = journey.get(teamLabel);
          record.tournaments.push(entry);
          if (entry.standing?.rank) {
            record.bestRank =
              record.bestRank === null || Number(entry.standing.rank) < Number(record.bestRank)
                ? entry.standing.rank
                : record.bestRank;
          }
          record.latestIndex = Math.min(record.latestIndex, index);
        });

        return Array.from(journey.values()).sort(
          (left, right) =>
            Number(left.latestIndex) - Number(right.latestIndex) ||
            String(left.teamName).localeCompare(String(right.teamName)),
        );
      }

      function getWorkspaceSearchResults(query, email = session.userEmail) {
        const normalizedQuery = normalizeTextKey(query);
        const visibleTournaments = getVisibleTournaments(email);
        const participantDirectory = getParticipantDirectoryRecords(email);

        const tournaments = visibleTournaments.filter((tournament) =>
          tournamentMatchesQuery(tournament, normalizedQuery),
        );

        const participants = participantDirectory.filter((profile) => {
          const values = [
            profile.name,
            profile.email,
            ...(profile.institutions || []),
            ...(profile.teams || []),
          ]
            .map((value) => String(value || "").trim().toLowerCase())
            .filter(Boolean);
          return values.some((value) => value.includes(normalizedQuery));
        });

        const teams = visibleTournaments
          .flatMap((tournament) =>
            getTournamentTeams(tournament).map((team) => ({
              tournament,
              team,
              label: getTeamDisplayLabel(team),
            })),
          )
          .filter(({ team, label }) =>
            [label, team.publicAlias, team.notes, team.institution]
              .map((value) => String(value || "").trim().toLowerCase())
              .filter(Boolean)
              .some((value) => value.includes(normalizedQuery)),
          );

        const accounts = canAccessGlobalSettings()
          ? state.users.filter((user) =>
              [user.name, user.email, toTitleLabel(user.globalRole)]
                .map((value) => String(value || "").trim().toLowerCase())
                .filter(Boolean)
                .some((value) => value.includes(normalizedQuery)),
            )
          : [];

        return {
          tournaments,
          participants,
          teams,
          accounts,
        };
      }

      function getWorkspaceSearchRecommendations(query = session.searchQuery, email = session.userEmail) {
        const normalizedQuery = normalizeTextKey(query);
        const visibleTournaments = getVisibleTournaments(email);
        const participantDirectory = getParticipantDirectoryRecords(email);
        const recommendations = [];
        const seen = new Set();

        function pushRecommendation(value, label, priority = 0, searchFields = []) {
          const cleanValue = String(value || "").trim();
          const cleanLabel = String(label || "").trim();
          if (!cleanValue) {
            return;
          }

          const key = normalizeTextKey(cleanValue);
          if (!key || seen.has(key)) {
            return;
          }

          const haystack = [cleanValue, cleanLabel, ...searchFields]
            .map((entry) => normalizeTextKey(entry))
            .filter(Boolean)
            .join(" ");

          if (normalizedQuery && !haystack.includes(normalizedQuery)) {
            return;
          }

          let score = priority;
          if (normalizedQuery) {
            if (key.startsWith(normalizedQuery)) {
              score += 8;
            } else if (key.split(/\s+/).some((part) => part.startsWith(normalizedQuery))) {
              score += 6;
            } else {
              score += 3;
            }
          }

          seen.add(key);
          recommendations.push({
            value: cleanValue,
            label: cleanLabel || cleanValue,
            score,
          });
        }

        visibleTournaments.forEach((tournament, index) => {
          const base = Math.max(12, 34 - index);
          pushRecommendation(
            tournament.name,
            "Tournament • " + tournament.code,
            base,
            [tournament.code, getFormatLabel(tournament), tournament.notes],
          );
          pushRecommendation(
            tournament.code,
            "Code • " + tournament.name,
            base - 1,
            [tournament.name, getFormatLabel(tournament)],
          );
        });

        participantDirectory.forEach((profile, index) => {
          const base = Math.max(10, 28 - index);
          pushRecommendation(
            profile.name,
            "Profile • " +
              profile.tournamentsCount +
              " tournament" +
              (profile.tournamentsCount === 1 ? "" : "s") +
              " tracked",
            base,
            [profile.email, ...(profile.institutions || []), ...(profile.teams || [])],
          );
        });

        return recommendations
          .sort(
            (left, right) =>
              Number(right.score || 0) - Number(left.score || 0) ||
              String(left.label).localeCompare(String(right.label)),
          )
          .slice(0, normalizedQuery ? 8 : 6);
      }

      function renderSearchAssist(query = session.searchQuery, datalistId = "workspace-search-suggestions", email = session.userEmail) {
        const suggestions = getWorkspaceSearchRecommendations(query, email);
        if (!suggestions.length) {
          return "";
        }

        return `
          <div class="search-assist">
            <datalist id="${escapeHtml(datalistId)}">
              ${suggestions
                .map(
                  (suggestion) =>
                    `<option value="${escapeHtml(suggestion.value)}">${escapeHtml(
                      suggestion.label,
                    )}</option>`,
                )
                .join("")}
            </datalist>
            <div class="search-suggestion-row">
              <span class="theme-section-label">${escapeHtml(
                String(query || "").trim() ? "Recommended Matches" : "Try Searching For",
              )}</span>
              ${suggestions
                .slice(0, String(query || "").trim() ? 5 : 4)
                .map(
                  (suggestion) => `
                    <button class="secondary-button search-suggestion-chip" type="button" data-action="apply-search-recommendation" data-query="${escapeHtml(
                      suggestion.value,
                    )}">${escapeHtml(suggestion.value)}</button>
                  `,
                )
                .join("")}
            </div>
          </div>
        `;
      }
      function getWorkspaceCapabilities(email = session.userEmail) {
        const target = normalizeEmail(email);
        const accessRecords = state.tournaments.map((tournament) => ({
          tournament,
          access: getTournamentAccess(tournament, target),
        }));
        const managedTournaments = accessRecords
          .filter((record) => hasTournamentBackstageAccess(record.access))
          .map((record) => record.tournament);
        const judgedTournaments = accessRecords
          .filter((record) => record.access === "judge")
          .map((record) => record.tournament);
        const debaterTournaments = accessRecords
          .filter((record) => record.access === "debater")
          .map((record) => record.tournament);
        const globalManager = isManager(target);
        const systemAdmin = isSystemAdmin(target);
        const regionalRole = getRegionalOperationsRoleForEmail(target);
        const regionalAccess = Boolean(globalManager || systemAdmin || regionalRole);
        const regionalPortalMode = Boolean(isRegionalOperationsPortalPage() && regionalAccess);
        const canManageAny = globalManager || systemAdmin || managedTournaments.length > 0;
        const canJudgeAny = judgedTournaments.length > 0;
        const competitorOnly = debaterTournaments.length > 0 && !canManageAny && !canJudgeAny;
        const judgeOnly = canJudgeAny && !canManageAny && debaterTournaments.length === 0;
        const regionalOnly = regionalPortalMode;

        return {
          accessRecords,
          managedTournaments,
          judgedTournaments,
          debaterTournaments,
          globalManager,
          systemAdmin,
          regionalRole,
          regionalAccess,
          canManageAny,
          canJudgeAny,
          competitorOnly,
          judgeOnly,
          regionalPortalMode,
          regionalOnly,
          canViewPeople:
            globalManager ||
            systemAdmin ||
            accessRecords.some((record) => hasTournamentPeopleAccess(record.access)),
          canViewLinks: Boolean(target),
          canViewJudging: canJudgeAny,
          canViewRegionalOperations: regionalPortalMode,
          canViewSearch: Boolean(target),
          canViewSettings: Boolean(target),
          canLaunchTournaments: canCreateTournaments(),
        };
      }

      function getAllowedLandingViews(email = session.userEmail) {
        return Array.from(new Set(getWorkspaceNavItems(email).map((item) => item.key)));
      }

      function getTournamentAppointeeStats() {
        return state.tournaments.reduce(
          (totals, tournament) => {
            const permissions = normalizeTournamentPermissions(tournament.permissions || {});
            totals.tournaments += 1;
            getTournamentPermissionKeys({ includeLegacy: true }).forEach((key) => {
              totals[key] += (permissions[key] || []).length;
            });
            totals.totalAppointments = getTournamentPermissionKeys({ includeLegacy: true }).reduce(
              (sum, key) => sum + Number(totals[key] || 0),
              0,
            );
            return totals;
          },
          {
            tournaments: 0,
            totalAppointments: 0,
            ...getTournamentPermissionKeys({ includeLegacy: true }).reduce((result, key) => {
              result[key] = 0;
              return result;
            }, {}),
          },
        );
      }

      function getPreferredLandingView(email = session.userEmail) {
        const preferred = String(getCurrentUser()?.preferredLandingView || "overview").trim();
        const allowed = getAllowedLandingViews(email);
        if (allowed.includes(preferred)) {
          return preferred;
        }
        return "overview";
      }

      function getWorkspaceNavItems(email = session.userEmail) {
        const capabilities = getWorkspaceCapabilities(email);

        if (capabilities.regionalPortalMode) {
          return [
            {
              key: "regional",
              label: "Regional Ops",
              count: getRegionalOperationsRoleForEmail(email)
                ? toTitleLabel(getRegionalOperationsRoleForEmail(email))
                : "Portal",
            },
          ];
        }

        if (capabilities.competitorOnly) {
          return [
            {
              key: "overview",
              label: "My Tab",
              count: capabilities.debaterTournaments.length,
            },
            {
              key: "tournaments",
              label: "My Events",
              count: capabilities.debaterTournaments.length,
            },
            {
              key: "search",
              label: "Search",
              count: "Find",
            },
            {
              key: "links",
              label: "Access Links",
              count: 1,
            },
            {
              key: "about",
              label: "About",
              count: "Info",
            },
            {
              key: "settings",
              label: "Settings",
              count: "You",
            },
          ];
        }

        if (capabilities.judgeOnly) {
          return [
            {
              key: "overview",
              label: "Overview",
              count: getVisibleTournaments(email).length,
            },
            {
              key: "judging",
              label: "Judging",
              count: getJudgeAssignments(email).length,
            },
            {
              key: "search",
              label: "Search",
              count: "Find",
            },
            {
              key: "tournaments",
              label: "Tournaments",
              count: getVisibleTournaments(email).length,
            },
            {
              key: "links",
              label: "Access Links",
              count: 1,
            },
            {
              key: "about",
              label: "About",
              count: "Info",
            },
            {
              key: "settings",
              label: "Settings",
              count: "You",
            },
          ];
        }

        const stats = getOverviewStats();
        const items = [
          { key: "overview", label: "Overview", count: stats.visibleTournaments },
          { key: "tournaments", label: "Tournaments", count: stats.openTournaments },
        ];

        if (capabilities.canLaunchTournaments) {
          items.push({ key: "launch", label: "Launcher", count: "New" });
        }

        if (capabilities.canViewSearch) {
          items.push({ key: "search", label: "Search", count: "Find" });
        }
        if (capabilities.canViewRegionalOperations) {
          items.push({ key: "regional", label: "Regional Ops", count: "Portal" });
        }

        if (capabilities.canViewJudging) {
          items.push({
            key: "judging",
            label: "Judging",
            count: getJudgeAssignments(email).length,
          });
        }

        if (capabilities.canViewPeople) {
          items.push({ key: "people", label: "People", count: state.users.length });
        }

        if (capabilities.canViewLinks) {
          items.push({ key: "links", label: "Private Links", count: stats.privateLinks });
        }

        items.push({ key: "about", label: "About", count: "Info" });

        if (capabilities.canViewSettings) {
          items.push({ key: "settings", label: "Settings", count: "All" });
        }

        return items;
      }

      function normalizeWorkspaceView(view = session.view, email = session.userEmail) {
        const items = getWorkspaceNavItems(email);
        const fallback = items[0]?.key || "overview";
        return items.some((item) => item.key === view) ? view : fallback;
      }

      function getManagedTournamentForSession() {
        const managed = getWorkspaceCapabilities().managedTournaments.filter((tournament) =>
          canManageTournament(tournament),
        );
        if (!managed.length || !session.managedTournamentId) {
          session.managedTournamentId = "";
          return null;
        }
        const preferred =
          managed.find((tournament) => tournament.id === session.managedTournamentId) || null;
        if (!preferred) {
          session.managedTournamentId = "";
        }
        return preferred;
      }

      function getSelectedTournamentForSession(email = session.userEmail) {
        const visible = getVisibleTournaments(email);
        if (!visible.length || !session.selectedTournamentId) {
          session.selectedTournamentId = "";
          return null;
        }

        const selectedTournament =
          visible.find(
            (tournament) =>
              String(tournament.id || "").trim() ===
              String(session.selectedTournamentId || "").trim(),
          ) || null;

        if (!selectedTournament) {
          session.selectedTournamentId = "";
        }

        return selectedTournament;
      }

      function getPinnedTournamentIds(email = session.userEmail) {
        return normalizeStringList(getCurrentUser()?.pinnedTournamentIds || [], 12);
      }

      function isTournamentPinned(tournamentId, email = session.userEmail) {
        return getPinnedTournamentIds(email).includes(String(tournamentId || "").trim());
      }

      function getRecentTournamentIds() {
        return normalizeStringList(session.recentTournamentIds, 8);
      }

      function getTournamentsByStoredOrder(tournaments, orderedIds) {
        const order = new Map(
          normalizeStringList(orderedIds, 20).map((id, index) => [String(id), index]),
        );

        return [...tournaments].sort((left, right) => {
          const leftOrder = order.has(left.id) ? order.get(left.id) : Number.MAX_SAFE_INTEGER;
          const rightOrder = order.has(right.id) ? order.get(right.id) : Number.MAX_SAFE_INTEGER;
          if (leftOrder !== rightOrder) {
            return leftOrder - rightOrder;
          }
          return String(left.name).localeCompare(String(right.name));
        });
      }

      function getPinnedTournaments(tournaments = getVisibleTournaments()) {
        const pinnedIds = getPinnedTournamentIds();
        return getTournamentsByStoredOrder(
          tournaments.filter((tournament) => pinnedIds.includes(tournament.id)),
          pinnedIds,
        );
      }

      function getRecentTournaments(tournaments = getVisibleTournaments()) {
        const recentIds = getRecentTournamentIds();
        return getTournamentsByStoredOrder(
          tournaments.filter((tournament) => recentIds.includes(tournament.id)),
          recentIds,
        );
      }

      function recordRecentTournament(tournamentId) {
        const targetId = String(tournamentId || "").trim();
        if (!targetId) {
          return;
        }
        session.recentTournamentIds = [targetId]
          .concat(getRecentTournamentIds().filter((id) => id !== targetId))
          .slice(0, 8);
      }

      function getRecentViewKeys() {
        return normalizeStringList(session.recentViewKeys, 8);
      }

      function recordRecentView(viewKey) {
        const normalizedView = normalizeWorkspaceView(String(viewKey || "").trim(), session.userEmail);
        if (!normalizedView) {
          return;
        }
        session.recentViewKeys = [normalizedView]
          .concat(getRecentViewKeys().filter((entry) => entry !== normalizedView))
          .slice(0, 8);
      }

      function getRecentParticipantKeys() {
        return normalizeStringList(session.recentParticipantKeys, 8);
      }

      function recordRecentParticipant(identityKey) {
        const targetKey = String(identityKey || "").trim();
        if (!targetKey) {
          return;
        }
        session.recentParticipantKeys = [targetKey]
          .concat(getRecentParticipantKeys().filter((entry) => entry !== targetKey))
          .slice(0, 8);
      }

      function getPublishedDrawEntries(tournament) {
        return (tournament.draw || []).filter(
          (entry) => String(entry.status || "").trim().toLowerCase() === "published",
        );
      }

      function getDraftDrawEntries(tournament) {
        return (tournament.draw || []).filter((entry) => {
          const status = String(entry.status || "").trim().toLowerCase();
          return status !== "published" && status !== "archived";
        });
      }

      function getOfficialBallotDrawIdSet(tournament) {
        const drawIds = new Set();
        (tournament.participants || []).forEach((participant) => {
          getOfficialParticipantFeedbackEntries(tournament, participant).forEach((entry) => {
            const drawId = String(entry.drawId || "").trim();
            if (drawId) {
              drawIds.add(drawId);
            }
          });
        });
        return drawIds;
      }

      function getTournamentOpsSnapshot(tournament) {
        const teams = getTournamentTeams(tournament).length;
        const speakers = (tournament.participants || []).length;
        const judges = getTournamentJudges(tournament).length;
        const totalRooms = (tournament.draw || []).length;
        const publishedRooms = getPublishedDrawEntries(tournament);
        const draftRooms = getDraftDrawEntries(tournament);
        const chairlessRooms = (tournament.draw || []).filter(
          (entry) => !getChairAllocationForDrawEntry(tournament, entry.id),
        );
        const returnedBallots = getOfficialBallotDrawIdSet(tournament);
        const pendingBallotRooms = publishedRooms.filter(
          (entry) => !returnedBallots.has(String(entry.id || "").trim()),
        );
        const latestPublishedRound = publishedRooms.length
          ? Math.max(...publishedRooms.map((entry) => Number(entry.round || 0)))
          : null;
        const nextDraftRound = draftRooms.length
          ? Math.min(...draftRooms.map((entry) => Number(entry.round || 0)))
          : null;
        const nextUnbuiltProfile =
          getRoundProfiles(tournament).find(
            (profile) =>
              !(tournament.draw || []).some(
                (entry) => Number(entry.round || 0) === Number(profile.round || 0),
              ),
          ) || null;
        const conflictFlags = getRoundProfiles(tournament).reduce(
          (sum, profile) => sum + getRoundConflictSummary(tournament, profile.round).total,
          0,
        );
        const attention = [];

        if (!teams && !speakers) {
          attention.push("Registration has not started yet.");
        } else if (tournament.participantModel === "teams" && !teams) {
          attention.push("Teams still need to be built from the roster.");
        }

        if (!judges) {
          attention.push("No judges have been added to this tournament.");
        }

        if (!totalRooms) {
          attention.push("No draw rooms have been created yet.");
        } else {
          if (draftRooms.length) {
            attention.push(
              draftRooms.length +
                " draft room" +
                (draftRooms.length === 1 ? " is" : "s are") +
                " waiting to be released.",
            );
          }
          if (chairlessRooms.length) {
            attention.push(
              chairlessRooms.length +
                " room" +
                (chairlessRooms.length === 1 ? " still needs" : "s still need") +
                " a chair allocation.",
            );
          }
          if (pendingBallotRooms.length) {
            attention.push(
              pendingBallotRooms.length +
                " published room" +
                (pendingBallotRooms.length === 1 ? " is" : "s are") +
                " awaiting official ballots.",
            );
          }
          if (conflictFlags) {
            attention.push(
              conflictFlags +
                " draw conflict flag" +
                (conflictFlags === 1 ? "" : "s") +
                " should be reviewed before the next release.",
            );
          }
        }

        return {
          teams,
          speakers,
          judges,
          totalRooms,
          publishedRooms: publishedRooms.length,
          draftRooms: draftRooms.length,
          chairlessRooms: chairlessRooms.length,
          pendingBallotRooms: pendingBallotRooms.length,
          latestPublishedRound,
          nextDraftRound,
          nextUnbuiltRound: nextUnbuiltProfile ? Number(nextUnbuiltProfile.round || 0) : null,
          conflictFlags,
          attention,
          attentionCount: attention.length,
        };
      }

      function normalizeNoticeAudience(value, fallback = "everyone") {
        const normalized = String(value || "")
          .trim()
          .toLowerCase()
          .replace(/[_-]+/g, " ");

        if (["everyone", "public", "all", "members"].includes(normalized)) {
          return "everyone";
        }
        if (["judge", "judges", "adjudicators"].includes(normalized)) {
          return "judges";
        }
        if (["debater", "debaters", "participant", "participants", "competitors"].includes(normalized)) {
          return "debaters";
        }
        if (["staff", "manager", "managers", "tab", "admins"].includes(normalized)) {
          return "staff";
        }
        return fallback;
      }

      function getNoticeAudienceLabel(value) {
        return {
          everyone: "Everyone",
          debaters: "Debaters",
          judges: "Judges",
          staff: "Staff",
        }[normalizeNoticeAudience(value)];
      }

      function createTournamentNoticeRecord(payload = {}) {
        const createdAt = String(payload.createdAt || timestamp()).trim();
        const createdAtKey = normalizeTimestampKey(payload.createdAtKey, createdAt) || Date.now();
        return {
          id: payload.id || createId("notice"),
          title: String(payload.title || "").trim(),
          message: String(payload.message || "").trim(),
          audience: normalizeNoticeAudience(payload.audience, "everyone"),
          round: normalizeOptionalCount(payload.round, null, MAX_TOURNAMENT_ROUNDS),
          pinned: Boolean(payload.pinned),
          active: payload.active !== false,
          createdAt,
          createdAtKey,
          createdBy: normalizeEmail(payload.createdBy) || normalizeEmail(session.userEmail) || "system",
        };
      }

      function normalizeTournamentNoticeRecord(record) {
        return createTournamentNoticeRecord(record);
      }

      function getTournamentNoticeAudienceOptionsMarkup(currentValue = "everyone") {
        const current = normalizeNoticeAudience(currentValue, "everyone");
        return [
          { value: "everyone", label: "Everyone" },
          { value: "debaters", label: "Debaters" },
          { value: "judges", label: "Judges" },
          { value: "staff", label: "Staff" },
        ]
          .map(
            (option) =>
              `<option value="${escapeHtml(option.value)}" ${selected(
                option.value,
                current,
              )}>${escapeHtml(option.label)}</option>`,
          )
          .join("");
      }

      function getVisibleTournamentNotices(tournament, options = {}) {
        const scope = String(options.scope || "public").trim().toLowerCase();
        const includeInactive = Boolean(options.includeInactive);
        const notices = (Array.isArray(tournament?.notices) ? tournament.notices : [])
          .map((notice) => normalizeTournamentNoticeRecord(notice))
          .filter((notice) => (includeInactive ? true : notice.active !== false))
          .filter((notice) => {
            if (scope === "manager") {
              return true;
            }
            if (scope === "participant" || scope === "debater") {
              return notice.audience === "everyone" || notice.audience === "debaters";
            }
            if (scope === "judge") {
              return notice.audience === "everyone" || notice.audience === "judges";
            }
            return notice.audience === "everyone";
          })
          .sort(
            (left, right) =>
              Number(right.pinned) - Number(left.pinned) ||
              Number(right.createdAtKey || 0) - Number(left.createdAtKey || 0),
          );

        return typeof options.limit === "number" ? notices.slice(0, options.limit) : notices;
      }

      function tournamentMatchesQuery(tournament, query) {
        const normalizedQuery = normalizeTextKey(query);
        if (!normalizedQuery) {
          return true;
        }

        const values = [
          tournament.name,
          tournament.code,
          getFormatLabel(tournament),
          tournament.customFormatName,
          tournament.notes,
          tournament.announcement,
        ]
          .map((value) => String(value || "").trim().toLowerCase())
          .filter(Boolean);

        return values.some((value) => value.includes(normalizedQuery));
      }

      function renderBrandLockup({
        kicker = "JADE Hummingbird",
        subtitle = "",
        size = "compact",
        className = "",
        showSubtitle = true,
      } = {}) {
        const appName =
          state?.appSettings?.branding?.appName || DEFAULT_SETTINGS.branding.appName;
        const copy =
          subtitle || state?.appSettings?.branding?.subtitle || DEFAULT_SETTINGS.branding.subtitle;

        return `
          <div class="brand-lockup ${escapeHtml(size)} ${escapeHtml(className)}">
            <div class="jade-logo-wrap">
              <img class="jade-logo" src="${escapeHtml(JADE_LOGO_SRC)}" alt="JADE Hummingbird logo" />
            </div>
            <div class="brand-copy">
              <p class="brand-kicker">${escapeHtml(kicker)}</p>
              <p class="brand-name">${escapeHtml(appName)}</p>
              ${showSubtitle ? `<p class="brand-subtitle">${escapeHtml(copy)}</p>` : ""}
            </div>
          </div>
        `;
      }

      function getFormatOptionMarkup(current) {
        return Object.keys(FORMAT_PRESETS)
          .map(
            (format) =>
              `<option value="${escapeHtml(format)}" ${selected(format, current)}>${escapeHtml(
                format,
              )}</option>`,
          )
          .join("");
      }

      function normalizeFormatName(value, options = {}) {
        const { allowBlank = false } = options;
        const normalized = String(value || "").trim();
        if (!normalized) {
          return allowBlank ? "" : "No Standard Format";
        }

        if (FORMAT_PRESETS[normalized]) {
          return normalized;
        }

        const aliasMap = {
          bp: "British Parliamentary",
          "british parliamentary": "British Parliamentary",
          ap: "American Parliamentary",
          "american parliamentary": "American Parliamentary",
          jade: "JADE Parliamentary",
          "jade parliamentary": "JADE Parliamentary",
          ipbp: "Iron Person British Parliamentary",
          "iron bp": "Iron Person British Parliamentary",
          "iron person bp": "Iron Person British Parliamentary",
          "iron person british parliamentary": "Iron Person British Parliamentary",
          wsdc: "World Schools",
          "world schools": "World Schools",
          "no standard": "No Standard Format",
          custom: "No Standard Format",
          "no standard format": "No Standard Format",
        };

        return aliasMap[normalized.toLowerCase()] || (allowBlank ? "" : "No Standard Format");
      }

      function normalizeRoundFormatOverride(value) {
        const normalized = normalizeFormatName(value, { allowBlank: true });
        return normalized && FORMAT_PRESETS[normalized] ? normalized : "";
      }

      function getRoundFormatOptionMarkup(current = "", tournamentFormat = "") {
        const normalizedCurrent = normalizeRoundFormatOverride(current);
        const inheritedLabel = tournamentFormat
          ? "Use Tournament Format (" + tournamentFormat + ")"
          : "Use Tournament Format";
        return [
          `<option value="" ${selected("", normalizedCurrent)}>${escapeHtml(inheritedLabel)}</option>`,
          ...Object.keys(FORMAT_PRESETS).map(
            (format) =>
              `<option value="${escapeHtml(format)}" ${selected(
                format,
                normalizedCurrent,
              )}>${escapeHtml(format)}</option>`,
          ),
        ].join("");
      }

      function getParticipantModelOptions(current) {
        return ["teams", "individuals", "hybrid"]
          .map(
            (mode) =>
              `<option value="${mode}" ${selected(mode, current)}>${escapeHtml(
                toTitleLabel(mode),
              )}</option>`,
          )
          .join("");
      }

      function getGlobalRoleOptions(current) {
        const normalizedCurrent = normalizeGlobalRole(current);
        return ["member", "manager", "system_admin"]
          .map(
            (role) =>
              `<option value="${role}" ${selected(role, normalizedCurrent)}>${escapeHtml(
                toTitleLabel(role),
              )}</option>`,
          )
          .join("");
      }

      function getRegionalOperationsRoleOptions(current = "", options = {}) {
        const normalizedCurrent = normalizeRegionalOperationsRole(current);
        const roles = [
          ...(options.allowEmpty
            ? [
                {
                  value: "",
                  label: "No Regional Access",
                },
              ]
            : []),
          {
            value: "regional_coordinator",
            label: "Regional Coordinator",
          },
          {
            value: "deputy_regional_coordinator",
            label: "Deputy Regional Coordinator",
          },
        ];
        return roles
          .map(
            (role) =>
              `<option value="${escapeHtml(role.value)}" ${selected(
                role.value,
                normalizedCurrent,
              )}>${escapeHtml(role.label)}</option>`,
          )
          .join("");
      }

      function getRegionalRegionOptions(current = "") {
        const normalizedCurrent = normalizeRegionalRegion(current);
        return REGIONAL_OPERATION_REGIONS.map(
          (region) =>
            `<option value="${escapeHtml(region)}" ${selected(
              region,
              normalizedCurrent,
            )}>${escapeHtml(region)}</option>`,
        ).join("");
      }

      function getAccountStatusOptions(currentActive = true) {
        return [
          {
            value: "active",
            label: "Active",
          },
          {
            value: "disabled",
            label: "Disabled",
          },
        ]
          .map(
            (status) =>
              `<option value="${escapeHtml(status.value)}" ${selected(
                status.value,
                currentActive ? "active" : "disabled",
              )}>${escapeHtml(status.label)}</option>`,
          )
          .join("");
      }

      function getJamaicanBankOptions(current = "") {
        const normalizedCurrent = String(current || "").trim();
        return JAMAICA_MAJOR_BANKS.map(
          (bank) =>
            `<option value="${escapeHtml(bank)}" ${selected(
              bank,
              normalizedCurrent,
            )}>${escapeHtml(bank)}</option>`,
        ).join("");
      }

      function getScoringMethodFieldLabel(participantModel = "", format = "") {
        const normalizedFormat = String(format || "").trim();
        const normalizedParticipantModel = String(participantModel || "").trim().toLowerCase();
        if (
          normalizedFormat === "Iron Person British Parliamentary" ||
          ([
            "British Parliamentary",
            "World Schools",
            "American Parliamentary",
            "JADE Parliamentary",
          ].includes(normalizedFormat) &&
            normalizedParticipantModel === "teams")
        ) {
          return "Team Points";
        }
        if (normalizedParticipantModel === "teams") {
          return "Team Points";
        }
        if (normalizedParticipantModel === "individuals") {
          return "Individual Scoring";
        }
        return "Scoring Method";
      }

      function normalizeScoringMethodChoice(value = "") {
        const normalized = String(value || "").trim();
        const normalizedKey = normalized.toLowerCase();

        if (!normalizedKey) {
          return "";
        }

        const legacyMap = {
          "team bp: 3 for 1st, 2 for 2nd, 1 for 3rd, 0 for 4th": "WUDC Team Points",
          "3 points per win, 1 point per loss": "WSDC Team Points",
          "custom jade parliamentary scoring": "JADE Parliamentary Team Points",
          "speaker points": "Individual Speaker Points",
          "win-loss plus speaks": "WSDC Team Points",
          "ballot wins plus speaker awards": "WSDC Team Points",
        };

        return legacyMap[normalizedKey] || normalized;
      }

      function getScoringMethodOptions(participantModel = "", format = "") {
        const normalized = String(participantModel || "").trim().toLowerCase();
        const normalizedFormat = String(format || "").trim();
        const teamFirst =
          normalized === "teams" || normalizedFormat === "Iron Person British Parliamentary";
        const blankLabel =
          teamFirst
            ? "No Standard Team Points"
            : normalized === "individuals"
              ? "No Standard Individual Scoring"
              : "No Standard Scoring Method";
        const teamOptions = [
          { value: "WUDC Team Points", label: "WUDC Team Points" },
          { value: "WSDC Team Points", label: "WSDC Team Points" },
          { value: "JADE Parliamentary Team Points", label: "JADE Parliamentary Team Points" },
        ];
        const individualOptions = [
          { value: "Individual Speaker Points", label: "Individual Speaker Points" },
        ];

        if (!teamFirst && normalized === "individuals") {
          return [{ value: "", label: blankLabel }, ...individualOptions, ...teamOptions];
        }

        if (teamFirst) {
          return [{ value: "", label: blankLabel }, ...teamOptions, ...individualOptions];
        }

        return [{ value: "", label: blankLabel }, ...teamOptions, ...individualOptions];
      }

      function getScoringMethodOptionsMarkup(currentValue = "", participantModel = "", format = "") {
        const normalizedCurrent = normalizeScoringMethodChoice(currentValue);
        const options = getScoringMethodOptions(participantModel, format);

        if (
          normalizedCurrent &&
          !options.some((option) => String(option.value) === normalizedCurrent)
        ) {
          options.push({ value: normalizedCurrent, label: normalizedCurrent });
        }

        return options
          .map(
            (option) =>
              `<option value="${escapeHtml(option.value)}" ${selected(
                option.value,
                normalizedCurrent,
              )}>${escapeHtml(option.label)}</option>`,
          )
          .join("");
      }

      function normalizeNonNegative(value, fallback = 0) {
        const number = Number(value);
        return Number.isFinite(number) && number >= 0 ? number : fallback;
      }

      function getScoringProfile(target, participantModelOverride = "") {
        const format = normalizeFormatName(
          typeof target === "object" ? target?.format : target,
        );
        const participantModel =
          participantModelOverride ||
          (typeof target === "object" ? target?.participantModel : "");

        if (format === "British Parliamentary" && participantModel === "teams") {
          return {
            mode: "bp_team",
            scoringMethod: "WUDC Team Points",
            note: "Team standings are calculated automatically with WUDC team points: 1st = 3, 2nd = 2, 3rd = 1, 4th = 0.",
          };
        }

        if (format === "Iron Person British Parliamentary") {
          return {
            mode: "bp_team",
            scoringMethod: "WUDC Team Points",
            note: "Iron Person BP uses WUDC team points for placements, while each speaker is still scored individually on the ballot.",
          };
        }

        if (
          (format === "American Parliamentary" || format === "World Schools") &&
          participantModel === "teams"
        ) {
          return {
            mode: "win_loss_team",
            scoringMethod: "WSDC Team Points",
            note: "Team standings are calculated automatically with WSDC-style team points: each win is worth 3 points and each loss is worth 1 point.",
          };
        }

        if (format === "JADE Parliamentary" && participantModel === "teams") {
          return {
            mode: "win_loss_team",
            scoringMethod: "JADE Parliamentary Team Points",
            note: "Team standings are calculated automatically from official ballots, with team points tracked separately from speaker scores.",
          };
        }

        return {
          mode: "generic",
          scoringMethod: normalizeScoringMethodChoice(FORMAT_PRESETS[format]?.scoringMethod || ""),
          note:
            participantModel === "individuals"
              ? "Individual speaker points are tracked automatically from judge ballots."
              : "Speaker rankings stay separate from team points.",
        };
      }

      function getScoringMethodValue(
        format,
        participantModel,
        currentValue = "",
        options = {},
      ) {
        const { preserveBlank = false } = options;
        const profile = getScoringProfile({ format, participantModel });
        const normalized = normalizeScoringMethodChoice(currentValue);
        if (!normalized) {
          return preserveBlank ? "" : profile.scoringMethod;
        }

        return normalized;
      }

      function getScoringProfileHelperText(target) {
        const participantModel =
          typeof target === "object" ? String(target?.participantModel || "").trim() : "";
        const profile = getScoringProfile(target);
        if (!profile.note) {
          return "";
        }
        if (profile.mode === "generic" && participantModel.toLowerCase() === "individuals") {
          return profile.note;
        }
        return profile.note + " Speaker rankings are tracked separately from team standings.";
      }

      function getRoundScoringProfile(tournament, roundOrProfile = null) {
        return getScoringProfile({
          format: getRoundFormat(tournament, roundOrProfile),
          participantModel: tournament?.participantModel || "",
        });
      }

      function getStandingsProfile(tournament) {
        const baseProfile = getScoringProfile(tournament);
        const teamModes = new Set(
          getRoundProfiles(tournament)
            .map((profile) => getRoundScoringProfile(tournament, profile).mode)
            .filter((mode) => mode === "bp_team" || mode === "win_loss_team"),
        );

        if (teamModes.size > 1) {
          return {
            mode: "mixed_team",
            scoringMethod: "Mixed Team Points",
            note:
              "This tournament uses more than one team-point model across its rounds, so standings combine placements and win-loss points into one mixed board.",
          };
        }

        return baseProfile;
      }

      function usesTeamPointStandings(tournament) {
        return ["bp_team", "win_loss_team", "mixed_team"].includes(
          getStandingsProfile(tournament).mode,
        );
      }

      function getFormatSelectionDefaults(format, participantModelOverride = "") {
        const preset = getFormatPreset(format);
        const participantModel = participantModelOverride || preset.participantModel || "teams";
        return {
          participantModel,
          teamsPerRoom: normalizeOptionalCount(preset.teamsPerRoom, null),
          teamSize: normalizeOptionalCount(preset.teamSize, null),
          speakersPerSide: normalizeOptionalCount(preset.speakersPerSide, null),
          crossExaminationEnabled: Boolean(preset.crossExaminationEnabled),
          rebuttalEnabled: Boolean(preset.rebuttalEnabled),
          randomTeamsAllowed: Boolean(preset.randomTeamsAllowed),
          motionStyle: String(preset.motionStyle || "").trim(),
          scoringMethod: getScoringMethodValue(
            format,
            participantModel,
            preset.scoringMethod || "",
            { preserveBlank: true },
          ),
        };
      }

      function normalizeRoundCount(value, fallback = 1) {
        const number = Number(value);
        if (!Number.isFinite(number)) {
          return fallback;
        }
        return Math.min(MAX_TOURNAMENT_ROUNDS, Math.max(1, Math.round(number)));
      }

      function normalizeRoundStage(value = "") {
        const normalized = String(value || "")
          .trim()
          .toLowerCase()
          .replaceAll("-", "_")
          .replaceAll(" ", "_");

        if (
          [
            "outround",
            "out_round",
            "break_round",
            "elimination",
            "elimination_round",
            "break",
          ].includes(normalized)
        ) {
          return "outround";
        }

        return "inround";
      }

      function isOutroundProfile(profile = {}) {
        return normalizeRoundStage(profile?.stage) === "outround";
      }

      function getRoundStageLabel(value = "") {
        return isOutroundProfile({ stage: value }) ? "Outround" : "In-Round";
      }

      function normalizeOutroundPairingMethod(value = "") {
        const normalized = String(value || "")
          .trim()
          .toLowerCase()
          .replaceAll("-", "_")
          .replaceAll(" ", "_");

        if (["fold", "folded", "fold_pair", "fold_pairing"].includes(normalized)) {
          return "fold";
        }

        if (
          ["power", "power_pair", "power_pairing", "paired", "power_paired"].includes(
            normalized,
          )
        ) {
          return "power";
        }

        if (["random", "randomise", "randomize"].includes(normalized)) {
          return "random";
        }

        return "";
      }

      function getStoredRoundPairingMethod(profile = {}) {
        return normalizeOutroundPairingMethod(
          profile?.pairingMethod || profile?.outroundPairingMethod || "",
        );
      }

      function getOutroundPairingMethodLabel(value = "") {
        const normalized = normalizeOutroundPairingMethod(value);
        if (normalized === "fold") {
          return "Folded";
        }
        if (normalized === "random") {
          return "Randomised";
        }
        return "Power Paired";
      }

      function getOutroundProfilesFromList(profiles = []) {
        return (Array.isArray(profiles) ? profiles : [])
          .filter((profile) => isOutroundProfile(profile))
          .sort((left, right) => Number(left.round || 0) - Number(right.round || 0));
      }

      function getAutomaticOutroundPairingMethod(source, roundProfile = null) {
        const profiles = Array.isArray(source) ? source : getRoundProfiles(source);
        const outrounds = getOutroundProfilesFromList(profiles);
        if (!outrounds.length) {
          return "power";
        }

        if (roundProfile) {
          const targetRound = Number(roundProfile.round || 0);
          const target = outrounds.find((profile) => Number(profile.round || 0) === targetRound);
          if (!target) {
            return "power";
          }
        }

        return outrounds.length > 1 ? "fold" : "power";
      }

      function getAutomaticRoundPairingMethod(source, roundProfile = null) {
        const profile =
          roundProfile && typeof roundProfile === "object"
            ? roundProfile
            : Array.isArray(source)
              ? (source.find(
                  (entry) => Number(entry?.round || 0) === Number(roundProfile || 0),
                ) || {})
              : getRoundProfileForRound(source, roundProfile || 1);

        return isOutroundProfile(profile)
          ? getAutomaticOutroundPairingMethod(source, profile)
          : "power";
      }

      function getResolvedOutroundPairingMethod(tournament, roundProfile = null) {
        const profile =
          roundProfile && typeof roundProfile === "object"
            ? roundProfile
            : getRoundProfileForRound(tournament, roundProfile || 1);
        if (!isOutroundProfile(profile)) {
          return "power";
        }
        return (
          getStoredRoundPairingMethod(profile) ||
          getAutomaticOutroundPairingMethod(tournament, profile)
        );
      }

      function normalizeDrawMethodChoice(value = "", fallback = "auto") {
        const normalized = normalizeOutroundPairingMethod(value);
        if (normalized) {
          return normalized;
        }

        const raw = String(value || "")
          .trim()
          .toLowerCase()
          .replaceAll("-", "_")
          .replaceAll(" ", "_");
        if (["auto", "automatic", "recommended", ""].includes(raw)) {
          return "auto";
        }
        return fallback;
      }

      function getResolvedDrawMethod(tournament, roundProfile = null, value = "auto") {
        const normalized = normalizeDrawMethodChoice(value, "auto");
        if (normalized !== "auto") {
          return normalized;
        }

        const profile =
          roundProfile && typeof roundProfile === "object"
            ? roundProfile
            : getRoundProfileForRound(tournament, roundProfile || 1);

        const storedMethod = getStoredRoundPairingMethod(profile);
        if (storedMethod) {
          return storedMethod;
        }

        if (isOutroundProfile(profile)) {
          return getResolvedOutroundPairingMethod(tournament, profile);
        }

        return "power";
      }

      function getDrawMethodDisplayLabel(tournament, roundProfile = null, value = "auto") {
        const normalized = getResolvedDrawMethod(tournament, roundProfile, value);
        if (normalized === "fold") {
          return "Folded";
        }
        if (normalized === "random") {
          return "Randomised";
        }
        return "Power Paired";
      }

      function resolveRoundStructureValue(profileValue, roundDefaultValue, baseValue) {
        const normalizedProfileValue = normalizeOptionalCount(profileValue, null);
        const normalizedRoundDefaultValue = normalizeOptionalCount(roundDefaultValue, null);
        const normalizedBaseValue = normalizeOptionalCount(baseValue, null);

        if (!hasConfiguredValue(normalizedProfileValue)) {
          return normalizeOptionalCount(normalizedRoundDefaultValue, normalizedBaseValue);
        }

        if (
          hasConfiguredValue(normalizedRoundDefaultValue) &&
          hasConfiguredValue(normalizedBaseValue) &&
          Number(normalizedProfileValue) === Number(normalizedBaseValue) &&
          Number(normalizedProfileValue) !== Number(normalizedRoundDefaultValue)
        ) {
          return normalizedRoundDefaultValue;
        }

        return normalizedProfileValue;
      }

      function createRoundProfile(round, baseConfig = {}, profile = {}) {
        const roundFormat = normalizeRoundFormatOverride(profile.format);
        const roundDefaults = roundFormat
          ? getFormatSelectionDefaults(
              roundFormat,
              String(baseConfig.participantModel || profile.participantModel || "").trim(),
            )
          : {};
        const stage = normalizeRoundStage(profile.stage);
        const pairingMethod = getStoredRoundPairingMethod(profile);

        return {
          round,
          label: String(profile.label || "Round " + round).trim(),
          stage,
          format: roundFormat,
          teamsPerRoom: roundFormat
            ? resolveRoundStructureValue(
                profile.teamsPerRoom,
                roundDefaults.teamsPerRoom,
                baseConfig.teamsPerRoom,
              )
            : normalizeOptionalCount(
            profile.teamsPerRoom,
            normalizeOptionalCount(
              roundDefaults.teamsPerRoom,
              normalizeOptionalCount(baseConfig.teamsPerRoom, null),
            ),
          ),
          teamSize: roundFormat
            ? resolveRoundStructureValue(
                profile.teamSize,
                roundDefaults.teamSize,
                baseConfig.teamSize,
              )
            : normalizeOptionalCount(
            profile.teamSize,
            normalizeOptionalCount(
              roundDefaults.teamSize,
              normalizeOptionalCount(baseConfig.teamSize, null),
            ),
          ),
          speakersPerSide: roundFormat
            ? resolveRoundStructureValue(
                profile.speakersPerSide,
                roundDefaults.speakersPerSide,
                baseConfig.speakersPerSide,
              )
            : normalizeOptionalCount(
            profile.speakersPerSide,
            normalizeOptionalCount(
              roundDefaults.speakersPerSide,
              normalizeOptionalCount(baseConfig.speakersPerSide, null),
            ),
          ),
          pairingMethod,
          outroundPairingMethod: isOutroundProfile({ stage }) ? pairingMethod : "",
          notes: String(profile.notes || "").trim(),
        };
      }

      function buildRoundProfiles(rounds, baseConfig = {}, profiles = []) {
        const totalRounds = normalizeRoundCount(rounds, 1);
        const existing = Array.isArray(profiles) ? profiles : [];
        return Array.from({ length: totalRounds }, (_, index) =>
          createRoundProfile(
            index + 1,
            baseConfig,
            existing.find((profile) => Number(profile.round) === index + 1) || {},
          ),
        );
      }

      function parseRoundProfilesFromForm(formData, rounds, baseConfig = {}) {
        return buildRoundProfiles(
          rounds,
          baseConfig,
          Array.from({ length: normalizeRoundCount(rounds, 1) }, (_, index) => {
            const round = index + 1;
            const stage = normalizeRoundStage(formData.get("roundStage-" + round));
            const pairingMethod = normalizeOutroundPairingMethod(
              formData.get("roundPairingMethod-" + round) ||
                formData.get("roundOutroundPairingMethod-" + round),
            );
            return {
              round,
              label: String(formData.get("roundLabel-" + round) || "").trim(),
              stage,
              format: normalizeRoundFormatOverride(formData.get("roundFormat-" + round)),
              teamsPerRoom: optionalNumberFromForm(formData, "roundTeamsPerRoom-" + round, null),
              teamSize: optionalNumberFromForm(formData, "roundTeamSize-" + round, null),
              speakersPerSide: optionalNumberFromForm(
                formData,
                "roundSpeakersPerSide-" + round,
                null,
              ),
              pairingMethod,
              outroundPairingMethod: stage === "outround" ? pairingMethod : "",
              notes: String(formData.get("roundNotes-" + round) || "").trim(),
            };
          }),
        );
      }

      function getRoundProfiles(tournament) {
        return buildRoundProfiles(
          tournament.rounds,
          {
            ...tournament.config,
            format: tournament.format,
            participantModel: tournament.participantModel,
          },
          tournament.config?.roundProfiles || [],
        );
      }

      function createRoundControlRecord(round, record = {}) {
        return {
          round: normalizeRoundCount(record.round || round, round),
          motionTitle: String(record.motionTitle || record.title || "").trim(),
          motionText: String(record.motionText || record.motion || "").trim(),
          judgeNotes: String(record.judgeNotes || record.notes || "").trim(),
          prepMinutes: normalizeOptionalCount(record.prepMinutes, null, 240),
          motionReleased: Boolean(record.motionReleased),
          motionReleasedAt: String(record.motionReleasedAt || "").trim(),
          motionReleasedAtKey: normalizeTimestampKey(
            record.motionReleasedAtKey,
            record.motionReleasedAt,
          ),
          prepStartedAt: String(record.prepStartedAt || "").trim(),
          prepStartedAtKey: normalizeTimestampKey(record.prepStartedAtKey, record.prepStartedAt),
        };
      }

      function buildRoundControls(rounds, controls = []) {
        const existing = Array.isArray(controls) ? controls : [];
        return Array.from({ length: normalizeRoundCount(rounds, 1) }, (_, index) =>
          createRoundControlRecord(
            index + 1,
            existing.find((record) => Number(record.round) === index + 1) || {},
          ),
        );
      }

      function getRoundControls(tournament) {
        return buildRoundControls(tournament.rounds, tournament.roundControls || []);
      }

      function getRoundControlForRound(tournament, round) {
        return (
          getRoundControls(tournament).find((control) => Number(control.round) === Number(round)) ||
          createRoundControlRecord(round)
        );
      }

      function getRoundPrepEndKey(control) {
        const startKey = normalizeTimestampKey(control?.prepStartedAtKey, control?.prepStartedAt);
        const prepMinutes = normalizeOptionalCount(control?.prepMinutes, null, 240);
        if (!startKey || !prepMinutes) {
          return 0;
        }
        return startKey + prepMinutes * 60 * 1000;
      }

      function getRoundMotionStatus(control) {
        if (!control?.motionReleased) {
          return { label: "Locked", tone: "warning" };
        }

        if (getRoundPrepEndKey(control)) {
          const now = Date.now();
          const endKey = getRoundPrepEndKey(control);
          if (now < endKey) {
            return { label: "Prep Live", tone: "success" };
          }
          return { label: "Prep Closed", tone: "warning" };
        }

        return { label: "Motion Released", tone: "success" };
      }

      function getRoundPrepSummary(control) {
        const prepMinutes = normalizeOptionalCount(control?.prepMinutes, null, 240);
        if (!prepMinutes) {
          return "No prep timer set";
        }

        const endKey = getRoundPrepEndKey(control);
        if (!endKey) {
          return prepMinutes + " minute prep window ready";
        }

        const now = Date.now();
        const minutesRemaining = Math.max(0, Math.ceil((endKey - now) / 60000));
        if (minutesRemaining > 0) {
          return minutesRemaining + " minute" + (minutesRemaining === 1 ? "" : "s") + " remaining";
        }
        return "Prep closed after " + prepMinutes + " minutes";
      }

      function hasVariableRoundStructure(tournament) {
        const profiles = getRoundProfiles(tournament);
        return profiles.some(
          (profile) =>
            (normalizeRoundFormatOverride(profile.format) &&
              normalizeRoundFormatOverride(profile.format) !==
                String(tournament.format || "").trim()) ||
            Number(profile.teamsPerRoom) !== Number(tournament.config.teamsPerRoom) ||
            Number(profile.teamSize) !== Number(tournament.config.teamSize) ||
            Number(profile.speakersPerSide) !== Number(tournament.config.speakersPerSide),
        );
      }

      function getTournamentFlexibleFeatures(tournament) {
        if (!tournament) {
          return [];
        }

        const features = [];
        const format = normalizeFormatName(tournament.format);
        const participantModel = String(tournament.participantModel || "")
          .trim()
          .toLowerCase();
        const preset = getFormatPreset(format);
        const presetParticipantModel = String(preset?.participantModel || "")
          .trim()
          .toLowerCase();
        const defaults = getFormatSelectionDefaults(format, participantModel);
        const configuredScoring = normalizeScoringMethodChoice(tournament?.config?.scoringMethod);
        const defaultScoring = normalizeScoringMethodChoice(defaults.scoringMethod);

        if (format === "No Standard Format") {
          features.push(tournament.customFormatName ? "Custom ruleset" : "Custom format");
        }

        if (hasVariableRoundStructure(tournament)) {
          features.push("Round-by-round structure");
        }

        if (participantModel === "hybrid") {
          features.push("Mixed team and individual field");
        } else if (presetParticipantModel && participantModel && presetParticipantModel !== participantModel) {
          features.push("Custom field model");
        }

        if (Boolean(tournament?.config?.randomTeamsAllowed)) {
          features.push("Random teams enabled");
        }

        if (
          !hasConfiguredValue(tournament?.config?.teamsPerRoom) ||
          !hasConfiguredValue(tournament?.config?.teamSize) ||
          !hasConfiguredValue(tournament?.config?.speakersPerSide)
        ) {
          features.push("Flexible room structure");
        }

        if (configuredScoring && defaultScoring && configuredScoring !== defaultScoring) {
          features.push("Custom scoring");
        }

        return Array.from(new Set(features));
      }

      function usesFlexibleTournamentSetup(tournament) {
        return getTournamentFlexibleFeatures(tournament).length > 0;
      }

      function getTournamentFormatContextLabel(tournament, options = {}) {
        const formatLabel = getFormatLabel(tournament);
        const parts = [formatLabel];
        if (options.includeParticipantModel && tournament?.participantModel) {
          parts.push(toTitleLabel(tournament.participantModel));
        }
        return parts.filter(Boolean).join(" • ");
      }

      function getTournamentFlexibleSummary(tournament, limit = 2) {
        const features = getTournamentFlexibleFeatures(tournament);
        if (!features.length) {
          return "";
        }
        return features.slice(0, Math.max(1, limit)).join(" • ");
      }

      function getTournamentSetupBadgeLabel(tournament) {
        return getTournamentFlexibleSummary(tournament, 1) || getFormatLabel(tournament) || "Setup";
      }

      function getRoundStructureSummary(tournament) {
        const profiles = getRoundProfiles(tournament);
        const referenceProfile = profiles[0] || {};
        const outroundCount = getOutroundProfilesFromList(profiles).length;
        const inroundCount = Math.max(0, profiles.length - outroundCount);
        const uniqueStructures = new Set(
          profiles.map(
            (profile) =>
              getRoundFormat(tournament, profile) +
              "-" +
              profile.teamsPerRoom +
              "-" +
              profile.teamSize +
              "-" +
              profile.speakersPerSide,
          ),
        );

        if (uniqueStructures.size <= 1) {
          const parts = [
            getRoundFormatDisplayLabel(tournament, profiles[0] || null, {
              includeInheritance: false,
            }),
            inroundCount
              ? inroundCount + " in-round" + (inroundCount === 1 ? "" : "s")
              : "",
            outroundCount
              ? outroundCount + " out-round" + (outroundCount === 1 ? "" : "s")
              : "",
            hasConfiguredValue(referenceProfile.teamsPerRoom)
              ? referenceProfile.teamsPerRoom + " teams per room"
              : "Teams per room vary",
            hasConfiguredValue(referenceProfile.teamSize)
              ? referenceProfile.teamSize + " per team"
              : "Team size varies",
            hasConfiguredValue(referenceProfile.speakersPerSide)
              ? referenceProfile.speakersPerSide + " speakers per side"
              : "Speakers per side vary",
          ];
          return parts.filter(Boolean).join(", ");
        }

        return (
          uniqueStructures.size +
          " different round setups across " +
          profiles.length +
          " rounds" +
          (outroundCount ? " • " + outroundCount + " outround" + (outroundCount === 1 ? "" : "s") : "")
        );
      }

      function getBreakSizeSummary(value) {
        const normalized = normalizeOptionalBreakSize(value, null);
        if (normalized === null || normalized === 0) {
          return "No break configured";
        }
        return normalized + " break size";
      }

      function getScoringMethodSummary(value) {
        return normalizeScoringMethodChoice(value) || "No standard scoring method";
      }

      function getOptionalScoringSummary(target) {
        if (target?.config && (target?.rounds || target?.format)) {
          const profiles = getRoundProfiles(target);
          const optionalRoundConfigs = profiles.map((profile) =>
            getRoundOptionalScoreConfig(target, profile),
          );
          const crossRounds = optionalRoundConfigs.filter(
            (config) => config.crossExaminationEnabled,
          ).length;
          const rebuttalRounds = optionalRoundConfigs.filter(
            (config) => config.rebuttalEnabled,
          ).length;
          const parts = [];

          if (crossRounds) {
            parts.push(
              "Cross-examination in " +
                crossRounds +
                " round" +
                (crossRounds === 1 ? "" : "s"),
            );
          }
          if (rebuttalRounds) {
            parts.push(
              "Rebuttal in " +
                rebuttalRounds +
                " round" +
                (rebuttalRounds === 1 ? "" : "s"),
            );
          }

          return parts.length ? parts.join(" • ") : "Standard speaker scoring only";
        }

        const config = target?.config || target?.defaults || target || {};
        const parts = [];

        if (config.crossExaminationEnabled) {
          parts.push("Cross-examination: questions /20 and responses /40");
        }
        if (config.rebuttalEnabled) {
          parts.push("Rebuttal /50");
        }

        return parts.length ? parts.join(" • ") : "Standard speaker scoring only";
      }

      function getRoundOptionalScoreConfig(tournament, roundOrProfile = null) {
        if (!tournament) {
          return {
            crossExaminationEnabled: false,
            rebuttalEnabled: false,
            hasOptionalScores: false,
          };
        }

        const participantModel = String(tournament.participantModel || "").trim().toLowerCase();
        const teamBased = participantModel === "teams" || participantModel === "hybrid";
        const profile =
          roundOrProfile && typeof roundOrProfile === "object"
            ? roundOrProfile
            : getRoundProfileForRound(tournament, roundOrProfile || 1);
        const hasRoundFormatOverride = Boolean(normalizeRoundFormatOverride(profile?.format));
        const roundFormat = getRoundFormat(tournament, profile);
        const preset = getFormatPreset(roundFormat);

        if (!teamBased) {
          return {
            crossExaminationEnabled: false,
            rebuttalEnabled: false,
            hasOptionalScores: false,
          };
        }

        let crossExaminationEnabled = false;
        let rebuttalEnabled = false;

        if (roundFormat === "No Standard Format") {
          crossExaminationEnabled = Boolean(tournament.config?.crossExaminationEnabled);
          rebuttalEnabled = Boolean(tournament.config?.rebuttalEnabled);
        } else if (hasRoundFormatOverride) {
          crossExaminationEnabled = Boolean(preset.crossExaminationEnabled);
          rebuttalEnabled = Boolean(preset.rebuttalEnabled);
        } else {
          crossExaminationEnabled =
            Boolean(tournament.config?.crossExaminationEnabled) ||
            Boolean(preset.crossExaminationEnabled);
          rebuttalEnabled =
            Boolean(tournament.config?.rebuttalEnabled) || Boolean(preset.rebuttalEnabled);
        }

        return {
          crossExaminationEnabled,
          rebuttalEnabled,
          hasOptionalScores: crossExaminationEnabled || rebuttalEnabled,
        };
      }

      function renderScoringOptionToggles(config = {}, disabled = false) {
        return `
          <div class="field-grid two">
            <label class="checkbox-row">
              <input type="checkbox" name="crossExaminationEnabled" ${checked(
                config.crossExaminationEnabled,
              )} ${disabled ? "disabled" : ""} />
              <span>Use cross-examination scoring</span>
            </label>
            <label class="checkbox-row">
              <input type="checkbox" name="rebuttalEnabled" ${checked(
                config.rebuttalEnabled,
              )} ${disabled ? "disabled" : ""} />
              <span>Use rebuttal scoring</span>
            </label>
          </div>
          <p class="fine-print">
            Cross-examination adds questions out of 20 and responses out of 40. Rebuttal adds a separate score out of 50.
          </p>
        `;
      }

      function renderRoundPlannerEditor(rounds, profiles = [], baseConfig = {}, options = {}) {
        const roundProfiles = buildRoundProfiles(rounds, baseConfig, profiles);
        const plannerGuidance =
          options.plannerGuidance ||
          "Each round can use a different team count, team size, or speaker count. Leave any round field blank when that round should inherit the tournament default.";

        return `
          <div class="round-planner-wrap">
            <div class="round-planner-grid">
              ${roundProfiles
                .map(
                  (profile) => `
                    <article class="round-planner-card" data-round-planner-row data-round="${escapeHtml(
                      profile.round,
                    )}">
                      <div class="round-planner-card-header">
                        <div class="round-planner-card-title">
                          <p class="eyebrow">Round ${escapeHtml(profile.round)}</p>
                          <strong>${escapeHtml(profile.label || "Round " + profile.round)}</strong>
                        </div>
                        <span class="mini-pill ${escapeHtml(
                          isOutroundProfile(profile) ? "warning" : "success",
                        )}">${escapeHtml(getRoundStageLabel(profile.stage))}</span>
                      </div>
                      <div class="field-grid two round-planner-card-grid">
                        <label>
                          Label
                          <input type="text" name="roundLabel-${escapeHtml(
                            profile.round,
                          )}" value="${escapeHtml(profile.label)}" />
                        </label>
                        <label>
                          Stage
                          <select name="roundStage-${escapeHtml(profile.round)}">
                            ${getRoundStageOptionMarkup(profile.stage)}
                          </select>
                        </label>
                        <label>
                          Pairing
                          <select name="roundPairingMethod-${escapeHtml(profile.round)}">
                            ${getRoundPairingMethodOptionMarkup(
                              profile.pairingMethod,
                              getAutomaticRoundPairingMethod(roundProfiles, profile),
                              profile.stage,
                            )}
                          </select>
                        </label>
                        <label>
                          Format
                          <select name="roundFormat-${escapeHtml(profile.round)}">
                            ${getRoundFormatOptionMarkup(
                              profile.format,
                              options.tournamentFormat || String(baseConfig.format || "").trim(),
                            )}
                          </select>
                        </label>
                        <label>
                          Teams / Room
                          <input type="number" min="1" max="8" name="roundTeamsPerRoom-${escapeHtml(
                            profile.round,
                          )}" value="${escapeHtml(profile.teamsPerRoom)}" placeholder="Default" />
                        </label>
                        <label>
                          People / Team
                          <input type="number" min="1" max="8" name="roundTeamSize-${escapeHtml(
                            profile.round,
                          )}" value="${escapeHtml(profile.teamSize)}" placeholder="Default" />
                        </label>
                        <label>
                          Speakers / Side
                          <input type="number" min="1" max="8" name="roundSpeakersPerSide-${escapeHtml(
                            profile.round,
                          )}" value="${escapeHtml(profile.speakersPerSide)}" placeholder="Default" />
                        </label>
                        <label class="round-planner-card-notes">
                          Notes
                          <input type="text" name="roundNotes-${escapeHtml(
                            profile.round,
                          )}" value="${escapeHtml(profile.notes)}" placeholder="Optional note" />
                        </label>
                      </div>
                    </article>
                  `,
                )
                .join("")}
            </div>
          </div>
          <p class="fine-print" data-round-planner-guidance>${escapeHtml(plannerGuidance)}</p>
        `;
      }

      function renderRoundPlannerEditorContainer(
        rounds,
        profiles = [],
        baseConfig = {},
        options = {},
      ) {
        const normalizedBaseConfig = {
          teamsPerRoom: normalizeOptionalCount(baseConfig?.teamsPerRoom, null),
          teamSize: normalizeOptionalCount(baseConfig?.teamSize, null),
          speakersPerSide: normalizeOptionalCount(baseConfig?.speakersPerSide, null),
        };

        return `
          <div
            data-round-planner-editor
            data-base-teams-per-room="${escapeHtml(normalizedBaseConfig.teamsPerRoom ?? "")}"
            data-base-team-size="${escapeHtml(normalizedBaseConfig.teamSize ?? "")}"
            data-base-speakers-per-side="${escapeHtml(normalizedBaseConfig.speakersPerSide ?? "")}"
          >
            ${renderRoundPlannerEditor(rounds, profiles, normalizedBaseConfig, options)}
          </div>
        `;
      }

      function renderRoundPlannerReadOnly(tournament) {
        const profiles = getRoundProfiles(tournament);
        if (!profiles.length) {
          return `<div class="empty-state">No round structure has been configured yet.</div>`;
        }

        return `
          <div class="round-planner-wrap">
            <div class="round-planner-summary-grid">
              ${profiles
                .map(
                  (profile) => `
                    <article class="round-planner-summary-card">
                      <div class="round-planner-card-header">
                        <div class="round-planner-card-title">
                          <p class="eyebrow">Round ${escapeHtml(profile.round)}</p>
                          <strong>${escapeHtml(profile.label)}</strong>
                        </div>
                        <span class="mini-pill ${escapeHtml(
                          isOutroundProfile(profile) ? "warning" : "success",
                        )}">${escapeHtml(getRoundStageLabel(profile.stage))}</span>
                      </div>
                      <div class="round-planner-summary-list">
                        <span><strong>Pairing:</strong> ${escapeHtml(
                          getDrawMethodDisplayLabel(tournament, profile, "auto"),
                        )}</span>
                        <span><strong>Format:</strong> ${escapeHtml(
                          getRoundFormatDisplayLabel(tournament, profile),
                        )}</span>
                        <span><strong>Teams / Room:</strong> ${escapeHtml(
                          getConfiguredStructureValue(profile.teamsPerRoom, "Flexible"),
                        )}</span>
                        <span><strong>People / Team:</strong> ${escapeHtml(
                          getConfiguredStructureValue(profile.teamSize, "Flexible"),
                        )}</span>
                        <span><strong>Speakers / Side:</strong> ${escapeHtml(
                          getConfiguredStructureValue(profile.speakersPerSide, "Flexible"),
                        )}</span>
                      </div>
                    </article>
                  `,
                )
                .join("")}
            </div>
          </div>
        `;
      }

      function calculateBpTeamPoints(record) {
        return (
          normalizeNonNegative(record.firsts, 0) * 3 +
          normalizeNonNegative(record.seconds, 0) * 2 +
          normalizeNonNegative(record.thirds, 0)
        );
      }

      function calculateWinLossPoints(record) {
        return (
          normalizeNonNegative(record.wins, 0) * 3 +
          normalizeNonNegative(record.losses, 0)
        );
      }

      function normalizeStandingRecord(record, tournament) {
        const profile = getStandingsProfile(tournament);
        const hasPlacementBreakdown = ["firsts", "seconds", "thirds", "fourths"].some(
          (key) => record?.[key] !== undefined,
        );
        const hasLossBreakdown = record?.losses !== undefined;
        const normalized = {
          id: record.id || createId("standing"),
          name: String(record.name || "").trim(),
          wins: normalizeNonNegative(record.wins, 0),
          losses: normalizeNonNegative(record.losses, 0),
          points: normalizeNonNegative(record.points, 0),
          speaks: normalizeNonNegative(record.speaks, 0),
          firsts: normalizeNonNegative(record.firsts, 0),
          seconds: normalizeNonNegative(record.seconds, 0),
          thirds: normalizeNonNegative(record.thirds, 0),
          fourths: normalizeNonNegative(record.fourths, 0),
          rank: normalizeNonNegative(record.rank, 0),
        };

        if (profile.mode === "bp_team") {
          if (!hasPlacementBreakdown && normalized.wins > 0) {
            normalized.firsts = normalized.wins;
          }
          if (hasPlacementBreakdown) {
            normalized.points = calculateBpTeamPoints(normalized);
          }
          normalized.wins = normalized.firsts;
        }

        if (profile.mode === "win_loss_team" && hasLossBreakdown) {
          normalized.points = calculateWinLossPoints(normalized);
        }

        return normalized;
      }

      function normalizeParticipantRecord(record) {
        return {
          ...record,
          email: normalizeEmail(record.email),
          name: String(record.name || "").trim(),
          institution: String(record.institution || "").trim(),
          teamId: String(record.teamId || "").trim(),
          teamName: String(record.teamName || "").trim(),
          wins: normalizeNonNegative(record.wins, 0),
          losses: normalizeNonNegative(record.losses, 0),
          points: normalizeNonNegative(record.points, 0),
          firsts: normalizeNonNegative(record.firsts, 0),
          seconds: normalizeNonNegative(record.seconds, 0),
          thirds: normalizeNonNegative(record.thirds, 0),
          fourths: normalizeNonNegative(record.fourths, 0),
          speakerScore: normalizeNonNegative(record.speakerScore, 0),
          feedback: Array.isArray(record.feedback) ? clone(record.feedback) : [],
          sanctions: Array.isArray(record.sanctions) ? clone(record.sanctions) : [],
        };
      }

      function sortStandingsForTournament(standings, tournament) {
        const profile = getStandingsProfile(tournament);
        return applyCompetitionRanks(
          standings
          .map((standing) => normalizeStandingRecord(standing, tournament))
          .sort((left, right) => {
            if (profile.mode === "bp_team") {
              return (
                Number(right.points) - Number(left.points) ||
                Number(right.speaks) - Number(left.speaks) ||
                Number(right.firsts) - Number(left.firsts) ||
                Number(right.seconds) - Number(left.seconds) ||
                Number(right.thirds) - Number(left.thirds) ||
                Number(left.fourths) - Number(right.fourths) ||
                String(left.name).localeCompare(String(right.name))
              );
            }

            if (profile.mode === "win_loss_team") {
              return (
                Number(right.points) - Number(left.points) ||
                Number(right.speaks) - Number(left.speaks) ||
                Number(right.wins) - Number(left.wins) ||
                Number(left.losses) - Number(right.losses) ||
                String(left.name).localeCompare(String(right.name))
              );
            }

            if (profile.mode === "mixed_team") {
              return (
                Number(right.points) - Number(left.points) ||
                Number(right.speaks) - Number(left.speaks) ||
                Number(right.wins) - Number(left.wins) ||
                Number(right.firsts) - Number(left.firsts) ||
                Number(right.seconds) - Number(left.seconds) ||
                Number(right.thirds) - Number(left.thirds) ||
                Number(left.fourths) - Number(right.fourths) ||
                Number(left.losses) - Number(right.losses) ||
                String(left.name).localeCompare(String(right.name))
              );
            }

            return (
              (String(tournament?.participantModel || "").trim().toLowerCase() === "individuals"
                ? Number(right.points) - Number(left.points) ||
                  Number(right.wins) - Number(left.wins)
                : Number(right.wins) - Number(left.wins) ||
                  Number(right.points) - Number(left.points) ||
                  Number(right.speaks) - Number(left.speaks)) ||
              String(left.name).localeCompare(String(right.name))
            );
          }),
          (left, right) => areStandingsTied(left, right, tournament),
          "rank",
        );
      }

      function applyCompetitionRanks(records, areTied, rankKey = "rank") {
        let previousRecord = null;
        let currentRank = 0;

        return (Array.isArray(records) ? records : []).map((record, index) => {
          if (!previousRecord || !areTied(previousRecord, record, index)) {
            currentRank = index + 1;
          }
          previousRecord = record;
          return {
            ...record,
            [rankKey]: currentRank,
          };
        });
      }

      function areStandingsTied(left, right, tournament) {
        if (!left || !right) {
          return false;
        }

        const profile = getStandingsProfile(tournament);
        const first = normalizeStandingRecord(left, tournament);
        const second = normalizeStandingRecord(right, tournament);

        if (profile.mode === "bp_team") {
          return (
            Number(first.points) === Number(second.points) &&
            Number(first.speaks) === Number(second.speaks) &&
            Number(first.firsts) === Number(second.firsts) &&
            Number(first.seconds) === Number(second.seconds) &&
            Number(first.thirds) === Number(second.thirds) &&
            Number(first.fourths) === Number(second.fourths)
          );
        }

        if (profile.mode === "win_loss_team") {
          return (
            Number(first.points) === Number(second.points) &&
            Number(first.speaks) === Number(second.speaks) &&
            Number(first.wins) === Number(second.wins) &&
            Number(first.losses) === Number(second.losses)
          );
        }

        if (profile.mode === "mixed_team") {
          return (
            Number(first.points) === Number(second.points) &&
            Number(first.speaks) === Number(second.speaks) &&
            Number(first.wins) === Number(second.wins) &&
            Number(first.firsts) === Number(second.firsts) &&
            Number(first.seconds) === Number(second.seconds) &&
            Number(first.thirds) === Number(second.thirds) &&
            Number(first.fourths) === Number(second.fourths) &&
            Number(first.losses) === Number(second.losses)
          );
        }

        if (String(tournament?.participantModel || "").trim().toLowerCase() === "individuals") {
          return (
            Number(first.points) === Number(second.points) &&
            Number(first.wins) === Number(second.wins)
          );
        }

        return (
          Number(first.wins) === Number(second.wins) &&
          Number(first.points) === Number(second.points) &&
          Number(first.speaks) === Number(second.speaks)
        );
      }

      function areSpeakerStandingsTied(left, right) {
        if (!left || !right) {
          return false;
        }
        return (
          Number(left.cumulativeSpeakerScore ?? left.speakerScore ?? 0) ===
          Number(right.cumulativeSpeakerScore ?? right.speakerScore ?? 0)
        );
      }

      function getStandingsColumns(tournament) {
        const profile = getStandingsProfile(tournament);
        if (profile.mode === "bp_team") {
          return [
            { key: "rank", label: "Rank" },
            { key: "name", label: "Entry" },
            { key: "speaks", label: "Speaks" },
            { key: "firsts", label: "1sts" },
            { key: "seconds", label: "2nds" },
            { key: "thirds", label: "3rds" },
            { key: "fourths", label: "4ths" },
            { key: "points", label: "Team points" },
          ];
        }

        if (profile.mode === "win_loss_team") {
          return [
            { key: "rank", label: "Rank" },
            { key: "name", label: "Entry" },
            { key: "speaks", label: "Speaks" },
            { key: "wins", label: "Wins" },
            { key: "losses", label: "Losses" },
            { key: "points", label: "Team points" },
          ];
        }

        if (profile.mode === "mixed_team") {
          return [
            { key: "rank", label: "Rank" },
            { key: "name", label: "Entry" },
            { key: "points", label: "Team points" },
            { key: "speaks", label: "Speaks" },
            { key: "wins", label: "Wins" },
            { key: "losses", label: "Losses" },
            { key: "firsts", label: "1sts" },
            { key: "seconds", label: "2nds" },
            { key: "thirds", label: "3rds" },
            { key: "fourths", label: "4ths" },
          ];
        }

        return [
          { key: "rank", label: "Rank" },
          {
            key: "name",
            label:
              String(tournament?.participantModel || "").trim().toLowerCase() === "individuals"
                ? "Speaker"
                : "Entry",
          },
          ...(String(tournament?.participantModel || "").trim().toLowerCase() === "individuals"
            ? [{ key: "points", label: "Speaks" }]
            : [
                { key: "wins", label: "Wins" },
                { key: "points", label: "Points" },
              ]),
        ];
      }

      function getStandingCellValue(standing, key) {
        if (key === "name") {
          return standing.name;
        }
        return standing[key] ?? 0;
      }

      function getFormattedStandingCellValue(tournament, standing, key) {
        const value = getStandingCellValue(standing, key);
        if (["points", "speakerScore"].includes(String(key || "").trim())) {
          return formatScoreValue(value);
        }
        if (String(key || "").trim() === "speaks") {
          return formatScoreValue(value);
        }
        return value;
      }

      function getStandingSummaryText(tournament, standing) {
        const profile = getStandingsProfile(tournament);
        const normalized = normalizeStandingRecord(standing, tournament);

        if (profile.mode === "bp_team") {
          return (
            formatScoreValue(normalized.points) +
            " team points • " +
            formatScoreValue(normalized.speaks) +
            " speaks • " +
            normalized.firsts +
            " firsts, " +
            normalized.seconds +
            " seconds, " +
            normalized.thirds +
            " thirds, " +
            normalized.fourths +
            " fourths"
          );
        }

        if (profile.mode === "win_loss_team") {
          return (
            formatScoreValue(normalized.points) +
            " team points • " +
            formatScoreValue(normalized.speaks) +
            " speaks • " +
            normalized.wins +
            " wins and " +
            normalized.losses +
            " losses"
          );
        }

        if (profile.mode === "mixed_team") {
          return (
            formatScoreValue(normalized.points) +
            " team points • " +
            formatScoreValue(normalized.speaks) +
            " speaks • " +
            normalized.wins +
            " wins • " +
            normalized.firsts +
            " firsts"
          );
        }

        if (String(tournament?.participantModel || "").trim().toLowerCase() === "individuals") {
          return formatScoreValue(normalized.points) + " speaks";
        }

        return normalized.wins + " wins and " + formatScoreValue(normalized.points) + " points";
      }

      function getParticipantSummaryText(tournament, participant) {
        const normalized = normalizeParticipantRecord(participant);
        const computedSpeakerScore = getParticipantComputedSpeakerScore(tournament, normalized);
        if (tournament.participantModel === "teams") {
          return (
            (normalized.teamName || "Unassigned team") +
            (normalized.institution ? " • " + normalized.institution : "") +
            " • speaker score " +
            formatScoreValue(computedSpeakerScore)
          );
        }
        return (
          (normalized.institution ? normalized.institution + " • " : "") +
          "speaker score " +
          formatScoreValue(computedSpeakerScore)
        );
      }

      function getTeamStanding(tournament, team) {
        return (
          getComputedStandings(tournament).find(
            (standing) =>
              normalizeTextKey(standing.name) === normalizeTextKey(team.name),
          ) || null
        );
      }

      function getTeamSpeakers(tournament, team) {
        const teamNameKey = normalizeTextKey(team.name);
        const institutionKey = normalizeTextKey(team.institution);
        return (tournament.participants || [])
          .map((participant) => normalizeParticipantRecord(participant))
          .filter((participant) => {
            if (participant.teamId && participant.teamId === team.id) {
              return true;
            }
            if (normalizeTextKey(participant.teamName) !== teamNameKey) {
              return false;
            }
            if (!institutionKey) {
              return true;
            }
            return (
              !participant.institution ||
              normalizeTextKey(participant.institution) === institutionKey
            );
          });
      }

      function getTournamentTeams(tournament) {
        return normalizeTeamsForTournament(tournament.teams || [], tournament);
      }

      function getTeamOptionsMarkup(tournament, currentTeamId = "") {
        const teams = getTournamentTeams(tournament);
        return [
          `<option value="">No linked team</option>`,
          ...teams.map(
            (team) =>
              `<option value="${escapeHtml(team.id)}" ${selected(
                team.id,
                currentTeamId,
              )}>${escapeHtml(getTeamDisplayLabel(team))}</option>`,
          ),
        ].join("");
      }

      function getEffectiveRoundStructure(tournament, roundOrProfile = null, options = {}) {
        const profile =
          roundOrProfile && typeof roundOrProfile === "object"
            ? roundOrProfile
            : getRoundProfileForRound(tournament, roundOrProfile || 1);
        const roundFormat = getRoundFormat(tournament, profile);
        const preset = getFormatPreset(roundFormat);
        const isStandardFormat = roundFormat !== "No Standard Format";
        const baseTeamsPerRoom = isStandardFormat ? preset.teamsPerRoom : profile?.teamsPerRoom;
        const baseTeamSize = isStandardFormat ? preset.teamSize : profile?.teamSize;
        const baseSpeakersPerSide = isStandardFormat
          ? preset.speakersPerSide
          : profile?.speakersPerSide;

        return {
          format: roundFormat,
          isStandardFormat,
          teamsPerRoom: normalizeOptionalCount(
            options.allowRoomOverride && !isStandardFormat
              ? options.roomSizeOverride
              : baseTeamsPerRoom,
            normalizeOptionalCount(tournament?.config?.teamsPerRoom, 2),
          ),
          teamSize: normalizeOptionalCount(
            baseTeamSize,
            normalizeOptionalCount(tournament?.config?.teamSize, 1),
          ),
          speakersPerSide: normalizeOptionalCount(
            baseSpeakersPerSide,
            normalizeOptionalCount(tournament?.config?.speakersPerSide, 1),
          ),
        };
      }

      function getDrawEntriesForTournament(tournament) {
        const teams = getTournamentTeams(tournament);
        const participantModel = String(tournament?.participantModel || "").trim().toLowerCase();
        if (
          (participantModel === "teams" && teams.length) ||
          (participantModel === "hybrid" && teams.length) ||
          (participantModel !== "teams" && participantModel !== "hybrid" && teams.length >= 2)
        ) {
          return teams
            .map((team) => {
              const standing = getTeamStanding(tournament, team);
              const roster = getTeamSpeakers(tournament, team);
              return {
                id: team.id,
                label: getTeamDisplayLabel(team),
                shortLabel: team.name,
                publicAlias: team.publicAlias || "",
                type: "team",
                institution: team.institution,
                team,
                roster,
                standing: standing ? normalizeStandingRecord(standing, tournament) : null,
              };
            })
            .filter((entry) => entry.label);
        }

        return (tournament.participants || [])
          .map((participant) => normalizeParticipantRecord(participant))
          .map((participant) => ({
            id: participant.id,
            label: participant.institution
              ? participant.institution + " " + participant.name
              : participant.name,
            shortLabel: participant.name,
            type: "speaker",
            institution: participant.institution,
            participant,
          }))
          .filter((entry) => entry.label);
      }

      function getEligibleTeamDrawEntriesForRound(tournament, roundProfile = {}) {
        const structure = getEffectiveRoundStructure(tournament, roundProfile);
        const expectedTeamSize = Math.max(1, Number(structure.teamSize) || 1);
        return getTournamentTeams(tournament)
          .map((team) => {
            const standing = getTeamStanding(tournament, team);
            const roster = getTeamSpeakers(tournament, team);
            return {
              id: team.id,
              label: getTeamDisplayLabel(team),
              shortLabel: team.name,
              publicAlias: team.publicAlias || "",
              type: "team",
              institution: team.institution,
              team,
              roster,
              standing: standing ? normalizeStandingRecord(standing, tournament) : null,
            };
          })
          .filter(
            (entry) =>
              entry.label &&
              Array.isArray(entry.roster) &&
              entry.roster.length === expectedTeamSize,
          );
      }

      function getSpeakerDrawEntriesForTournament(tournament) {
        return (tournament.participants || [])
          .map((participant) => normalizeParticipantRecord(participant))
          .map((participant) => ({
            id: participant.id,
            label: participant.institution
              ? participant.institution + " " + participant.name
              : participant.name,
            shortLabel: participant.name,
            type: "speaker",
            institution: participant.institution,
            participant,
          }))
          .filter((entry) => entry.label);
      }

      function shouldGenerateSpeakerPairingTeams(tournament, roundProfile = {}) {
        const participantModel = String(tournament?.participantModel || "").trim().toLowerCase();
        const structure = getEffectiveRoundStructure(tournament, roundProfile);
        const teamSize = Math.max(1, Number(structure.teamSize) || 1);
        const teamsPerRoom = Math.max(1, Number(structure.teamsPerRoom) || 1);
        const hasManagedTeams = getTournamentTeams(tournament).some(
          (team) => normalizeTeamSource(team?.source) === "manual",
        );
        const eligibleTeams = getEligibleTeamDrawEntriesForRound(tournament, roundProfile);

        if (participantModel === "individuals") {
          return teamSize > 1 && teamsPerRoom > 1;
        }

        if (participantModel === "teams" && eligibleTeams.length === 0) {
          return teamSize > 1 && teamsPerRoom > 1;
        }

        if (participantModel === "hybrid" && !hasManagedTeams) {
          return teamSize > 1 && teamsPerRoom > 1;
        }

        return false;
      }

      function getSpeakerDrawEntriesExcludingParticipants(tournament, excludedParticipantIds = []) {
        const excluded = new Set(
          (Array.isArray(excludedParticipantIds) ? excludedParticipantIds : [])
            .map((id) => String(id || "").trim())
            .filter(Boolean),
        );
        return getSpeakerDrawEntriesForTournament(tournament).filter(
          (entry) => !excluded.has(String(entry.participant?.id || entry.id || "").trim()),
        );
      }

      function buildSpeakerPairingTeamPlan(
        tournament,
        roundProfile = {},
        method = "random",
        participantEntries = null,
      ) {
        const participants = Array.isArray(participantEntries)
          ? participantEntries
          : getSpeakerDrawEntriesForTournament(tournament);
        const structure = getEffectiveRoundStructure(tournament, roundProfile);
        const teamSize = Math.max(1, Number(structure.teamSize) || 1);
        let orderedParticipants = [...participants];

        if (method === "random") {
          orderedParticipants = shuffleEntries(orderedParticipants);
        } else {
          orderedParticipants.sort(
            (left, right) =>
              Number(
                getParticipantComputedSpeakerScore(tournament, right.participant) || 0,
              ) -
                Number(getParticipantComputedSpeakerScore(tournament, left.participant) || 0) ||
              String(left.shortLabel || left.label).localeCompare(
              String(right.shortLabel || right.label),
            ),
          );
        }

        const completeParticipantCount =
          Math.floor(orderedParticipants.length / teamSize) * teamSize;
        const pairedParticipants = orderedParticipants.slice(0, completeParticipantCount);
        const overflowParticipants = orderedParticipants
          .slice(completeParticipantCount)
          .map((entry) => normalizeParticipantRecord(entry.participant));

        const entries = chunkEntries(pairedParticipants, teamSize)
          .filter((group) => group.length === teamSize)
          .map((group, index) => {
            const roster = group.map((entry) => normalizeParticipantRecord(entry.participant));
            const displayNames = roster.map((participant) => participant.name).filter(Boolean);
            const shortNames = displayNames.map(
              (name) => String(name || "").trim().split(/\s+/)[0] || name,
            );
            const institutions = Array.from(
              new Set(roster.map((participant) => String(participant.institution || "").trim()).filter(Boolean)),
            );
            const institutionLabel = institutions.length === 1 ? institutions[0] : "";
            const label = displayNames.join(" / ");
            const shortLabel = shortNames.join(" / ") || label || "Pairing Team " + (index + 1);
            const speakerStrength = roundScoreValue(
              roster.reduce(
                (sum, participant) =>
                  sum + Number(getParticipantComputedSpeakerScore(tournament, participant) || 0),
                0,
              ) / Math.max(1, roster.length),
            );
            const teamRecord = createTeamRecord(label || "Pairing Team " + (index + 1), institutionLabel, {
              source: "generated",
              notes: "Round-generated speaker pairing.",
            });

            return {
              id: teamRecord.id,
              label: label || shortLabel,
              shortLabel,
              type: "team",
              institution: institutionLabel,
              team: teamRecord,
              roster,
              standing: {
                wins: 0,
                losses: 0,
                points: speakerStrength,
                firsts: 0,
                seconds: 0,
                thirds: 0,
                fourths: 0,
                speakerScore: speakerStrength,
              },
            };
          });

        return {
          entries,
          overflowParticipants,
        };
      }

      function getSupplementalRoundTeamPlan(tournament, roundProfile = {}, method = "random") {
        const structure = getEffectiveRoundStructure(tournament, roundProfile);
        const eligibleTeamEntries = getEligibleTeamDrawEntriesForRound(tournament, roundProfile);
        const assignedParticipantIds = eligibleTeamEntries.flatMap((entry) =>
          Array.isArray(entry.roster)
            ? entry.roster
                .map((participant) => String(participant?.id || "").trim())
                .filter(Boolean)
            : [],
        );
        const supplementalPairingPlan =
          Number(structure.teamSize || 0) > 1
            ? buildSpeakerPairingTeamPlan(
                tournament,
                roundProfile,
                method,
                getSpeakerDrawEntriesExcludingParticipants(tournament, assignedParticipantIds),
              )
            : { entries: [], overflowParticipants: [] };

        return {
          eligibleTeamEntries,
          supplementalPairingPlan,
        };
      }

      function getDrawGenerationPlan(
        tournament,
        roundProfile = {},
        method = "power",
        roomSizeOverride = null,
      ) {
        const resolvedMethod = getResolvedDrawMethod(tournament, roundProfile, method);
        if (isOutroundProfile(roundProfile)) {
          const outroundPlan = getOutroundDrawGenerationPlan(
            tournament,
            roundProfile,
            resolvedMethod,
            roomSizeOverride,
          );
          if (outroundPlan) {
            return outroundPlan;
          }
        }

        const participantModel = String(tournament?.participantModel || "").trim().toLowerCase();
        const hasManagedTeams = getTournamentTeams(tournament).some(
          (team) => normalizeTeamSource(team?.source) === "manual",
        );
        const structure = getEffectiveRoundStructure(tournament, roundProfile, {
          roomSizeOverride,
          allowRoomOverride: true,
        });
        const roomSize = Math.max(1, Number(structure.teamsPerRoom) || 1);
        const supplementalTeamPlan =
          participantModel === "teams" || participantModel === "hybrid"
            ? getSupplementalRoundTeamPlan(tournament, roundProfile, method)
            : { eligibleTeamEntries: [], supplementalPairingPlan: { entries: [], overflowParticipants: [] } };

        if (shouldGenerateSpeakerPairingTeams(tournament, roundProfile)) {
          const pairingPlan = buildSpeakerPairingTeamPlan(tournament, roundProfile, method);
          return {
            roomSize,
            entries: pairingPlan.entries,
            overflowParticipants: pairingPlan.overflowParticipants,
            resolvedMethod,
          };
        }

        if (participantModel === "teams") {
          const { eligibleTeamEntries, supplementalPairingPlan } = supplementalTeamPlan;
          return {
            roomSize,
            entries: eligibleTeamEntries.concat(supplementalPairingPlan.entries),
            overflowParticipants: supplementalPairingPlan.overflowParticipants,
            resolvedMethod,
          };
        }

        if (participantModel === "individuals") {
          return {
            roomSize,
            entries: getSpeakerDrawEntriesForTournament(tournament),
            overflowParticipants: [],
            resolvedMethod,
          };
        }

        if (participantModel === "hybrid" && !hasManagedTeams) {
          return {
            roomSize,
            entries: getSpeakerDrawEntriesForTournament(tournament),
            overflowParticipants: [],
            resolvedMethod,
          };
        }

        if (participantModel === "hybrid") {
          const { eligibleTeamEntries, supplementalPairingPlan } = supplementalTeamPlan;
          return {
            roomSize,
            entries: eligibleTeamEntries.concat(supplementalPairingPlan.entries),
            overflowParticipants: supplementalPairingPlan.overflowParticipants,
            resolvedMethod,
          };
        }

        return {
          roomSize,
          entries: getDrawEntriesForTournament(tournament),
          overflowParticipants: [],
          resolvedMethod,
        };
      }

      function getOutroundProgressionInfo(tournament, roundProfile = {}) {
        const profile =
          roundProfile && typeof roundProfile === "object"
            ? roundProfile
            : getRoundProfileForRound(tournament, roundProfile || 1);
        const outrounds = getOutroundProfilesFromList(getRoundProfiles(tournament));
        const index = outrounds.findIndex(
          (entry) => Number(entry.round || 0) === Number(profile.round || 0),
        );
        const breakSize = normalizeOptionalBreakSize(tournament?.config?.breakSize, null);
        const structure = getEffectiveRoundStructure(tournament, profile);
        const minimumFieldSize = Math.max(2, Number(structure.teamsPerRoom) || 2);
        const targetFieldSize =
          index >= 0 && breakSize
            ? Math.max(
                minimumFieldSize,
                Math.round(Number(breakSize || 0) / Math.max(1, 2 ** index)),
              )
            : 0;

        return {
          profile,
          outrounds,
          index,
          breakSize,
          structure,
          minimumFieldSize,
          targetFieldSize,
          previousProfile: index > 0 ? outrounds[index - 1] : null,
        };
      }

      function getBreakBoard(tournament) {
        const breakSize = normalizeOptionalBreakSize(tournament?.config?.breakSize, null);
        const standings = getComputedStandings(tournament);
        if (!breakSize || !standings.length) {
          return null;
        }

        const cut = Math.max(0, Math.min(Number(breakSize || 0), standings.length));
        return {
          breakSize,
          total: standings.length,
          breaking: standings.slice(0, cut),
          missing: standings.slice(cut),
          cutStanding: standings[cut - 1] || null,
          nextStanding: standings[cut] || null,
        };
      }

      function getOutroundEligibleEntryCatalog(tournament, roundProfile = {}) {
        return new Map(
          getEligibleTeamDrawEntriesForRound(tournament, roundProfile)
            .filter((entry) => String(entry?.team?.id || "").trim())
            .map((entry) => [String(entry.team.id || "").trim(), entry]),
        );
      }

      function getBreakQualifiedEntriesForRound(tournament, roundProfile = {}, limit = null) {
        const board = getBreakBoard(tournament);
        if (!board) {
          return [];
        }

        const catalog = getOutroundEligibleEntryCatalog(tournament, roundProfile);
        const target = Math.max(
          0,
          Math.min(
            Number(limit || board.breakSize || 0),
            board.breaking.length,
          ),
        );

        return board.breaking
          .map((standing) => {
            const team = findTournamentTeamByName(tournament, standing?.name || "");
            if (!team) {
              return null;
            }
            return catalog.get(String(team.id || "").trim()) || null;
          })
          .filter(Boolean)
          .slice(0, target);
      }

      function getRankedOfficialOutroundSlotRecords(tournament, drawEntry = {}) {
        const slots = Array.isArray(drawEntry?.slots) ? drawEntry.slots : [];
        const officialResults = normalizeDrawOfficialResults(drawEntry?.officialResults);
        if (!slots.length || !Object.keys(officialResults).length) {
          return [];
        }

        const completeRanks = slots.every((slot) => {
          const result = officialResults[getDrawSlotCheckInKey(slot)] || {};
          return Number(result.rank || 0) > 0;
        });
        if (completeRanks) {
          return slots
            .map((slot) => ({
              slot,
              result: officialResults[getDrawSlotCheckInKey(slot)] || {},
            }))
            .sort((left, right) => Number(left.result.rank || 0) - Number(right.result.rank || 0));
        }

        const completeOutcomes = slots.every((slot) => {
          const result = officialResults[getDrawSlotCheckInKey(slot)] || {};
          return String(result.outcome || "").trim();
        });
        if (completeOutcomes) {
          return slots
            .map((slot) => ({
              slot,
              result: officialResults[getDrawSlotCheckInKey(slot)] || {},
            }))
            .sort((left, right) => {
              const leftWin = String(left.result.outcome || "").trim().toLowerCase() === "win";
              const rightWin = String(right.result.outcome || "").trim().toLowerCase() === "win";
              return Number(rightWin) - Number(leftWin);
            });
        }

        return [];
      }

      function getAdvancingEntriesFromPreviousOutround(tournament, roundProfile = {}) {
        const progression = getOutroundProgressionInfo(tournament, roundProfile);
        if (!progression.previousProfile || !progression.targetFieldSize) {
          return [];
        }

        const previousDrawEntries = (tournament.draw || [])
          .filter(
            (entry) =>
              Number(entry.round || 0) === Number(progression.previousProfile.round || 0) &&
              Array.isArray(entry.slots) &&
              entry.slots.length,
          )
          .sort(
            (left, right) =>
              String(left.room || "").localeCompare(String(right.room || "")) ||
              String(left.id || "").localeCompare(String(right.id || "")),
          );

        if (!previousDrawEntries.length) {
          return [];
        }

        const advancePerRoom = Math.max(
          1,
          Math.floor(Number(progression.targetFieldSize || 0) / previousDrawEntries.length),
        );
        const catalog = getOutroundEligibleEntryCatalog(tournament, roundProfile);
        const advancing = [];

        for (const drawEntry of previousDrawEntries) {
          const rankedSlots = getRankedOfficialOutroundSlotRecords(tournament, drawEntry);
          if (rankedSlots.length !== drawEntry.slots.length) {
            return [];
          }

          rankedSlots.slice(0, advancePerRoom).forEach((record) => {
            const teamId = String(record.slot?.teamId || "").trim();
            if (!teamId) {
              return;
            }
            const entry = catalog.get(teamId);
            if (entry) {
              advancing.push(entry);
            }
          });
        }

        return Array.from(
          new Map(
            advancing.map((entry) => [String(entry?.team?.id || entry?.id || "").trim(), entry]),
          ).values(),
        ).slice(0, progression.targetFieldSize);
      }

      function getOutroundDrawGenerationPlan(
        tournament,
        roundProfile = {},
        method = "auto",
        roomSizeOverride = null,
      ) {
        const progression = getOutroundProgressionInfo(tournament, roundProfile);
        const resolvedMethod = getResolvedDrawMethod(tournament, progression.profile, method);
        const structure = getEffectiveRoundStructure(tournament, progression.profile, {
          roomSizeOverride,
          allowRoomOverride: true,
        });
        const roomSize = Math.max(1, Number(structure.teamsPerRoom) || 1);

        if (!usesTeamPointStandings(tournament)) {
          return null;
        }

        if (!progression.breakSize) {
          return {
            roomSize,
            entries: [],
            overflowParticipants: [],
            resolvedMethod,
            error: "Set a break size before building an outround draw.",
          };
        }

        const sourceEntries =
          progression.index > 0
            ? getAdvancingEntriesFromPreviousOutround(tournament, progression.profile)
            : getBreakQualifiedEntriesForRound(
                tournament,
                progression.profile,
                progression.targetFieldSize || progression.breakSize,
              );
        const expectedEntries = Math.max(
          roomSize,
          progression.targetFieldSize || progression.breakSize || 0,
        );

        if (!sourceEntries.length) {
          return {
            roomSize,
            entries: [],
            overflowParticipants: [],
            resolvedMethod,
            error:
              progression.index > 0
                ? "Record official results for the previous outround before generating this break round."
                : "Collect standings and complete rosters before generating the break round.",
          };
        }

        if (sourceEntries.length < expectedEntries) {
          return {
            roomSize,
            entries: [],
            overflowParticipants: [],
            resolvedMethod,
            error:
              progression.index > 0
                ? "The previous outround does not yet have enough advancing teams recorded to build this break round."
                : "Not enough complete breaking teams are available to build this outround yet.",
          };
        }

        return {
          roomSize,
          entries: sourceEntries.slice(0, expectedEntries),
          overflowParticipants: [],
          resolvedMethod,
          sourceLabel:
            progression.index > 0
              ? "Previous outround winners"
              : "Break field",
        };
      }

      function getDrawEntryParticipantIds(entry) {
        if (!entry) {
          return [];
        }
        if (entry.type === "speaker") {
          return [String(entry.participant?.id || entry.id || "").trim()].filter(Boolean);
        }
        const roster = Array.isArray(entry.roster) ? entry.roster : [];
        return Array.from(
          new Set(
            roster
              .map((participant) => String(participant?.id || "").trim())
              .filter(Boolean),
          ),
        );
      }

      function getDrawEntryTeamId(entry) {
        if (!entry) {
          return "";
        }
        if (entry.type === "team") {
          return String(entry.team?.id || entry.id || "").trim();
        }
        return String(entry.participant?.teamId || "").trim();
      }

      function formatOverflowDrawMatchup(overflowEntries = [], overflowParticipants = []) {
        const entryLabel = overflowEntries
          .map((entry) => String(entry.shortLabel || entry.label || "").trim())
          .filter(Boolean)
          .join(" • ");
        const speakerLabel = overflowParticipants
          .map((participant) => String(participant?.name || "").trim())
          .filter(Boolean)
          .join(" / ");
        const parts = [];
        if (entryLabel) {
          parts.push("Overflow entries: " + entryLabel);
        }
        if (speakerLabel) {
          parts.push("Unpaired speakers: " + speakerLabel);
        }
        return parts.join(" • ") || "Overflow room";
      }

      function getDrawEntrySpeakerStrength(tournament, entry) {
        if (!entry) {
          return 0;
        }
        if (entry.type === "speaker") {
          return Number(getParticipantComputedSpeakerScore(tournament, entry.participant) || 0);
        }
        const standingScore = Number(entry.standing?.speakerScore || 0);
        if (standingScore) {
          return standingScore;
        }
        const roster = Array.isArray(entry.roster)
          ? entry.roster.map((participant) => normalizeParticipantRecord(participant))
          : [];
        if (!roster.length) {
          return 0;
        }
        return roundScoreValue(
          roster.reduce(
            (sum, participant) =>
              sum + Number(getParticipantComputedSpeakerScore(tournament, participant) || 0),
            0,
          ) / Math.max(1, roster.length),
        );
      }

      function compareDrawEntries(tournament, left, right) {
        const profile = getStandingsProfile(tournament);
        const leftStanding = left.standing || left.participant || {};
        const rightStanding = right.standing || right.participant || {};
        const leftSpeakerScore = getDrawEntrySpeakerStrength(tournament, left);
        const rightSpeakerScore = getDrawEntrySpeakerStrength(tournament, right);

        if (profile.mode === "bp_team") {
          return (
            Number(rightStanding.points || 0) - Number(leftStanding.points || 0) ||
            Number(rightStanding.firsts || 0) - Number(leftStanding.firsts || 0) ||
            Number(rightStanding.seconds || 0) - Number(leftStanding.seconds || 0) ||
            String(left.shortLabel || left.label).localeCompare(
              String(right.shortLabel || right.label),
            )
          );
        }

        if (profile.mode === "win_loss_team") {
          return (
            Number(rightStanding.points || 0) - Number(leftStanding.points || 0) ||
            Number(rightStanding.wins || 0) - Number(leftStanding.wins || 0) ||
            Number(leftStanding.losses || 0) - Number(rightStanding.losses || 0) ||
            String(left.shortLabel || left.label).localeCompare(
              String(right.shortLabel || right.label),
            )
          );
        }

        if (profile.mode === "mixed_team") {
          return (
            Number(rightStanding.points || 0) - Number(leftStanding.points || 0) ||
            Number(rightStanding.wins || 0) - Number(leftStanding.wins || 0) ||
            Number(rightStanding.firsts || 0) - Number(leftStanding.firsts || 0) ||
            Number(rightStanding.seconds || 0) - Number(leftStanding.seconds || 0) ||
            Number(rightStanding.thirds || 0) - Number(leftStanding.thirds || 0) ||
            Number(leftStanding.fourths || 0) - Number(rightStanding.fourths || 0) ||
            Number(leftStanding.losses || 0) - Number(rightStanding.losses || 0) ||
            String(left.shortLabel || left.label).localeCompare(
              String(right.shortLabel || right.label),
            )
          );
        }

        return (
          Number(rightStanding.wins || 0) - Number(leftStanding.wins || 0) ||
          Number(rightStanding.points || 0) - Number(leftStanding.points || 0) ||
          Number(rightSpeakerScore || 0) - Number(leftSpeakerScore || 0) ||
          String(left.shortLabel || left.label).localeCompare(
            String(right.shortLabel || right.label),
          )
        );
      }

      function shuffleEntries(entries) {
        const next = [...entries];
        for (let index = next.length - 1; index > 0; index -= 1) {
          const swapIndex = Math.floor(Math.random() * (index + 1));
          const temp = next[index];
          next[index] = next[swapIndex];
          next[swapIndex] = temp;
        }
        return next;
      }

      function foldEntries(entries) {
        const ordered = [];
        let start = 0;
        let end = entries.length - 1;
        while (start <= end) {
          ordered.push(entries[start]);
          start += 1;
          if (start <= end) {
            ordered.push(entries[end]);
            end -= 1;
          }
        }
        return ordered.filter(Boolean);
      }

      function chunkEntries(entries, size) {
        const chunks = [];
        for (let index = 0; index < entries.length; index += size) {
          chunks.push(entries.slice(index, index + size));
        }
        return chunks;
      }

      function getRoundProfileForRound(tournament, round) {
        return (
          getRoundProfiles(tournament).find((profile) => Number(profile.round) === Number(round)) ||
          createRoundProfile(round, tournament.config)
        );
      }

      function getRoundOptionMarkup(tournament, currentRound = 1) {
        return getRoundProfiles(tournament)
          .map(
            (profile) => {
              const stageLabel = getRoundStageLabel(profile.stage);
              const pairingLabel =
                isOutroundProfile(profile) || getStoredRoundPairingMethod(profile)
                  ? " • " + getDrawMethodDisplayLabel(tournament, profile, "auto")
                  : "";
              return (
              `<option value="${escapeHtml(profile.round)}" ${selected(
                profile.round,
                currentRound,
              )}>${escapeHtml(
                (profile.label || "Round " + profile.round) +
                  " • " +
                  stageLabel +
                  pairingLabel +
                  " • " +
                  getRoundFormatDisplayLabel(tournament, profile, {
                    includeInheritance: false,
                  }),
              )}</option>`
              );
            },
          )
          .join("");
      }

      function getRoundStageOptionMarkup(current = "inround") {
        return [
          { value: "inround", label: "In-Round" },
          { value: "outround", label: "Outround" },
        ]
          .map(
            (item) =>
              `<option value="${escapeHtml(item.value)}" ${selected(
                item.value,
                normalizeRoundStage(current),
              )}>${escapeHtml(item.label)}</option>`,
          )
          .join("");
      }

      function getRoundPairingMethodOptionMarkup(current = "", autoMethod = "power", stage = "inround") {
        const normalized = normalizeOutroundPairingMethod(current);
        const isOutround = normalizeRoundStage(stage) === "outround";
        const options = [
          {
            value: "",
            label: "Automatic (" + getOutroundPairingMethodLabel(autoMethod) + ")",
          },
          { value: "power", label: "Power Paired" },
          ...(isOutround ? [{ value: "fold", label: "Folded" }] : [{ value: "random", label: "Randomised" }]),
        ];

        return options
          .map(
            (item) =>
              `<option value="${escapeHtml(item.value)}" ${selected(
                item.value,
                normalized,
              )}>${escapeHtml(item.label)}</option>`,
          )
          .join("");
      }

      function getDrawMethodOptionMarkup(current = "auto", options = {}) {
        const normalized = normalizeDrawMethodChoice(current, "auto");
        const autoMethod = normalizeOutroundPairingMethod(options.autoMethod) || "power";
        return [
          {
            value: "auto",
            label: "Automatic (" + getOutroundPairingMethodLabel(autoMethod) + ")",
          },
          { value: "random", label: "Randomise" },
          { value: "power", label: "Power Pair" },
          { value: "fold", label: "Folded" },
        ]
          .map(
            (item) =>
              `<option value="${escapeHtml(item.value)}" ${selected(
                item.value,
                normalized,
              )}>${escapeHtml(item.label)}</option>`,
          )
          .join("");
      }

      function normalizeRoomPriority(value, fallback = 3) {
        const number = Number(value);
        if (!Number.isFinite(number)) {
          return fallback;
        }
        return Math.min(5, Math.max(1, Math.round(number)));
      }

      function getRoomPriorityLabel(value) {
        const priority = normalizeRoomPriority(value, 3);
        return (
          {
            5: "Featured",
            4: "High",
            3: "Standard",
            2: "Light",
            1: "Overflow",
          }[priority] || "Standard"
        );
      }

      function getRoomPriorityOptionsMarkup(current = 3) {
        return [5, 4, 3, 2, 1]
          .map(
            (priority) =>
              `<option value="${priority}" ${selected(
                priority,
                normalizeRoomPriority(current, 3),
              )}>${escapeHtml(priority + " • " + getRoomPriorityLabel(priority))}</option>`,
          )
          .join("");
      }

      function roundScoreValue(value, decimals = 1) {
        const factor = 10 ** decimals;
        return Math.round(Number(value || 0) * factor) / factor;
      }

      function formatScoreValue(value, fallback = "0") {
        const number = Number(value);
        if (!Number.isFinite(number)) {
          return fallback;
        }
        const text = String(number);
        if (!/[eE]/.test(text)) {
          return text.replace(/\.0+$/, "").replace(/(\.\d*?)0+$/, "$1");
        }
        return String(roundScoreValue(number, 2))
          .replace(/\.0+$/, "")
          .replace(/(\.\d*?)0+$/, "$1");
      }

      function parseBallotScoreValue(value) {
        const text = String(value ?? "").trim();
        if (!text) {
          return null;
        }
        const number = Number(text);
        return Number.isFinite(number) ? number : null;
      }

      function formatOrdinal(value) {
        const number = Number(value || 0);
        if (!Number.isFinite(number) || number <= 0) {
          return "";
        }
        const mod100 = number % 100;
        if (mod100 >= 11 && mod100 <= 13) {
          return number + "th";
        }
        const suffix =
          {
            1: "st",
            2: "nd",
            3: "rd",
          }[number % 10] || "th";
        return number + suffix;
      }

      function getDrawSideLabelsForFormat(format, count) {
        const normalizedFormat = String(format || "").trim();
        const total = Math.max(0, Number(count) || 0);
        let labels = [];

        if (
          normalizedFormat === "British Parliamentary" ||
          normalizedFormat === "Iron Person British Parliamentary"
        ) {
          labels = ["OG", "OO", "CG", "CO"];
        } else if (normalizedFormat === "World Schools") {
          labels = ["Proposition", "Opposition"];
        } else if (
          normalizedFormat === "American Parliamentary" ||
          normalizedFormat === "JADE Parliamentary"
        ) {
          labels = ["Government", "Opposition"];
        }

        if (labels.length < total) {
          for (let index = labels.length; index < total; index += 1) {
            labels.push("Side " + (index + 1));
          }
        }

        return labels.slice(0, total);
      }

      function getDrawSideLabels(tournament, count, roundOrProfile = null) {
        return getDrawSideLabelsForFormat(getRoundFormat(tournament, roundOrProfile), count);
      }

      function shouldRandomizeDrawRolesForFormat(format) {
        const normalizedFormat = String(format || "").trim();
        return [
          "British Parliamentary",
          "Iron Person British Parliamentary",
          "World Schools",
          "American Parliamentary",
          "JADE Parliamentary",
        ].includes(normalizedFormat);
      }

      function shouldRandomizeDrawRoles(tournament, roundOrProfile = null) {
        return shouldRandomizeDrawRolesForFormat(getRoundFormat(tournament, roundOrProfile));
      }

      function buildDrawSlots(tournament, entries, roundOrProfile = null) {
        const roomEntries = Array.isArray(entries) ? [...entries] : [];
        const baseSideLabels = getDrawSideLabels(tournament, roomEntries.length, roundOrProfile);
        const sideLabels = shouldRandomizeDrawRoles(tournament, roundOrProfile)
          ? shuffleEntries(baseSideLabels)
          : baseSideLabels;
        return roomEntries.map((entry, index) => {
          const roster =
            entry.type === "team"
              ? (entry.roster || []).map((participant) => normalizeParticipantRecord(participant))
              : [normalizeParticipantRecord(entry.participant)];
          const participantIds = roster.map((participant) => participant.id).filter(Boolean);
          const teamId =
            entry.type === "team"
              ? String(entry.team?.id || entry.id || "").trim()
              : String(entry.participant?.teamId || "").trim();
          const teamName =
            entry.type === "team"
              ? String(entry.team?.name || entry.shortLabel || entry.label || "").trim()
              : String(entry.participant?.teamName || "").trim();
          return {
            side: sideLabels[index] || "Side " + (index + 1),
            entryId: String(entry.id || "").trim(),
            label: String(entry.label || "").trim(),
            shortLabel: String(entry.shortLabel || entry.label || "").trim(),
            publicAlias:
              entry.type === "team"
                ? String(entry.team?.publicAlias || entry.publicAlias || "").trim()
                : "",
            type: String(entry.type || "").trim() || "speaker",
            institution: String(entry.institution || "").trim(),
            participantIds,
            teamId,
            teamName,
          };
        });
      }

      function getDrawSlotCheckInKey(slot) {
        return (
          String(slot?.entryId || "").trim() ||
          String(slot?.teamId || "").trim() ||
          String(slot?.label || "").trim()
        );
      }

      function normalizeDrawOfficialResults(value = {}) {
        if (!value || typeof value !== "object") {
          return {};
        }

        return Object.entries(value).reduce((result, [key, record]) => {
          const normalizedKey = String(key || "").trim();
          if (!normalizedKey || !record || typeof record !== "object") {
            return result;
          }

          const rank = normalizeOptionalCount(record.rank, null, 32);
          const outcome = ["win", "loss", "draw"].includes(
            String(record.outcome || "").trim().toLowerCase(),
          )
            ? String(record.outcome || "").trim().toLowerCase()
            : "";

          if (rank || outcome) {
            result[normalizedKey] = {
              rank: rank || null,
              outcome,
            };
          }
          return result;
        }, {});
      }

      function getDrawOfficialResultMode(tournament, roundOrDrawEntry = null) {
        const roundReference =
          roundOrDrawEntry && typeof roundOrDrawEntry === "object"
            ? roundOrDrawEntry.round
            : roundOrDrawEntry;
        const profile = getRoundScoringProfile(tournament, roundReference);
        if (profile.mode === "bp_team") {
          return "bp_rank";
        }
        if (profile.mode === "win_loss_team") {
          return "win_loss";
        }
        return "speaker_only";
      }

      function isGenericDrawSideLabel(value) {
        return /^side\s+\d+$/i.test(String(value || "").trim());
      }

      function getResolvedDrawSlotSideLabel(tournament, drawEntry, slot, slotIndex = -1) {
        const explicitSide = String(slot?.side || "").trim();
        if (explicitSide && !isGenericDrawSideLabel(explicitSide)) {
          return explicitSide;
        }

        const slots = Array.isArray(drawEntry?.slots) ? drawEntry.slots : [];
        const resolvedIndex =
          slotIndex >= 0
            ? slotIndex
            : slots.findIndex(
                (candidate) =>
                  candidate === slot ||
                  getDrawSlotCheckInKey(candidate) === getDrawSlotCheckInKey(slot),
              );
        if (resolvedIndex < 0) {
          return explicitSide;
        }

        const sideLabels = getDrawSideLabels(tournament, slots.length, drawEntry?.round);
        return String(sideLabels[resolvedIndex] || explicitSide || "").trim();
      }

      function getCanonicalDrawSideOrderForFormat(format) {
        const normalizedFormat = String(format || "").trim();
        if (
          normalizedFormat === "British Parliamentary" ||
          normalizedFormat === "Iron Person British Parliamentary"
        ) {
          return [
            ["og", "opening government"],
            ["oo", "opening opposition"],
            ["cg", "closing government"],
            ["co", "closing opposition"],
          ];
        }

        if (normalizedFormat === "World Schools") {
          return [
            ["proposition", "prop"],
            ["opposition", "opp"],
          ];
        }

        if (
          normalizedFormat === "American Parliamentary" ||
          normalizedFormat === "JADE Parliamentary"
        ) {
          return [
            ["government", "gov"],
            ["opposition", "opp"],
          ];
        }

        return [];
      }

      function getDrawSlotDisplaySortValue(tournament, drawEntry, slot, slotIndex = -1) {
        const format = getRoundFormat(
          tournament,
          drawEntry?.round ?? drawEntry ?? null,
        );
        const canonicalOrder = getCanonicalDrawSideOrderForFormat(format);
        const resolvedLabel = normalizeTextKey(
          getResolvedDrawSlotSideLabel(tournament, drawEntry, slot, slotIndex),
        );
        const canonicalIndex = canonicalOrder.findIndex((aliases) => aliases.includes(resolvedLabel));
        if (canonicalIndex >= 0) {
          return canonicalIndex;
        }

        const genericMatch = resolvedLabel.match(/^side\s+(\d+)$/i);
        if (genericMatch) {
          return 100 + Math.max(0, Number.parseInt(genericMatch[1], 10) || 0);
        }

        return 1000 + Math.max(0, slotIndex);
      }

      function getOrderedDrawSlotsForDisplay(tournament, drawEntry) {
        const slots = Array.isArray(drawEntry?.slots) ? drawEntry.slots : [];
        return slots
          .map((slot, index) => ({
            slot,
            index,
            sortValue: getDrawSlotDisplaySortValue(tournament, drawEntry, slot, index),
          }))
          .sort(
            (left, right) =>
              left.sortValue - right.sortValue ||
              left.index - right.index,
          );
      }

      function getDrawOfficialResultSummary(tournament, drawEntry) {
        const slots = getOrderedDrawSlotsForDisplay(tournament, drawEntry).map((entry) => entry.slot);
        const officialResults = normalizeDrawOfficialResults(drawEntry?.officialResults);
        const resultMode = getDrawOfficialResultMode(tournament, drawEntry);
        if (!slots.length || !Object.keys(officialResults).length) {
          return "";
        }

        function getResultPointLabel(result) {
          if (resultMode === "bp_rank") {
            const placementPoints = [3, 2, 1, 0];
            const points = placementPoints[Math.max(0, Number(result?.rank || 0) - 1)] ?? 0;
            return formatScoreValue(points) + " team point" + (points === 1 ? "" : "s");
          }
          if (resultMode === "win_loss") {
            const points = String(result?.outcome || "").trim().toLowerCase() === "win" ? 3 : 1;
            return formatScoreValue(points) + " team point" + (points === 1 ? "" : "s");
          }
          return "";
        }

        if (resultMode === "bp_rank") {
          const rankedSlots = slots
            .map((slot) => ({
              slot,
              result: officialResults[getDrawSlotCheckInKey(slot)] || null,
            }))
            .filter((entry) => entry.result?.rank)
            .sort((left, right) => Number(left.result.rank || 0) - Number(right.result.rank || 0));

          if (rankedSlots.length !== slots.length) {
            return "";
          }

          return rankedSlots
            .map((entry) => {
              const label = getDrawSlotDisplayLabel(tournament, entry.slot, {
                drawEntry,
                slotIndex: slots.findIndex(
                  (slot) => getDrawSlotCheckInKey(slot) === getDrawSlotCheckInKey(entry.slot),
                ),
              });
              return (
                label +
                " " +
                formatOrdinal(entry.result.rank) +
                " (" +
                getResultPointLabel(entry.result) +
                ")"
              );
            })
            .join(" • ");
        }

        if (resultMode === "win_loss") {
          const outcomeSlots = slots
            .map((slot) => ({
              slot,
              result: officialResults[getDrawSlotCheckInKey(slot)] || null,
            }))
            .filter((entry) => entry.result?.outcome);

          if (!outcomeSlots.length) {
            return "";
          }

          return outcomeSlots
            .map((entry) => {
              const label = getDrawSlotDisplayLabel(tournament, entry.slot, {
                drawEntry,
                slotIndex: slots.findIndex(
                  (slot) => getDrawSlotCheckInKey(slot) === getDrawSlotCheckInKey(entry.slot),
                ),
              });
              return (
                label +
                " " +
                toTitleLabel(entry.result.outcome) +
                " (" +
                getResultPointLabel(entry.result) +
                ")"
              );
            })
            .join(" • ");
        }

        return "";
      }

      function getJudgeRoomResultOptionsMarkup(tournament, drawEntry, slot) {
        const slotKey = getDrawSlotCheckInKey(slot);
        const currentResult = normalizeDrawOfficialResults(drawEntry?.officialResults)?.[slotKey] || {};
        const resultMode = getDrawOfficialResultMode(tournament, drawEntry);
        if (resultMode === "bp_rank") {
          const total = Math.max(0, Array.isArray(drawEntry?.slots) ? drawEntry.slots.length : 0);
          return [
            `<option value="">Select placement</option>`,
            ...Array.from({ length: total }, (_, index) => index + 1).map(
              (rank) =>
                `<option value="${escapeHtml(rank)}" ${selected(
                  String(rank),
                  String(currentResult.rank || ""),
                )}>${escapeHtml(formatOrdinal(rank))}</option>`,
            ),
          ].join("");
        }

        if (resultMode === "win_loss") {
          return [
            `<option value="">Select result</option>`,
            `<option value="win" ${selected("win", currentResult.outcome || "")}>Win</option>`,
            `<option value="loss" ${selected("loss", currentResult.outcome || "")}>Loss</option>`,
          ].join("");
        }

        return "";
      }

      function getJudgeRoomResultGuideText(tournament, drawEntry) {
        const slotCount = Math.max(0, Array.isArray(drawEntry?.slots) ? drawEntry.slots.length : 0);
        const resultMode = getDrawOfficialResultMode(tournament, drawEntry);
        if (resultMode === "bp_rank") {
          return "Assign a unique placement to each team in the room. These placements drive the team points table automatically.";
        }
        if (resultMode === "win_loss") {
          return slotCount === 2
            ? "Mark the winning side and the losing side. Team points update automatically from this official result."
            : "Mark each side as a win or loss. Team points update automatically from this official result.";
        }
        return "";
      }

      function normalizeDrawEntryCheckIns(value = {}) {
        if (Array.isArray(value)) {
          return value.reduce((result, item) => {
            const key = String(item || "").trim();
            if (key) {
              result[key] = true;
            }
            return result;
          }, {});
        }

        return Object.entries(value || {}).reduce((result, [key, checkedIn]) => {
          const normalizedKey = String(key || "").trim();
          if (normalizedKey) {
            result[normalizedKey] = Boolean(checkedIn);
          }
          return result;
        }, {});
      }

      function getDrawSlotDisplayLabel(tournament, slot, options = {}) {
        if (!slot) {
          return "";
        }

        const participants = (tournament.participants || []).map((participant) =>
          normalizeParticipantRecord(participant),
        );
        const team = slot.teamId
          ? getTournamentTeams(tournament).find((entry) => entry.id === slot.teamId) || null
          : findTournamentTeamByName(
              tournament,
              slot.teamName || slot.shortLabel || slot.label || "",
            );

        let label = "";
        if (team) {
          label = getTeamNameForDisplay(tournament, team, options);
        } else if (slot.type === "speaker") {
          const participant =
            participants.find((entry) => entry.id === slot.entryId) ||
            participants.find(
              (entry) =>
                normalizeTextKey(entry.name) === normalizeTextKey(slot.shortLabel || slot.label),
            ) ||
            null;
          label = participant
            ? participant.institution
              ? participant.institution + " " + participant.name
              : participant.name
            : String(slot.label || slot.shortLabel || "").trim();
        } else {
          label = String(slot.label || slot.shortLabel || "").trim();
        }

        const sideLabel = getResolvedDrawSlotSideLabel(
          tournament,
          options.drawEntry || null,
          slot,
          options.slotIndex ?? -1,
        );
        return sideLabel ? sideLabel + ": " + label : label;
      }

      function getDrawMatchupForDisplay(tournament, drawEntry, options = {}) {
        if (Array.isArray(drawEntry?.slots) && drawEntry.slots.length) {
          const labels = getOrderedDrawSlotsForDisplay(tournament, drawEntry)
            .map(({ slot, index }) =>
              getDrawSlotDisplayLabel(tournament, slot, {
                ...options,
                drawEntry,
                slotIndex: index,
              }),
            )
            .filter(Boolean);
          if (labels.length <= 2) {
            return labels.join(" vs ");
          }
          return labels.join(" • ");
        }

        return String(drawEntry?.matchup || "").trim();
      }

      function getDrawSlotLabels(tournament, slots, roundOrProfile = null) {
        const normalizedSlots = Array.isArray(slots) ? slots : [];
        const slotRecords = tournament
          ? normalizedSlots
              .map((slot, index) => ({
                slot,
                index,
                sortValue: getDrawSlotDisplaySortValue(
                  tournament,
                  { round: roundOrProfile, slots: normalizedSlots },
                  slot,
                  index,
                ),
              }))
              .sort((left, right) => left.sortValue - right.sortValue || left.index - right.index)
              .map((entry) => entry.slot)
          : normalizedSlots;

        return slotRecords
          .map((slot) =>
            slot.side
              ? String(slot.side || "").trim() + ": " + String(slot.label || "").trim()
              : String(slot.label || "").trim(),
          )
          .filter(Boolean);
      }

      function inferDrawEntriesFromMatchup(tournament, matchup) {
        const normalizedMatchup = String(matchup || "").trim().toLowerCase();
        if (!normalizedMatchup) {
          return [];
        }

        return getDrawEntriesForTournament(tournament)
          .map((entry) => {
            const searchTerms = [
              entry.label,
              entry.shortLabel,
              entry.team?.name,
              entry.team && entry.team.institution
                ? entry.team.institution + " " + entry.team.name
                : "",
            ]
              .map((value) => String(value || "").trim().toLowerCase())
              .filter(Boolean);
            const positions = searchTerms
              .map((term) => normalizedMatchup.indexOf(term))
              .filter((position) => position >= 0);
            if (!positions.length) {
              return null;
            }
            return {
              entry,
              index: Math.min(...positions),
            };
          })
          .filter(Boolean)
          .sort((left, right) => Number(left.index) - Number(right.index))
          .map((item) => item.entry);
      }

      function formatDrawMatchup(tournament, target, roundOrProfile = null) {
        if (Array.isArray(target) && target.length && target[0]?.side) {
          const slotLabels = getDrawSlotLabels(tournament, target, roundOrProfile);
          return slotLabels.length <= 2 ? slotLabels.join(" vs ") : slotLabels.join(" • ");
        }

        if (Array.isArray(target)) {
          const labels = target.map((entry) => entry.label).filter(Boolean);
          if (labels.length <= 2) {
            return labels.join(" vs ");
          }
          return labels.join(" • ");
        }

        if (target && Array.isArray(target.slots) && target.slots.length) {
          const slotLabels = getDrawSlotLabels(tournament, target.slots, target.round);
          return slotLabels.length <= 2 ? slotLabels.join(" vs ") : slotLabels.join(" • ");
        }

        return String(target?.matchup || "").trim();
      }

      function createDrawRecord(tournament, payload = {}) {
        const inferredEntries =
          payload.disableMatchupInference
            ? []
            : Array.isArray(payload.entries) && payload.entries.length
            ? payload.entries
            : inferDrawEntriesFromMatchup(tournament, payload.matchup || "");
        const roundProfile = getRoundProfileForRound(
          tournament,
          Number(payload.round || 1),
        );
        const slots = Array.isArray(payload.slots) && payload.slots.length
          ? payload.slots
          : inferredEntries.length
            ? buildDrawSlots(tournament, inferredEntries, roundProfile)
            : [];
        const participantIds = Array.from(
          new Set(
            (Array.isArray(payload.participantIds) ? payload.participantIds : [])
              .concat(
                slots.flatMap((slot) =>
                  Array.isArray(slot.participantIds) ? slot.participantIds : [],
                ),
              )
              .map((id) => String(id || "").trim())
              .filter(Boolean),
          ),
        );
        const teamIds = Array.from(
          new Set(
            (Array.isArray(payload.teamIds) ? payload.teamIds : [])
              .concat(slots.map((slot) => String(slot.teamId || "").trim()))
              .filter(Boolean),
          ),
        );
        const entryIds = Array.from(
          new Set(
            (Array.isArray(payload.entryIds) ? payload.entryIds : [])
              .concat(slots.map((slot) => String(slot.entryId || "").trim()))
              .filter(Boolean),
          ),
        );
        const createdAt = String(payload.createdAt || timestamp()).trim();
        const createdAtKey = normalizeTimestampKey(payload.createdAtKey, createdAt) || Date.now();
        const status = String(payload.status || "Draft").trim();
        const publishedAt = String(
          payload.publishedAt || (status.toLowerCase() === "published" ? createdAt : ""),
        ).trim();
        const publishedAtKey =
          normalizeTimestampKey(payload.publishedAtKey, publishedAt) ||
          (status.toLowerCase() === "published" ? createdAtKey : 0);

        return {
          id: payload.id || createId("draw"),
          round: Number(payload.round || 1),
          room: String(payload.room || "").trim(),
          matchup: String(payload.matchup || formatDrawMatchup(tournament, slots, roundProfile)).trim(),
          status,
          priority: normalizeRoomPriority(payload.priority, 3),
          createdAt,
          createdAtKey,
          publishedAt,
          publishedAtKey,
          ballotCheckedIn: Boolean(payload.ballotCheckedIn),
          entryCheckIns: normalizeDrawEntryCheckIns(payload.entryCheckIns),
          officialResults: normalizeDrawOfficialResults(payload.officialResults),
          slots,
          entryIds,
          teamIds,
          participantIds:
            participantIds.length ||
            !String(payload.matchup || "").trim()
              ? participantIds
              : inferParticipantIdsFromMatchup(tournament, payload.matchup || ""),
        };
      }

      function getFeedbackSpeakerScore(entry) {
        if (entry?.speakerScore !== undefined && entry?.speakerScore !== null) {
          return parseBallotScoreValue(entry.speakerScore);
        }

        const scores = entry?.scores || {};
        const speakerKey = Object.keys(scores).find((key) =>
          ["speaker score", "speaker points", "speaks"].includes(
            String(key || "").trim().toLowerCase(),
          ),
        );
        if (speakerKey) {
          return parseBallotScoreValue(scores[speakerKey]);
        }

        return null;
      }

      function getFeedbackTotalScore(entry) {
        const speakerScore = getFeedbackSpeakerScore(entry);
        const scoreTotal = Object.entries(entry?.scores || {}).reduce((sum, [key, value]) => {
          const normalizedKey = String(key || "").trim().toLowerCase();
          if (["speaker score", "speaker points", "speaks"].includes(normalizedKey)) {
            return sum;
          }
          return sum + Number(value || 0);
        }, 0);
        return scoreTotal + Number(speakerScore || 0);
      }

      function getParticipantBallotGroups(tournamentOrParticipant, maybeParticipant) {
        const tournament = maybeParticipant ? tournamentOrParticipant : null;
        const participant = maybeParticipant || tournamentOrParticipant;
        const groups = new Map();
        const entries = tournament
          ? getOfficialParticipantFeedbackEntries(tournament, participant)
          : participant?.feedback || [];
        entries.forEach((entry, index) => {
          const speakerScore = getFeedbackSpeakerScore(entry);
          if (speakerScore === null) {
            return;
          }
          const groupKey =
            String(entry?.drawId || "").trim() ||
            String(entry?.allocationId || "").trim() ||
            "legacy-" + index;
          const timestampKey =
            normalizeTimestampKey(entry?.createdAtKey, entry?.createdAt) || index + 1;
          const current = groups.get(groupKey);
          if (!current || Number(timestampKey) >= Number(current.timestampKey || 0)) {
            groups.set(groupKey, {
              score: Number(speakerScore || 0),
              timestampKey,
            });
          }
        });
        return groups;
      }

      function getParticipantComputedSpeakerScore(tournamentOrParticipant, maybeParticipant) {
        const tournament = maybeParticipant ? tournamentOrParticipant : null;
        const participant = maybeParticipant || tournamentOrParticipant;
        const normalized = normalizeParticipantRecord(participant);
        const ballotGroups = tournament
          ? getParticipantBallotGroups(tournament, normalized)
          : getParticipantBallotGroups(normalized);
        if (!ballotGroups.size) {
          return Number(normalized.speakerScore || 0);
        }

        let total = 0;
        ballotGroups.forEach((entry) => {
          total += Number(entry?.score || 0);
        });
        return total;
      }

      function getParticipantSpeakerScoreBreakdown(tournament, participant) {
        const normalized = normalizeParticipantRecord(participant);
        const grouped = new Map();

        getOfficialParticipantFeedbackEntries(tournament, normalized).forEach((entry, index) => {
          const speakerScore = getFeedbackSpeakerScore(entry);
          if (speakerScore === null) {
            return;
          }

          const groupKey =
            String(entry?.drawId || "").trim() ||
            String(entry?.allocationId || "").trim() ||
            "legacy-" + index;
          const timestampKey =
            normalizeTimestampKey(entry?.createdAtKey, entry?.createdAt) || index + 1;
          const drawEntry = getDrawEntryById(tournament, entry?.drawId);
          const allocation = getFeedbackAllocation(tournament, entry);
          const round = normalizeRoundCount(
            drawEntry?.round || allocation?.round || entry?.round || index + 1,
            index + 1,
          );
          const room = String(drawEntry?.room || allocation?.room || "").trim();
          const current = grouped.get(groupKey);

          if (!current || Number(timestampKey) >= Number(current.timestampKey || 0)) {
            grouped.set(groupKey, {
              key: groupKey,
              drawId: String(entry?.drawId || "").trim(),
              round,
              room,
              score: Number(speakerScore || 0),
              timestampKey,
            });
          }
        });

        return Array.from(grouped.values()).sort(
          (left, right) =>
            Number(left.round || 0) - Number(right.round || 0) ||
            String(left.room || "").localeCompare(String(right.room || "")) ||
            Number(left.timestampKey || 0) - Number(right.timestampKey || 0),
        );
      }

      function hasSpeakerRankingData(participant) {
        return (
          (Array.isArray(participant?.scoreBreakdown) && participant.scoreBreakdown.length > 0) ||
          Number(participant?.speakerScore || 0) > 0
        );
      }

      function getSpeakerScoreBreakdownText(breakdown = [], options = {}) {
        const records = Array.isArray(breakdown) ? breakdown : [];
        const includeRoom = Boolean(options.includeRoom);
        if (!records.length) {
          return "Awaiting scores";
        }
        return records
          .map(
            (entry) =>
              "R" +
              entry.round +
              " " +
              formatScoreValue(entry.score) +
              (includeRoom && entry.room ? " (" + entry.room + ")" : ""),
          )
          .join(" • ");
      }

      function renderSpeakerScoreBreakdownMarkup(participant, options = {}) {
        const record = participant || {};
        if (!hasSpeakerRankingData(record)) {
          return `<div class="speaker-score-cell"><span class="fine-print">Awaiting scores</span></div>`;
        }

        const breakdown = Array.isArray(record.scoreBreakdown) ? record.scoreBreakdown : [];
        const roundCount = breakdown.length;
        return `
          <div class="speaker-score-cell">
            <span class="speaker-score-trail">${escapeHtml(
              getSpeakerScoreBreakdownText(breakdown, options),
            )}</span>
            <span class="fine-print">${escapeHtml(
              roundCount === 1 ? "1 scored round" : roundCount + " scored rounds",
            )}</span>
          </div>
        `;
      }

      function renderSpeakerScoreSummaryMarkup(participant) {
        const record = participant || {};
        if (!hasSpeakerRankingData(record)) {
          return `<span class="muted">Awaiting scores</span>`;
        }

        return `
          <div class="speaker-score-summary">
            <span>${escapeHtml(
              "Cumulative " + formatScoreValue(record.cumulativeSpeakerScore),
            )}</span>
            <span>${escapeHtml(
              "Average " + formatScoreValue(record.averageSpeakerScore),
            )}</span>
          </div>
        `;
      }

      function getComputedSpeakerParticipants(tournament) {
        return (tournament.participants || []).map((participant) => {
          const normalized = normalizeParticipantRecord(participant);
          const scoreBreakdown = getParticipantSpeakerScoreBreakdown(tournament, normalized);
          const cumulativeSpeakerScore = getParticipantComputedSpeakerScore(tournament, normalized);
          const averageSpeakerScore = scoreBreakdown.length
            ? roundScoreValue(cumulativeSpeakerScore / scoreBreakdown.length, 2)
            : Number(normalized.speakerScore || 0);
          return {
            ...normalized,
            speakerScore: cumulativeSpeakerScore,
            cumulativeSpeakerScore,
            averageSpeakerScore,
            scoreBreakdown,
          };
        });
      }

      function getParticipantAverageSpeakerScoreForDraw(tournament, participantId, drawId) {
        const participant = getParticipantById(tournament, participantId);
        if (!participant) {
          return null;
        }

        const latestEntry = getOfficialParticipantFeedbackEntries(tournament, participant)
          .filter((entry) => String(entry.drawId || "").trim() === String(drawId || "").trim())
          .map((entry, index) => ({
            entry,
            timestampKey:
              normalizeTimestampKey(entry?.createdAtKey, entry?.createdAt) || index + 1,
          }))
          .filter(({ entry }) => getFeedbackSpeakerScore(entry) !== null)
          .sort((left, right) => Number(left.timestampKey) - Number(right.timestampKey))
          .at(-1);

        if (!latestEntry) {
          return null;
        }

        return getFeedbackSpeakerScore(latestEntry.entry);
      }

      function getComputedStandings(tournament) {
        const profile = getStandingsProfile(tournament);
        const fallback = sortStandingsForTournament(tournament.standings || [], tournament);

        if (
          profile.mode !== "bp_team" &&
          profile.mode !== "win_loss_team" &&
          profile.mode !== "mixed_team"
        ) {
          const computedSpeakers = getComputedSpeakerParticipants(tournament);
          const hasBallots = computedSpeakers.some(
            (participant) =>
              getParticipantBallotGroups(tournament, participant).size > 0 &&
              Number(participant.speakerScore || 0) > 0,
          );

          if (!hasBallots) {
            return fallback;
          }

          return sortStandingsForTournament(
            computedSpeakers.map((participant) => ({
              id: "computed-standing-" + participant.id,
              name: participant.name,
              wins: normalizeNonNegative(participant.wins, 0),
              losses: normalizeNonNegative(participant.losses, 0),
              points: Number(participant.speakerScore || 0),
            })),
            tournament,
          );
        }

        const teamMap = new Map();
        getTournamentTeams(tournament).forEach((team) => {
          const key = String(team.id || normalizeTextKey(team.name)).trim();
          teamMap.set(key, {
            id: "computed-standing-" + key,
            name: team.name,
            wins: 0,
            losses: 0,
            points: 0,
            speaks: 0,
            firsts: 0,
            seconds: 0,
            thirds: 0,
            fourths: 0,
            rank: 0,
          });
        });

        let hasAutomaticResults = false;

        (tournament.draw || []).forEach((drawEntry) => {
          if (!Array.isArray(drawEntry.slots) || !drawEntry.slots.length) {
            return;
          }
          const roundProfile = getRoundScoringProfile(tournament, drawEntry.round);
          const officialResults = normalizeDrawOfficialResults(drawEntry.officialResults);

          const slotOutcomeRecords = drawEntry.slots.map((slot) => {
            const key =
              String(slot.teamId || "").trim() ||
              String(slot.entryId || "").trim() ||
              normalizeTextKey(slot.teamName || slot.shortLabel || slot.label);
            const teamName = String(slot.teamName || slot.shortLabel || slot.label || "").trim();
            if (!teamMap.has(key)) {
              teamMap.set(key, {
                id: "computed-standing-" + key,
                name: teamName,
                wins: 0,
                losses: 0,
                points: 0,
                speaks: 0,
                firsts: 0,
                seconds: 0,
                thirds: 0,
                fourths: 0,
                rank: 0,
              });
            }

            return {
              key,
              name: teamName,
              slotKey: getDrawSlotCheckInKey(slot),
              slot,
              result: officialResults[getDrawSlotCheckInKey(slot)] || null,
            };
          });

          const rankedSlots = drawEntry.slots
            .map((slot) => {
              const participantIds = Array.isArray(slot.participantIds) ? slot.participantIds : [];
              const participantScores = participantIds
                .map((participantId) =>
                  getParticipantAverageSpeakerScoreForDraw(
                    tournament,
                    participantId,
                    drawEntry.id,
                  ),
                )
                .filter((value) => value !== null);
              if (!participantScores.length) {
                return null;
              }

              const key =
                String(slot.teamId || "").trim() ||
                String(slot.entryId || "").trim() ||
                normalizeTextKey(slot.teamName || slot.shortLabel || slot.label);
              const teamName = String(slot.teamName || slot.shortLabel || slot.label || "").trim();
              if (!teamMap.has(key)) {
                teamMap.set(key, {
                  id: "computed-standing-" + key,
                  name: teamName,
                  wins: 0,
                  losses: 0,
                  points: 0,
                  speaks: 0,
                  firsts: 0,
                  seconds: 0,
                  thirds: 0,
                  fourths: 0,
                  rank: 0,
                });
              }

              return {
                key,
                name: teamName,
                averageScore: participantScores.reduce(
                  (sum, value) => sum + Number(value || 0),
                  0,
                ),
              };
            })
            .filter(Boolean)
            .sort(
              (left, right) =>
                Number(right.averageScore || 0) - Number(left.averageScore || 0) ||
                String(left.name).localeCompare(String(right.name)),
            );

          if (!rankedSlots.length || rankedSlots.length !== drawEntry.slots.length) {
            if (
              profile.mode !== "bp_team" &&
              profile.mode !== "win_loss_team"
            ) {
              return;
            }
          }

          if (roundProfile.mode === "bp_team") {
            const rankedOfficialSlots = slotOutcomeRecords
              .filter((entry) => entry.result?.rank)
              .sort((left, right) => Number(left.result.rank || 0) - Number(right.result.rank || 0));
            if (rankedOfficialSlots.length === drawEntry.slots.length) {
              hasAutomaticResults = true;
              const placementKeys = ["firsts", "seconds", "thirds", "fourths"];
              const placementPoints = [3, 2, 1, 0];
              rankedOfficialSlots.forEach((slot, index) => {
                const record = teamMap.get(slot.key);
                if (!record) return;
                const rankedSlot = rankedSlots.find((entry) => entry.key === slot.key);
                record.speaks += Number(rankedSlot?.averageScore || 0);
                record[placementKeys[index] || "fourths"] += 1;
                record.points += placementPoints[index] ?? 0;
              });
              return;
            }

            if (!rankedSlots.length || rankedSlots.length !== drawEntry.slots.length) {
              return;
            }

            hasAutomaticResults = true;
            const placementKeys = ["firsts", "seconds", "thirds", "fourths"];
            const placementPoints = [3, 2, 1, 0];
            rankedSlots.forEach((slot, index) => {
              const record = teamMap.get(slot.key);
              if (!record) return;
              record.speaks += Number(slot.averageScore || 0);
              record[placementKeys[index] || "fourths"] += 1;
              record.points += placementPoints[index] ?? 0;
            });
            return;
          }

          if (roundProfile.mode !== "win_loss_team" || rankedSlots.length < 2) {
            const completeOutcomes = slotOutcomeRecords.filter((entry) => entry.result?.outcome);
            if (completeOutcomes.length !== drawEntry.slots.length) {
              return;
            }
          }

          const officialOutcomeSlots = slotOutcomeRecords.filter((entry) => entry.result?.outcome);
          if (officialOutcomeSlots.length === drawEntry.slots.length) {
            hasAutomaticResults = true;
            officialOutcomeSlots.forEach((slot) => {
              const record = teamMap.get(slot.key);
              if (!record) return;
              const rankedSlot = rankedSlots.find((entry) => entry.key === slot.key);
              record.speaks += Number(rankedSlot?.averageScore || 0);
              if (slot.result.outcome === "win") {
                record.wins += 1;
                record.points += 3;
              } else if (slot.result.outcome === "loss") {
                record.losses += 1;
                record.points += 1;
              }
            });
            return;
          }

          if (rankedSlots.length < 2) {
            return;
          }

          hasAutomaticResults = true;
          const first = rankedSlots[0];
          const second = rankedSlots[1];
          const firstRecord = teamMap.get(first.key);
          const secondRecord = teamMap.get(second.key);
          if (!firstRecord || !secondRecord) {
            return;
          }
          firstRecord.speaks += Number(first.averageScore || 0);
          secondRecord.speaks += Number(second.averageScore || 0);

          if (Number(first.averageScore || 0) === Number(second.averageScore || 0)) {
            firstRecord.points += 2;
            secondRecord.points += 2;
            return;
          }

          firstRecord.wins += 1;
          firstRecord.points += 3;
          secondRecord.losses += 1;
          secondRecord.points += 1;
        });

        if (!hasAutomaticResults) {
          return fallback;
        }

        return sortStandingsForTournament(Array.from(teamMap.values()), tournament);
      }

      function getSpeakerStandings(tournament) {
        return applyCompetitionRanks(
          getComputedSpeakerParticipants(tournament)
            .filter((participant) => hasSpeakerRankingData(participant))
            .sort(
              (left, right) =>
                Number(right.speakerScore) - Number(left.speakerScore) ||
                String(left.name).localeCompare(String(right.name)),
            ),
          areSpeakerStandingsTied,
          "speakerRank",
        );
      }

      function getSpeakerStandingForParticipant(tournament, participant) {
        return (
          getSpeakerStandings(tournament).find((entry) => entry.id === participant.id) || null
        );
      }

      function renderSpeakerStandingsTable(tournament) {
        const speakerStandings = getSpeakerStandings(tournament);
        if (!speakerStandings.length) {
          return `<div class="empty-state">Speaker rankings will appear once judges submit ballots.</div>`;
        }

        return `
          <div class="table-wrap">
            <table>
              <thead>
                <tr>
                  <th>Rank</th>
                  <th>Speaker</th>
                  <th>Team</th>
                  <th>Match Scores</th>
                  <th>Cumulative</th>
                  <th>Average</th>
                  <th>Profile</th>
                </tr>
              </thead>
              <tbody>
                ${speakerStandings
                  .map(
                    (participant) => `
                      <tr>
                        <td>${escapeHtml(participant.speakerRank)}</td>
                        <td>${escapeHtml(participant.name)}</td>
                        <td>${escapeHtml(
                          participant.teamName
                            ? participant.teamName +
                                (participant.institution
                                  ? " • " + participant.institution
                                  : "")
                            : participant.institution || "Individual",
                        )}</td>
                        <td>${renderSpeakerScoreBreakdownMarkup(participant)}</td>
                        <td>${escapeHtml(formatScoreValue(participant.cumulativeSpeakerScore))}</td>
                        <td>${escapeHtml(formatScoreValue(participant.averageSpeakerScore))}</td>
                        <td>${renderParticipantProfileButton(participant, "Open", true)}</td>
                      </tr>
                    `,
                  )
                  .join("")}
              </tbody>
            </table>
          </div>
          <p class="table-caption">Match scores list the scored rounds for each speaker. Rankings use cumulative score, with the average shown alongside it.</p>
        `;
      }

      function renderParticipantScoreFields() {
        return ``;
      }

      function buildStandingMetricsFromForm(tournament, formData) {
        const profile = getScoringProfile(tournament);
        if (profile.mode === "bp_team") {
          const record = {
            firsts: numberFromForm(formData, "firsts", 0),
            seconds: numberFromForm(formData, "seconds", 0),
            thirds: numberFromForm(formData, "thirds", 0),
            fourths: numberFromForm(formData, "fourths", 0),
          };
          return {
            ...record,
            wins: record.firsts,
            losses: record.fourths,
            points: calculateBpTeamPoints(record),
          };
        }

        if (profile.mode === "win_loss_team") {
          const record = {
            wins: numberFromForm(formData, "wins", 0),
            losses: numberFromForm(formData, "losses", 0),
          };
          return {
            ...record,
            points: calculateWinLossPoints(record),
          };
        }

        return {
          wins: numberFromForm(formData, "wins", 0),
          losses: 0,
          points: numberFromForm(formData, "points", 0),
          firsts: 0,
          seconds: 0,
          thirds: 0,
          fourths: 0,
        };
      }

      function getAssignmentRoleOptions(currentValue = "") {
        return getTournamentPermissionRoleConfigs()
          .map(
            (item) =>
              `<option value="${item.key}" ${selected(
                item.key,
                currentValue,
              )}>${escapeHtml(item.assignmentLabel)}</option>`,
          )
          .join("");
      }

      function addAudit(tournament, message) {
        return {
          ...tournament,
          auditLog: [
            {
              id: createId("audit"),
              actor: normalizeEmail(session.userEmail) || "system",
              at: timestamp(),
              message,
            },
            ...(tournament.auditLog || []),
          ].slice(0, 50),
        };
      }

      function getCurrentThemePreset() {
        const presetKey = String(getCurrentUser()?.themePreset || "jade_classic").trim();
        return THEME_PRESETS[presetKey] ? presetKey : "jade_classic";
      }

      function applyBranding() {
        if (!state) return;
        const themeKey = getCurrentThemePreset();
        const theme = THEME_PRESETS[themeKey] || THEME_PRESETS.jade_classic;
        const root = document.documentElement;
        Object.entries(theme.vars || {}).forEach(([key, value]) => {
          root.style.setProperty(key, value);
        });

        const brandingAccent =
          state.appSettings.branding.accent || DEFAULT_SETTINGS.branding.accent;
        const brandingAccentDeep =
          state.appSettings.branding.accentDeep || DEFAULT_SETTINGS.branding.accentDeep;
        const effectiveAccent =
          themeKey === "jade_classic"
            ? brandingAccent
            : theme.vars?.["--accent"] || brandingAccent;
        const effectiveAccentDeep =
          themeKey === "jade_classic"
            ? brandingAccentDeep
            : theme.vars?.["--accent-deep"] || brandingAccentDeep;
        const effectiveGold = theme.vars?.["--gold"] || "#e1bf43";

        root.style.setProperty("--accent", effectiveAccent);
        root.style.setProperty("--accent-deep", effectiveAccentDeep);
        root.style.setProperty("--accent-soft", effectiveAccent + "22");
        root.style.setProperty("--accent-mist", effectiveAccent + "14");
        root.style.setProperty("--jade", effectiveAccent);
        root.style.setProperty("--jade-soft", effectiveAccent + "22");
        root.style.setProperty("--gold-soft", effectiveGold + "22");
        if (document.body) {
          document.body.dataset.theme = themeKey;
        }
        document.title = state.appSettings.branding.appName || DEFAULT_SETTINGS.branding.appName;
      }

      function applyAccessibilityPreferences() {
        const root = document.documentElement;
        const reduceMotion =
          Boolean(state?.appSettings?.accessibility?.reduceMotion) || Boolean(REDUCED_MOTION);
        root.dataset.reducedMotion = reduceMotion ? "true" : "false";
      }

      function saveSession() {
        localStorage.setItem(
          SESSION_STORAGE_KEY,
          JSON.stringify(normalizeSessionRecord(session)),
        );
      }

      function normalizeAuthPrefs(record = {}) {
        return {
          rememberedEmail: normalizeEmail(record.rememberedEmail),
          savePasswordOnDevice: record.savePasswordOnDevice !== false,
        };
      }

      function saveAuthPrefs() {
        localStorage.setItem(
          AUTH_PREFS_STORAGE_KEY,
          JSON.stringify(normalizeAuthPrefs(authPrefs)),
        );
      }

      function loadAuthPrefs() {
        const saved = localStorage.getItem(AUTH_PREFS_STORAGE_KEY);
        if (!saved) {
          return normalizeAuthPrefs({});
        }

        try {
          return normalizeAuthPrefs(JSON.parse(saved));
        } catch (error) {
          localStorage.removeItem(AUTH_PREFS_STORAGE_KEY);
          return normalizeAuthPrefs({});
        }
      }

      function updateAuthPrefsAfterCredentialChoice(email, shouldSavePassword) {
        authPrefs = normalizeAuthPrefs({
          rememberedEmail: shouldSavePassword ? email : "",
          savePasswordOnDevice: shouldSavePassword,
        });
        saveAuthPrefs();
      }

      function clearStoredSession() {
        localStorage.removeItem(SESSION_STORAGE_KEY);
      }

      function loadStoredSession() {
        const saved = localStorage.getItem(SESSION_STORAGE_KEY);
        if (!saved) {
          return getEmptySession();
        }

        try {
          return normalizeSessionRecord(JSON.parse(saved));
        } catch (error) {
          clearStoredSession();
          return getEmptySession();
        }
      }

      function normalizePendingCloudSyncRecord(record = {}) {
        const id = String(record.id || "").trim();
        const userEmail = normalizeEmail(record.userEmail);
        const createdAt = String(record.createdAt || "").trim();
        const incomingState = record.state;
        if (!id || !incomingState || typeof incomingState !== "object" || Array.isArray(incomingState)) {
          return null;
        }

        const snapshot = clone(incomingState);
        assertWorkspaceContract(snapshot, "pending cloud sync");

        return {
          id,
          userEmail,
          createdAt,
          state: snapshot,
        };
      }

      function loadPendingCloudSyncRecord() {
        const saved = localStorage.getItem(PENDING_CLOUD_SYNC_STORAGE_KEY);
        if (!saved) {
          return null;
        }

        try {
          const parsed = JSON.parse(saved);
          const normalized = normalizePendingCloudSyncRecord(parsed);
          if (!normalized) {
            localStorage.removeItem(PENDING_CLOUD_SYNC_STORAGE_KEY);
            return null;
          }
          return normalized;
        } catch (error) {
          localStorage.removeItem(PENDING_CLOUD_SYNC_STORAGE_KEY);
          return null;
        }
      }

      function savePendingCloudSyncRecord(snapshot, syncId) {
        if (!snapshot || !syncId) {
          return;
        }

        const normalizedSnapshot = clone(snapshot);
        normalizedSnapshot.workspaceContractVersion = WORKSPACE_CONTRACT_VERSION;
        assertWorkspaceContract(normalizedSnapshot, "pending cloud sync");

        pendingCloudSync = {
          id: String(syncId).trim(),
          userEmail: normalizeEmail(session.userEmail),
          createdAt: new Date().toISOString(),
          state: normalizedSnapshot,
        };
        localStorage.setItem(
          PENDING_CLOUD_SYNC_STORAGE_KEY,
          JSON.stringify(pendingCloudSync),
        );
      }

      function clearPendingCloudSyncRecord(syncId = "") {
        const normalizedSyncId = String(syncId || "").trim();
        if (normalizedSyncId && pendingCloudSync?.id && pendingCloudSync.id !== normalizedSyncId) {
          return;
        }

        pendingCloudSync = null;
        localStorage.removeItem(PENDING_CLOUD_SYNC_STORAGE_KEY);
      }

      function hasPendingCloudSyncForCurrentSession() {
        if (!pendingCloudSync?.state) {
          return false;
        }

        const currentEmail = normalizeEmail(session.userEmail);
        return !pendingCloudSync.userEmail || pendingCloudSync.userEmail === currentEmail;
      }

      async function refreshSharedStateSafely(options = {}) {
        if (hasPendingCloudSyncForCurrentSession()) {
          await flushCloudPersistQueue();
          if (hasPendingCloudSyncForCurrentSession()) {
            return false;
          }
        }

        return refreshStateFromBackend(options);
      }

      async function probeCloudBackend(force = false) {
        if (cloudRuntime.checked && !force) {
          return cloudRuntime.available;
        }

        let contractMismatch = false;

        const endpoints = Array.from(
          new Set(
            [cloudRuntime.endpoint, ...CLOUD_FUNCTION_ENDPOINTS].filter((value) =>
              String(value || "").trim(),
            ),
          ),
        );

        for (const endpoint of endpoints) {
          try {
            const response = await fetch(endpoint, {
              method: "GET",
              headers: {
                Accept: "application/json",
              },
            });
            if (!response.ok) {
              continue;
            }
            const payload = await response.json();
            if (!payload?.ok) {
              continue;
            }
            if (String(payload?.contractVersion || "").trim() !== WORKSPACE_CONTRACT_VERSION) {
              contractMismatch = true;
              continue;
            }
            cloudRuntime = {
              checked: true,
              available: true,
              initialized:
                typeof payload?.initialized === "boolean" ? payload.initialized : null,
              endpoint,
              revision: normalizeWorkspaceRevision(payload?.revision),
              contractVersion: String(payload?.contractVersion || "").trim(),
              contractMismatch: false,
            };
            return true;
          } catch (error) {
            // Try the next candidate endpoint.
          }
        }

        cloudRuntime = {
          checked: true,
          available: false,
          initialized: null,
          endpoint: "",
          revision: 0,
          contractVersion: "",
          contractMismatch: contractMismatch,
        };
        return false;
      }

      async function callCloud(action, payload = {}) {
        const endpoint = cloudRuntime.endpoint || CLOUD_FUNCTION_ENDPOINTS[0];
        const response = await fetch(endpoint, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Accept: "application/json",
          },
          body: JSON.stringify({
            action,
            ...payload,
          }),
        });

        let result = {};
        try {
          result = await response.json();
        } catch (error) {
          result = {};
        }

        if (!response.ok || result.ok === false) {
          const error = new Error(
            String(result?.error || result?.message || "JADE Hummingbird backend request failed."),
          );
          error.code = result?.code || String(response.status || "backend_error");
          throw error;
        }

        if (String(result?.contractVersion || "").trim() !== WORKSPACE_CONTRACT_VERSION) {
          cloudRuntime.contractMismatch = true;
          throw createWorkspaceContractError(
            action,
            `backend contract ${String(result?.contractVersion || "none").trim() || "none"} does not match ${WORKSPACE_CONTRACT_VERSION}`,
          );
        }

        if (typeof result?.initialized === "boolean") {
          cloudRuntime.initialized = result.initialized;
        }
        if (typeof result?.revision !== "undefined") {
          cloudRuntime.revision = normalizeWorkspaceRevision(result.revision);
        }
        cloudRuntime.contractVersion = String(result?.contractVersion || "").trim();
        cloudRuntime.contractMismatch = false;
        cloudRuntime.available = true;
        cloudRuntime.checked = true;
        cloudRuntime.endpoint = endpoint;
        return result;
      }

      async function getCloudBootstrapState() {
        if (!(await probeCloudBackend())) {
          return null;
        }

        try {
          const result = await callCloud("bootstrap");
          if (typeof result?.initialized === "boolean") {
            cloudRuntime.initialized = result.initialized;
          }
          return result.state ? await rehydrateState(result.state) : null;
        } catch (error) {
          return null;
        }
      }

      async function getCloudAuthenticatedState() {
        if (!(await probeCloudBackend()) || !session.cloudSessionToken) {
          return null;
        }

        try {
          const result = await callCloud("get_state", {
            sessionToken: session.cloudSessionToken,
          });
          cloudRuntime.initialized = true;
          return await rehydrateState(result.state);
        } catch (error) {
          session.cloudSessionToken = "";
          saveSession();
          return null;
        }
      }

      async function getCloudWorkspaceRevision() {
        if (!(await probeCloudBackend()) || !session.cloudSessionToken) {
          return 0;
        }

        try {
          const result = await callCloud("get_revision", {
            sessionToken: session.cloudSessionToken,
          });
          cloudRuntime.initialized = true;
          return normalizeWorkspaceRevision(result?.revision);
        } catch (error) {
          session.cloudSessionToken = "";
          saveSession();
          return 0;
        }
      }

      async function refreshStateFromBackend(options = {}) {
        if (!session.cloudSessionToken) {
          return false;
        }

        if (cloudRefreshInFlight) {
          return cloudRefreshInFlight;
        }

        cloudRefreshInFlight = (async () => {
          const previousRevision = normalizeWorkspaceRevision(cloudRuntime.revision);
          try {
            const result = await callCloud("get_state", {
              sessionToken: session.cloudSessionToken,
            });
            cloudRuntime.initialized = true;
            const latestRevision = normalizeWorkspaceRevision(result?.revision);
            const revisionUnchanged =
              previousRevision > 0 &&
              latestRevision > 0 &&
              latestRevision === previousRevision;

            if (revisionUnchanged && !options.forceApply) {
              return false;
            }

            state = await rehydrateState(result.state);
            updateCurrentUserRecord();
            applyBranding();
            saveState();
            saveSession();

            if (!options.skipRender) {
              renderApp();
            }
            return true;
          } catch (error) {
            session.cloudSessionToken = "";
            saveSession();
            return false;
          }
        })();

        try {
          return await cloudRefreshInFlight;
        } finally {
          cloudRefreshInFlight = null;
        }
      }

      function queueCloudPersist(options = {}) {
        const syncId = createId("cloud-sync");
        const queuedSnapshotSource =
          options.snapshot && typeof options.snapshot === "object" ? options.snapshot : state;
        if (!queuedSnapshotSource) {
          return;
        }
        const queuedState = clone(queuedSnapshotSource);
        savePendingCloudSyncRecord(queuedState, syncId);

        cloudPersistQueue = cloudPersistQueue
          .then(async () => {
            if (!(await probeCloudBackend()) || !session.cloudSessionToken || !getCurrentUser()) {
              return;
            }

            try {
              const snapshot = await rehydrateState(queuedState);
              const result = await callCloud("persist", {
                sessionToken: session.cloudSessionToken,
                state: snapshot,
                expectedRevision: cloudRuntime.revision,
              });
              cloudRuntime.initialized = true;
              if (result?.state && pendingCloudSync?.id === syncId) {
                state = await rehydrateState(result.state);
                updateCurrentUserRecord();
                saveState();
                saveSession();
                clearPendingCloudSyncRecord(syncId);
                if (requiresSharedBackend() && !options.skipSuccessRender) {
                  renderApp();
                }
              }
            } catch (error) {
              console.error(error);
              if (error.code === "stale_revision") {
                try {
                  await callCloud("get_state", {
                    sessionToken: session.cloudSessionToken,
                  });
                } catch (_refreshError) {
                  // Keep the preserved local snapshot even if the revision refresh fails.
                }
                if (pendingCloudSync?.id === syncId) {
                  setFlash(
                    "warning",
                    "JADE Hummingbird kept your newest local edit on this device, but another device changed the shared workspace first. Review the result and save again so nothing gets overwritten.",
                  );
                  renderApp();
                }
                return;
              }
              setFlash(
                "warning",
                "JADE Hummingbird kept this change on the device and will retry the shared backend save when the connection settles.",
              );
              renderApp();
            }
          })
          .catch((error) => {
            console.error(error);
          });
      }

      async function flushCloudPersistQueue() {
        try {
          await cloudPersistQueue;
        } catch (error) {
          console.error(error);
        }
      }

      async function persistStateToCloudNow({ skipRender = true } = {}) {
        updateCurrentUserRecord();
        saveState();
        saveSession();

        const cloudAvailable = await probeCloudBackend(true);
        if (!cloudAvailable) {
          if (requiresSharedBackend()) {
            throw new Error(getSharedBackendUnavailableMessage());
          }
          queueCloudPersist();
          return false;
        }

        if (!session.cloudSessionToken || !getCurrentUser()) {
          if (requiresSharedBackend()) {
            throw new Error("Your shared session has expired. Please sign in again.");
          }
          queueCloudPersist();
          return false;
        }

        let result;
        const syncId = createId("cloud-sync");
        const queuedState = clone(state);
        savePendingCloudSyncRecord(queuedState, syncId);
        try {
          const snapshot = await rehydrateState(queuedState);
          result = await callCloud("persist", {
            sessionToken: session.cloudSessionToken,
            state: snapshot,
            expectedRevision: cloudRuntime.revision,
          });
        } catch (error) {
          if (error.code === "stale_revision") {
            clearPendingCloudSyncRecord(syncId);
            await refreshStateFromBackend({ skipRender: true });
            const conflictError = new Error(
              "Another device changed JADE Hummingbird first. The page was refreshed to the latest shared version; please apply that edit again.",
            );
            conflictError.code = "stale_revision";
            throw conflictError;
          }
          throw error;
        }
        cloudRuntime.initialized = true;
        state = await rehydrateState(result.state);
        updateCurrentUserRecord();
        saveState();
        saveSession();
        clearPendingCloudSyncRecord(syncId);

        if (!skipRender) {
          renderApp();
        }

        return true;
      }

      async function saveBrowserCredential(name, email, password) {
        if (
          !window.PasswordCredential ||
          !navigator.credentials ||
          typeof navigator.credentials.store !== "function"
        ) {
          return;
        }

        try {
          const credential = new PasswordCredential({
            id: normalizeEmail(email),
            name: String(name || "").trim() || normalizeEmail(email),
            password: String(password || ""),
          });
          await navigator.credentials.store(credential);
        } catch (error) {
          // Ignore browsers or contexts that do not support credential storage here.
        }
      }

      function supportsDevicePasswordSaving() {
        return Boolean(
          window.PasswordCredential &&
            navigator.credentials &&
            typeof navigator.credentials.store === "function",
        );
      }

      function canClaimRegisteredUser(user = {}) {
        return (
          String(user.createdSource || "").trim().toLowerCase() === "registered" &&
          !String(user.lastLoginAt || "").trim()
        );
      }

      async function reduceDevicePasswordAutoSignIn() {
        if (
          !navigator.credentials ||
          typeof navigator.credentials.preventSilentAccess !== "function"
        ) {
          return;
        }

        try {
          await navigator.credentials.preventSilentAccess();
        } catch (error) {
          // Ignore browsers that reject this request.
        }
      }

      function updateCurrentUserRecord() {
        const current = getCurrentUser();
        if (!current) {
          session = getEmptySession();
          clearStoredSession();
        }
      }

      function saveState() {
        if (!state) {
          localStorage.removeItem(STORAGE_KEY);
          return;
        }
        state.workspaceContractVersion = WORKSPACE_CONTRACT_VERSION;
        assertWorkspaceContract(state, "local save");
        localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
      }

      function setFlash(type, text) {
        flash = { type, text };
      }

      function clearFlash() {
        flash = { type: "", text: "" };
      }

      function persist(type, text) {
        updateCurrentUserRecord();
        saveState();
        saveSession();
        applyBranding();
        if (type && text) {
          setFlash(type, text);
        }
        renderApp();
        queueCloudPersist({
          skipSuccessRender: true,
        });
      }

      function createParticipant(
        email,
        name,
        winsOrStats,
        points,
        teamName = "",
        extras = {},
      ) {
        const stats =
          typeof winsOrStats === "object"
            ? winsOrStats
            : {
                wins: winsOrStats,
                points,
                ...extras,
              };
        return {
          id: createId("participant"),
          email: normalizeEmail(email),
          name: String(name || "").trim(),
          institution: String(extras.institution || stats.institution || "").trim(),
          teamId: String(extras.teamId || stats.teamId || "").trim(),
          teamName: String(teamName || extras.teamName || stats.teamName || "").trim(),
          wins: normalizeNonNegative(stats.wins, 0),
          losses: normalizeNonNegative(stats.losses, 0),
          points: normalizeNonNegative(stats.points, 0),
          firsts: normalizeNonNegative(stats.firsts, 0),
          seconds: normalizeNonNegative(stats.seconds, 0),
          thirds: normalizeNonNegative(stats.thirds, 0),
          fourths: normalizeNonNegative(stats.fourths, 0),
          speakerScore: normalizeNonNegative(stats.speakerScore, 0),
          rank: 0,
          token: createId("token"),
          feedback: Array.isArray(extras.feedback || stats.feedback)
            ? clone(extras.feedback || stats.feedback)
            : [],
        };
      }

      function createStandingRecord(name, stats) {
        return {
          id: createId("standing"),
          name: String(name || "").trim(),
          wins: normalizeNonNegative(stats.wins, 0),
          losses: normalizeNonNegative(stats.losses, 0),
          points: normalizeNonNegative(stats.points, 0),
          firsts: normalizeNonNegative(stats.firsts, 0),
          seconds: normalizeNonNegative(stats.seconds, 0),
          thirds: normalizeNonNegative(stats.thirds, 0),
          fourths: normalizeNonNegative(stats.fourths, 0),
          rank: 0,
        };
      }

      function normalizeTeamSource(value, fallback = "manual") {
        const normalized = String(value || "")
          .trim()
          .toLowerCase()
          .replace(/[_\s-]+/g, "_");

        if (["generated", "random", "random_team"].includes(normalized)) {
          return "generated";
        }

        if (["derived", "participant", "standing", "inferred"].includes(normalized)) {
          return "derived";
        }

        return fallback;
      }

      function createTeamRecord(name, institution = "", extras = {}) {
        const source = normalizeTeamSource(
          extras.source ||
            extras.teamSource ||
            (String(extras.notes || "").trim().toLowerCase() === "randomly generated team."
              ? "generated"
              : ""),
        );
        return {
          id: extras.id || createId("team"),
          name: String(name || "").trim(),
          institution: String(institution || "").trim(),
          publicAlias: String(
            extras.publicAlias || extras.codeName || extras.publicName || "",
          ).trim(),
          notes: String(extras.notes || "").trim(),
          source,
          createdAt: extras.createdAt || timestamp(),
        };
      }

      function normalizeTeamRecord(record) {
        return createTeamRecord(record?.name || record?.teamName || "", record?.institution || "", {
          id: record?.id,
          publicAlias: record?.publicAlias || record?.codeName || record?.publicName,
          notes: record?.notes,
          source: record?.source || record?.teamSource,
          createdAt: record?.createdAt,
        });
      }

      function getTeamIdentityKey(team) {
        return [normalizeTextKey(team?.name), normalizeTextKey(team?.institution)].join("::");
      }

      function getTeamDisplayLabel(team) {
        const name = String(team?.name || "").trim();
        const institution = String(team?.institution || "").trim();
        if (!institution) {
          return name;
        }
        return institution + " " + name;
      }

      function getTeamPublicLabel(team) {
        return String(team?.publicAlias || "").trim() || getTeamDisplayLabel(team);
      }

      function teamsLookEquivalent(left, right) {
        if (!left || !right) {
          return false;
        }

        const leftKey = getTeamIdentityKey(left);
        const rightKey = getTeamIdentityKey(right);
        if (leftKey && rightKey && leftKey === rightKey) {
          return true;
        }

        const leftName = normalizeTextKey(left.name);
        const rightName = normalizeTextKey(right.name);
        const leftInstitution = normalizeTextKey(left.institution);
        const rightInstitution = normalizeTextKey(right.institution);
        const leftDisplay = normalizeTextKey(getTeamDisplayLabel(left));
        const rightDisplay = normalizeTextKey(getTeamDisplayLabel(right));
        const leftAlias = normalizeTextKey(left.publicAlias);
        const rightAlias = normalizeTextKey(right.publicAlias);

        if (leftAlias && rightAlias && leftAlias === rightAlias) {
          return true;
        }

        if (leftDisplay && rightDisplay && leftDisplay === rightDisplay) {
          return true;
        }

        if (leftName && rightDisplay && leftName === rightDisplay) {
          return !leftInstitution || !rightInstitution || leftInstitution === rightInstitution;
        }

        if (rightName && leftDisplay && rightName === leftDisplay) {
          return !leftInstitution || !rightInstitution || leftInstitution === rightInstitution;
        }

        if (!leftInstitution && !rightInstitution && leftName && rightName && leftName === rightName) {
          return true;
        }

        return false;
      }

      function shouldUsePublicTeamAliases(tournament, options = {}) {
        if (!tournament?.publication?.usePublicTeamAliases) {
          return false;
        }
        if (options.forcePublic === true) {
          return true;
        }
        if (options.forcePrivate === true) {
          return false;
        }
        return !canManageTournament(tournament) && !canJudgeTournament(tournament);
      }

      function findTournamentTeamByName(tournament, name) {
        const target = normalizeTextKey(name);
        if (!target) {
          return null;
        }

        return (
          getTournamentTeams(tournament).find(
            (team) =>
              normalizeTextKey(team.name) === target ||
              normalizeTextKey(getTeamDisplayLabel(team)) === target ||
              normalizeTextKey(team.publicAlias) === target,
          ) || null
        );
      }

      function getTeamNameForDisplay(tournament, team, options = {}) {
        if (!team) {
          return "";
        }
        return shouldUsePublicTeamAliases(tournament, options)
          ? getTeamPublicLabel(team)
          : getTeamDisplayLabel(team);
      }

      function getStandingDisplayName(tournament, standing, options = {}) {
        const team = findTournamentTeamByName(tournament, standing?.name || "");
        if (team) {
          return getTeamNameForDisplay(tournament, team, options);
        }
        return String(standing?.name || "").trim();
      }

      function normalizeTeamsForTournament(teamRecords = [], tournament = {}) {
        const catalog = [];
        const participantModel = String(tournament?.participantModel || "").trim().toLowerCase();

        (Array.isArray(teamRecords) ? teamRecords : []).forEach((record) => {
          const team = normalizeTeamRecord(record);
          if (
            team.name &&
            !catalog.some((existingTeam) => teamsLookEquivalent(existingTeam, team))
          ) {
            catalog.push(team);
          }
        });

        const curatedTeams = catalog.filter((team) => team.source !== "generated" && team.source !== "derived");
        const nonGeneratedTeams = catalog.filter((team) => team.source !== "generated");

        if (participantModel === "teams" && curatedTeams.length) {
          return curatedTeams.sort(
            (left, right) =>
              String(left.name).localeCompare(String(right.name)) ||
              String(left.institution).localeCompare(String(right.institution)),
          );
        }

        if (participantModel === "teams" && nonGeneratedTeams.length) {
          return nonGeneratedTeams.sort(
            (left, right) =>
              String(left.name).localeCompare(String(right.name)) ||
              String(left.institution).localeCompare(String(right.institution)),
          );
        }

        (tournament.participants || []).forEach((participant) => {
          const teamName = String(participant.teamName || "").trim();
          if (!teamName) return;
          const team = normalizeTeamRecord({
            id: participant.teamId || "",
            name: teamName,
            institution: participant.institution || "",
            source: "derived",
          });
          if (!catalog.some((existingTeam) => teamsLookEquivalent(existingTeam, team))) {
            catalog.push(team);
          }
        });

        if (tournament.participantModel === "teams") {
          (tournament.standings || []).forEach((standing) => {
            const name = String(standing.name || "").trim();
            if (!name) return;
            const standingTeam = normalizeTeamRecord({ name, source: "derived" });
            if (!catalog.some((team) => teamsLookEquivalent(team, standingTeam))) {
              const team = normalizeTeamRecord({ name, source: "derived" });
              catalog.push(team);
            }
          });
        }

        return catalog.sort(
          (left, right) =>
            String(left.name).localeCompare(String(right.name)) ||
            String(left.institution).localeCompare(String(right.institution)),
        );
      }

      function normalizeJudgePanelQuality(value, fallback = "wing") {
        const normalized = String(value || "")
          .trim()
          .toLowerCase()
          .replace(/[_-]+/g, " ");

        if (["chair", "chair quality", "chair capable"].includes(normalized)) {
          return "chair";
        }

        if (
          ["wing", "wing quality", "panel", "panelist", "panel quality"].includes(normalized)
        ) {
          return "wing";
        }

        return fallback;
      }

      function normalizeJudgeQualityTier(value, fallback = "solid") {
        const normalized = String(value || "")
          .trim()
          .toLowerCase()
          .replace(/[_-]+/g, " ");

        if (["premier", "elite", "top", "a"].includes(normalized)) {
          return "premier";
        }

        if (["strong", "advanced", "b"].includes(normalized)) {
          return "strong";
        }

        if (["solid", "standard", "c"].includes(normalized)) {
          return "solid";
        }

        if (["developing", "developing chair", "developing wing", "d"].includes(normalized)) {
          return "developing";
        }

        if (["trainee", "new", "novice", "e"].includes(normalized)) {
          return "trainee";
        }

        return fallback;
      }

      function getJudgePanelQualityLabel(value) {
        return normalizeJudgePanelQuality(value) === "chair" ? "Chair Quality" : "Wing Quality";
      }

      function getJudgeQualityTierLabel(value) {
        const normalized = normalizeJudgeQualityTier(value);
        return {
          premier: "Premier",
          strong: "Strong",
          solid: "Solid",
          developing: "Developing",
          trainee: "Trainee",
        }[normalized];
      }

      function getJudgeQualityRank(value) {
        return {
          premier: 5,
          strong: 4,
          solid: 3,
          developing: 2,
          trainee: 1,
        }[normalizeJudgeQualityTier(value)];
      }

      function compareJudgesByQuality(left, right) {
        const leftPanel = normalizeJudgePanelQuality(left?.panelQuality);
        const rightPanel = normalizeJudgePanelQuality(right?.panelQuality);
        const leftPanelScore = leftPanel === "chair" ? 1 : 0;
        const rightPanelScore = rightPanel === "chair" ? 1 : 0;

        return (
          rightPanelScore - leftPanelScore ||
          getJudgeQualityRank(right?.qualityTier) - getJudgeQualityRank(left?.qualityTier) ||
          String(left?.name || left?.email || "").localeCompare(
            String(right?.name || right?.email || ""),
          )
        );
      }

      function normalizeJudgeAllocationRole(value, fallback = "panelist") {
        const normalized = String(value || "")
          .trim()
          .toLowerCase()
          .replace(/[_-]+/g, " ");

        if (["chair", "chair quality"].includes(normalized)) {
          return "chair";
        }

        if (["panelist", "panel", "wing", "wing quality"].includes(normalized)) {
          return "panelist";
        }

        if (["auto", "profile", "use profile"].includes(normalized)) {
          return fallback;
        }

        return fallback;
      }

      function getJudgeAllocationRoleLabel(value) {
        return normalizeJudgeAllocationRole(value) === "chair" ? "Chair" : "Panelist";
      }

      function getJudgeQualityOptionsMarkup(currentValue = "solid") {
        const current = normalizeJudgeQualityTier(currentValue);
        return [
          { value: "premier", label: "Premier" },
          { value: "strong", label: "Strong" },
          { value: "solid", label: "Solid" },
          { value: "developing", label: "Developing" },
          { value: "trainee", label: "Trainee" },
        ]
          .map(
            (option) =>
              `<option value="${option.value}" ${selected(
                option.value,
                current,
              )}>${escapeHtml(option.label)}</option>`,
          )
          .join("");
      }

      function getJudgePanelQualityOptionsMarkup(currentValue = "wing") {
        const current = normalizeJudgePanelQuality(currentValue);
        return [
          { value: "chair", label: "Chair Quality" },
          { value: "wing", label: "Wing Quality" },
        ]
          .map(
            (option) =>
              `<option value="${option.value}" ${selected(
                option.value,
                current,
              )}>${escapeHtml(option.label)}</option>`,
          )
          .join("");
      }

      function getJudgeAssignmentRoleOptionsMarkup(currentValue = "auto") {
        const current = String(currentValue || "auto").trim().toLowerCase();
        return [
          { value: "auto", label: "Use Judge Profile" },
          { value: "chair", label: "Chair" },
          { value: "panelist", label: "Panelist" },
        ]
          .map(
            (option) =>
              `<option value="${option.value}" ${selected(
                option.value,
                current,
              )}>${escapeHtml(option.label)}</option>`,
          )
          .join("");
      }

      function getJudgeAffiliationOptionsMarkup(currentValue = "institutional") {
        const current = normalizeJudgeAffiliationType(currentValue);
        return [
          { value: "institutional", label: "Institutionally Affiliated" },
          { value: "independent", label: "Independent Judge" },
        ]
          .map(
            (option) =>
              `<option value="${option.value}" ${selected(
                option.value,
                current,
              )}>${escapeHtml(option.label)}</option>`,
          )
          .join("");
      }

      function normalizeJudgeAffiliationType(value, institution = "") {
        const normalized = String(value || "")
          .trim()
          .toLowerCase()
          .replace(/[_-]+/g, " ");

        if (["independent", "independent judge", "ind"].includes(normalized)) {
          return "independent";
        }

        if (
          [
            "institutional",
            "institutionally affiliated",
            "institutional judge",
            "affiliated",
            "institution",
          ].includes(normalized)
        ) {
          return "institutional";
        }

        return String(institution || "").trim() ? "institutional" : "independent";
      }

      function createTemporaryRegistrationPassword() {
        return Array.from(crypto.getRandomValues(new Uint8Array(24)))
          .map((value) => value.toString(16).padStart(2, "0"))
          .join("");
      }

      function createJudgeRecord(name, email, institution = "", extras = {}) {
        const normalizedInstitution = String(institution || "").trim();
        const affiliationType = normalizeJudgeAffiliationType(
          extras.affiliationType || extras.affiliation,
          normalizedInstitution,
        );
        return {
          id: extras.id || createId("judge"),
          name: String(name || "").trim() || String(email || "").trim().split("@")[0],
          email: normalizeEmail(email),
          institution: affiliationType === "independent" ? "" : normalizedInstitution,
          affiliationType,
          panelQuality: normalizeJudgePanelQuality(
            extras.panelQuality || extras.qualityTrack || extras.capability,
            "wing",
          ),
          qualityTier: normalizeJudgeQualityTier(
            extras.qualityTier || extras.ranking || extras.rating,
            "solid",
          ),
          notes: String(extras.notes || "").trim(),
          active: extras.active !== false,
          createdAt: extras.createdAt || timestamp(),
        };
      }

      function normalizeJudgeRecord(record) {
        return createJudgeRecord(
          record?.name || record?.email || "",
          record?.email || "",
          record?.institution || "",
          {
            id: record?.id,
            affiliationType: record?.affiliationType || record?.affiliation,
            panelQuality:
              record?.panelQuality || record?.qualityTrack || record?.capability || record?.panelRole,
            qualityTier: record?.qualityTier || record?.ranking || record?.rating,
            notes: record?.notes,
            active: record?.active,
            createdAt: record?.createdAt,
          },
        );
      }

      function getJudgeDisplayLabel(judge) {
        const name = String(judge?.name || judge?.email || "").trim();
        const affiliationType = normalizeJudgeAffiliationType(
          judge?.affiliationType,
          judge?.institution,
        );
        const institution = String(judge?.institution || "").trim();
        if (affiliationType === "independent") {
          return name ? name + " • Independent" : "Independent Judge";
        }
        return institution ? name + " • " + institution : name;
      }

      function getJudgeMetadataLine(judge) {
        const parts = [];
        if (judge?.email) {
          parts.push(judge.email);
        }
        if (normalizeJudgeAffiliationType(judge?.affiliationType, judge?.institution) === "independent") {
          parts.push("Independent Judge");
        } else if (judge?.institution) {
          parts.push(judge.institution);
        }
        parts.push(getJudgePanelQualityLabel(judge?.panelQuality));
        parts.push(getJudgeQualityTierLabel(judge?.qualityTier));
        return parts.filter(Boolean).join(" • ");
      }

      function getTournamentJudges(tournament) {
        const catalog = new Map();

        (Array.isArray(tournament.judges) ? tournament.judges : []).forEach((record) => {
          const judge = normalizeJudgeRecord(record);
          if (judge.email) {
            catalog.set(judge.email, judge);
          }
        });

        (tournament.permissions?.judgeEmails || []).forEach((email) => {
          const normalizedEmail = normalizeEmail(email);
          if (!normalizedEmail) return;
          if (!catalog.has(normalizedEmail)) {
            const linkedUser = state.users.find((user) => user.email === normalizedEmail);
            catalog.set(
              normalizedEmail,
              createJudgeRecord(
                linkedUser?.name || normalizedEmail.split("@")[0],
                normalizedEmail,
              ),
            );
          }
        });

        return Array.from(catalog.values()).sort(
          (left, right) =>
            compareJudgesByQuality(left, right) ||
            String(left.email).localeCompare(String(right.email)),
        );
      }

      function getJudgeByEmail(tournament, email) {
        const target = normalizeEmail(email);
        return getTournamentJudges(tournament).find((judge) => judge.email === target) || null;
      }

      function getJudgeOptionsMarkup(tournament, currentEmail = "") {
        const judges = getTournamentJudges(tournament);
        if (!judges.length) {
          return `<option value="">No judges added yet</option>`;
        }
        return judges
          .map(
            (judge) =>
              `<option value="${escapeHtml(judge.email)}" ${selected(
                judge.email,
                currentEmail,
              )}>${escapeHtml(
                getJudgeDisplayLabel(judge) +
                  " • " +
                  getJudgePanelQualityLabel(judge.panelQuality) +
                  " / " +
                  getJudgeQualityTierLabel(judge.qualityTier),
              )}</option>`,
          )
          .join("");
      }

      function inferParticipantIdsFromMatchup(tournament, matchup) {
        const text = String(matchup || "").trim().toLowerCase();
        if (!text) {
          return [];
        }

        const found = new Set();
        (tournament.participants || []).forEach((participant) => {
          const normalized = normalizeParticipantRecord(participant);
          const searchTerms = [
            normalized.name,
            normalized.teamName,
            normalized.institution,
            normalized.institution && normalized.teamName
              ? normalized.institution + " " + normalized.teamName
              : "",
          ]
            .map((value) => String(value || "").trim().toLowerCase())
            .filter(Boolean);
          if (searchTerms.some((term) => term && text.includes(term))) {
            found.add(normalized.id);
          }
        });
        return Array.from(found);
      }

      function getDrawEntryById(tournament, drawId) {
        return (tournament.draw || []).find((entry) => entry.id === drawId) || null;
      }

      function getParticipantsForDrawRecord(tournament, drawEntry) {
        if (!drawEntry) {
          return [];
        }

        const explicitIds = Array.isArray(drawEntry.participantIds)
          ? drawEntry.participantIds.map((id) => String(id))
          : [];
        if (explicitIds.length) {
          return (tournament.participants || [])
            .map((participant) => normalizeParticipantRecord(participant))
            .filter((participant) => explicitIds.includes(participant.id));
        }

        const inferredIds = inferParticipantIdsFromMatchup(tournament, drawEntry.matchup || "");
        return (tournament.participants || [])
          .map((participant) => normalizeParticipantRecord(participant))
          .filter((participant) => inferredIds.includes(participant.id));
      }

      function getParticipantDrawSlotDetails(tournament, drawEntry, participant) {
        if (!drawEntry || !participant) {
          return { slot: null, slotIndex: -1, label: "" };
        }

        const slotIndex = (Array.isArray(drawEntry.slots) ? drawEntry.slots : []).findIndex((slot) =>
          Array.isArray(slot.participantIds) && slot.participantIds.includes(participant.id),
        );
        const slot = slotIndex >= 0 ? drawEntry.slots[slotIndex] : null;
        return {
          slot,
          slotIndex,
          label: slot
            ? getDrawSlotDisplayLabel(tournament, slot, {
                drawEntry,
                slotIndex,
                forcePrivate: true,
              })
            : participant.teamName
              ? participant.teamName
              : participant.institution || "Individual",
        };
      }

      function orderParticipantsForDrawEntry(tournament, drawEntry, participants = []) {
        const slotDisplayOrder = new Map(
          getOrderedDrawSlotsForDisplay(tournament, drawEntry).map((entry, index) => [
            getDrawSlotCheckInKey(entry.slot),
            index,
          ]),
        );
        return [...(Array.isArray(participants) ? participants : [])].sort((left, right) => {
          const leftSlot = getParticipantDrawSlotDetails(tournament, drawEntry, left);
          const rightSlot = getParticipantDrawSlotDetails(tournament, drawEntry, right);
          const leftDisplayIndex = leftSlot.slot
            ? slotDisplayOrder.get(getDrawSlotCheckInKey(leftSlot.slot))
            : leftSlot.slotIndex;
          const rightDisplayIndex = rightSlot.slot
            ? slotDisplayOrder.get(getDrawSlotCheckInKey(rightSlot.slot))
            : rightSlot.slotIndex;
          const leftPosition =
            leftSlot.slot && Array.isArray(leftSlot.slot.participantIds)
              ? leftSlot.slot.participantIds.indexOf(left.id)
              : -1;
          const rightPosition =
            rightSlot.slot && Array.isArray(rightSlot.slot.participantIds)
              ? rightSlot.slot.participantIds.indexOf(right.id)
              : -1;

          return (
            Number(leftDisplayIndex ?? leftSlot.slotIndex) -
              Number(rightDisplayIndex ?? rightSlot.slotIndex) ||
            leftPosition - rightPosition ||
            String(left.name || "").localeCompare(String(right.name || ""))
          );
        });
      }

      function getDrawRoleDisplayLabels(tournament, drawEntry) {
        return getOrderedDrawSlotsForDisplay(tournament, drawEntry)
          .map(({ slot, index }) =>
            getDrawSlotDisplayLabel(tournament, slot, {
              drawEntry,
              slotIndex: index,
              forcePrivate: true,
            }),
          )
          .filter(Boolean);
      }

      function createJudgeAllocationRecord(tournament, drawEntry, judgeEmail, extras = {}) {
        const participants = getParticipantsForDrawRecord(tournament, drawEntry);
        const normalizedJudgeEmail = normalizeEmail(judgeEmail || extras.judgeEmail);
        const judgeRecord = getJudgeByEmail(tournament, normalizedJudgeEmail);
        const defaultRole =
          normalizeJudgePanelQuality(judgeRecord?.panelQuality) === "chair" ? "chair" : "panelist";
        return {
          id: extras.id || createId("allocation"),
          drawId: String(drawEntry?.id || extras.drawId || "").trim(),
          round: Number(drawEntry?.round || extras.round || 1),
          room: String(drawEntry?.room || extras.room || "").trim(),
          matchup: String(drawEntry?.matchup || extras.matchup || "").trim(),
          judgeEmail: normalizedJudgeEmail,
          panelRole: normalizeJudgeAllocationRole(extras.panelRole || extras.role, defaultRole),
          status: String(extras.status || "assigned").trim(),
          participantIds: Array.isArray(extras.participantIds)
            ? extras.participantIds.map((id) => String(id))
            : participants.map((participant) => participant.id),
          checkedIn: Boolean(extras.checkedIn),
          checkedInAt: String(extras.checkedInAt || "").trim(),
          checkedInAtKey: normalizeTimestampKey(extras.checkedInAtKey, extras.checkedInAt),
          submittedAt: String(extras.submittedAt || "").trim(),
          submittedAtKey: normalizeTimestampKey(extras.submittedAtKey, extras.submittedAt),
          createdAt: extras.createdAt || timestamp(),
        };
      }

      function normalizeJudgeAllocationRecord(record, tournament) {
        const drawEntry = getDrawEntryById(tournament, record?.drawId || "");
        return createJudgeAllocationRecord(
          tournament,
          drawEntry,
          record?.judgeEmail || "",
          {
            id: record?.id,
            drawId: record?.drawId,
            round: record?.round,
            room: record?.room,
            matchup: record?.matchup,
            panelRole: record?.panelRole || record?.role,
            status: record?.status,
            participantIds: record?.participantIds,
            checkedIn: record?.checkedIn,
            checkedInAt: record?.checkedInAt,
            checkedInAtKey: record?.checkedInAtKey,
            submittedAt: record?.submittedAt,
            submittedAtKey: record?.submittedAtKey,
            createdAt: record?.createdAt,
          },
        );
      }

      function getJudgeAllocationsForTournament(tournament) {
        return (Array.isArray(tournament.judgeAllocations) ? tournament.judgeAllocations : [])
          .map((allocation) => normalizeJudgeAllocationRecord(allocation, tournament))
          .sort(
            (left, right) =>
              Number(left.round) - Number(right.round) ||
              String(left.room).localeCompare(String(right.room)) ||
              String(left.judgeEmail).localeCompare(String(right.judgeEmail)),
          );
      }

      function getAllocationsForDrawEntry(tournament, drawId) {
        return getJudgeAllocationsForTournament(tournament).filter(
          (allocation) => allocation.drawId === drawId,
        );
      }

      function getRoomJudgeComposition(tournament, drawId, excludeAllocationId = "") {
        const allocations = getAllocationsForDrawEntry(tournament, drawId).filter(
          (allocation) => allocation.id !== excludeAllocationId,
        );
        const chairCount = allocations.filter(
          (allocation) =>
            normalizeJudgeAllocationRole(allocation.panelRole, "panelist") === "chair",
        ).length;
        const panelCount = allocations.length - chairCount;

        return {
          allocations,
          chairCount,
          panelCount,
          total: allocations.length,
        };
      }

      function getChairAllocationForDrawEntry(tournament, drawId, excludeAllocationId = "") {
        return (
          getAllocationsForDrawEntry(tournament, drawId).find(
            (allocation) =>
              allocation.id !== excludeAllocationId &&
              normalizeJudgeAllocationRole(allocation.panelRole, "panelist") === "chair",
          ) || null
        );
      }

      function getJudgeAllocationForRound(
        tournament,
        judgeEmail,
        round,
        excludeAllocationId = "",
      ) {
        const targetEmail = normalizeEmail(judgeEmail);
        return (
          getJudgeAllocationsForTournament(tournament).find(
            (allocation) =>
              allocation.id !== excludeAllocationId &&
              Number(allocation.round) === Number(round) &&
              normalizeEmail(allocation.judgeEmail) === targetEmail,
          ) || null
        );
      }

      function areAllDrawEntriesCheckedIn(drawEntry) {
        if (!Array.isArray(drawEntry?.slots) || !drawEntry.slots.length) {
          return false;
        }
        return drawEntry.slots.every(
          (slot) => Boolean(drawEntry.entryCheckIns?.[getDrawSlotCheckInKey(slot)]),
        );
      }

      function getOfficialBallotAllocationForDraw(tournament, drawEntry) {
        const chair = getChairAllocationForDrawEntry(tournament, drawEntry?.id || "");
        if (chair?.submittedAt) {
          return chair;
        }
        return null;
      }

      function getRoundStatusSummary(tournament, round) {
        const rooms = (tournament.draw || [])
          .filter((entry) => Number(entry.round) === Number(round))
          .sort(
            (left, right) =>
              Number(right.priority || 0) - Number(left.priority || 0) ||
              String(left.room || "").localeCompare(String(right.room || "")),
          );
        const allocations = getJudgeAllocationsForTournament(tournament).filter(
          (allocation) => Number(allocation.round) === Number(round),
        );
        const chairs = allocations.filter(
          (allocation) =>
            normalizeJudgeAllocationRole(allocation.panelRole, "panelist") === "chair",
        );
        const checkedInEntries = rooms.filter((entry) => areAllDrawEntriesCheckedIn(entry)).length;
        const checkedInJudges = allocations.filter((allocation) => allocation.checkedIn).length;
        const published = rooms.filter(
          (entry) => String(entry.status || "").trim().toLowerCase() === "published",
        ).length;
        const officialBallots = rooms.filter((entry) =>
          Boolean(getOfficialBallotAllocationForDraw(tournament, entry)),
        ).length;
        const ballotReturns = rooms.filter((entry) => Boolean(entry.ballotCheckedIn)).length;
        const fullyReady = rooms.filter((entry) => {
          const roomAllocations = getAllocationsForDrawEntry(tournament, entry.id);
          const hasChair = roomAllocations.some(
            (allocation) =>
              normalizeJudgeAllocationRole(allocation.panelRole, "panelist") === "chair",
          );
          return hasChair && areAllDrawEntriesCheckedIn(entry);
        }).length;
        return {
          round,
          rooms,
          allocations,
          chairs,
          checkedInEntries,
          checkedInJudges,
          published,
          officialBallots,
          ballotReturns,
          fullyReady,
          averagePriority: rooms.length
            ? roundScoreValue(
                rooms.reduce(
                  (sum, entry) => sum + normalizeRoomPriority(entry.priority, 3),
                  0,
                ) / rooms.length,
                0,
              )
            : 0,
        };
      }

      function getDrawEntryCheckInSummary(drawEntry) {
        const total = Array.isArray(drawEntry?.slots) ? drawEntry.slots.length : 0;
        const checked = (Array.isArray(drawEntry?.slots) ? drawEntry.slots : []).filter((slot) =>
          Boolean(drawEntry.entryCheckIns?.[getDrawSlotCheckInKey(slot)]),
        ).length;
        return {
          checked,
          total,
        };
      }

      function getDrawEntryIdentityKeys(drawEntry) {
        return Array.from(
          new Set(
            (Array.isArray(drawEntry?.slots) ? drawEntry.slots : [])
              .map(
                (slot) =>
                  String(slot.teamId || "").trim() ||
                  String(slot.entryId || "").trim() ||
                  normalizeTextKey(slot.teamName || slot.shortLabel || slot.label),
              )
              .filter(Boolean),
          ),
        );
      }

      function getDrawSlotInstitution(tournament, slot) {
        const team =
          (slot?.teamId &&
            getTournamentTeams(tournament).find((entry) => entry.id === String(slot.teamId).trim())) ||
          findTournamentTeamByName(
            tournament,
            slot?.teamName || slot?.shortLabel || slot?.label || "",
          );
        if (team?.institution) {
          return String(team.institution || "").trim();
        }

        const institutions = Array.from(
          new Set(
            (Array.isArray(slot?.participantIds) ? slot.participantIds : [])
              .map((participantId) =>
                (tournament.participants || []).find((entry) => entry.id === participantId),
              )
              .map((participant) => String(participant?.institution || "").trim())
              .filter(Boolean),
          ),
        );

        if (institutions.length === 1) {
          return institutions[0];
        }

        return "";
      }

      function getJudgeInstitutionConflict(tournament, drawEntry, judgeRecordOrEmail) {
        if (!drawEntry) {
          return null;
        }

        const judge =
          typeof judgeRecordOrEmail === "string"
            ? getJudgeByEmail(tournament, judgeRecordOrEmail)
            : judgeRecordOrEmail;
        const judgeInstitution = String(judge?.institution || "").trim();
        if (!judgeInstitution) {
          return null;
        }

        const matchingLabels = Array.from(
          new Set(
            getOrderedDrawSlotsForDisplay(tournament, drawEntry)
              .map(({ slot, index }) => ({
                slot,
                index,
                institution: getDrawSlotInstitution(tournament, slot),
              }))
              .filter(
                (record) =>
                  normalizeTextKey(record.institution) === normalizeTextKey(judgeInstitution),
              )
              .map((record) =>
                getDrawSlotDisplayLabel(tournament, record.slot, {
                  drawEntry,
                  slotIndex: record.index,
                  forcePrivate: true,
                }),
              )
              .filter(Boolean),
          ),
        );

        if (!matchingLabels.length) {
          return null;
        }

        return {
          judge,
          institution: judgeInstitution,
          matchingLabels,
        };
      }

      function getDrawEntryConflictReport(tournament, drawEntry) {
        if (!drawEntry) {
          return [];
        }

        const issues = [];
        const slots = Array.isArray(drawEntry.slots) ? drawEntry.slots : [];
        const currentKeys = getDrawEntryIdentityKeys(drawEntry);
        const institutionMap = new Map();

        slots.forEach((slot) => {
          const institution = getDrawSlotInstitution(tournament, slot);
          if (!institution) {
            return;
          }
          institutionMap.set(institution, (institutionMap.get(institution) || 0) + 1);
        });

        institutionMap.forEach((count, institution) => {
          if (count > 1) {
            issues.push({
              tone: "danger",
              label: "Institution clash",
              detail:
                institution +
                " appears " +
                count +
                " times in this room.",
            });
          }
        });

        (tournament.draw || [])
          .filter((entry) => Number(entry.round || 0) < Number(drawEntry.round || 0))
          .forEach((previousEntry) => {
            const previousKeys = getDrawEntryIdentityKeys(previousEntry);
            const overlap = currentKeys.filter((key) => previousKeys.includes(key));
            if (overlap.length >= 2) {
              issues.push({
                tone: "warning",
                label: "Repeat matchup",
                detail:
                  "This room repeats " +
                  overlap.length +
                  " entry matchups from Round " +
                  previousEntry.round +
                  " • " +
                  previousEntry.room +
                  ".",
              });
            }
          });

        getAllocationsForDrawEntry(tournament, drawEntry.id).forEach((allocation) => {
          const judge = getJudgeByEmail(tournament, allocation.judgeEmail);
          const judgeConflict = getJudgeInstitutionConflict(tournament, drawEntry, judge);
          if (judgeConflict) {
            issues.push({
              tone: "danger",
              label: "Judge conflict",
              detail:
                (judge?.name || allocation.judgeEmail) +
                " shares " +
                judgeConflict.institution +
                " with " +
                judgeConflict.matchingLabels.join(", ") +
                ".",
            });
          }

          (tournament.judgeAllocations || [])
            .filter(
              (previousAllocation) =>
                normalizeEmail(previousAllocation.judgeEmail) ===
                  normalizeEmail(allocation.judgeEmail) &&
                Number(previousAllocation.round || 0) < Number(drawEntry.round || 0),
            )
            .forEach((previousAllocation) => {
              const previousEntry = getDrawEntryById(tournament, previousAllocation.drawId);
              const previousKeys = getDrawEntryIdentityKeys(previousEntry);
              const overlap = currentKeys.filter((key) => previousKeys.includes(key));
              if (overlap.length) {
                issues.push({
                  tone: "warning",
                  label: "Judge repeat exposure",
                  detail:
                    (judge?.name || allocation.judgeEmail) +
                    " has already seen " +
                    overlap.length +
                    " of these entries earlier in the tournament.",
                });
              }
            });
        });

        return Array.from(
          new Map(
            issues.map((issue) => [issue.label + "::" + issue.detail, issue]),
          ).values(),
        );
      }

      function getRoundConflictSummary(tournament, round) {
        const rooms = (tournament.draw || []).filter(
          (entry) => Number(entry.round || 0) === Number(round || 0),
        );
        const flaggedRooms = rooms
          .map((entry) => ({
            entry,
            issues: getDrawEntryConflictReport(tournament, entry),
          }))
          .filter((record) => record.issues.length);
        const total = flaggedRooms.reduce((sum, record) => sum + record.issues.length, 0);
        const severe = flaggedRooms.reduce(
          (sum, record) =>
            sum + record.issues.filter((issue) => issue.tone === "danger").length,
          0,
        );

        return {
          round,
          flaggedRooms,
          total,
          severe,
        };
      }

      function getRoundTimelineStages(tournament, round, options = {}) {
        const summary = getRoundStatusSummary(tournament, round);
        const control = getRoundControlForRound(tournament, round);
        const canManage = Boolean(options.canManage);
        const canSeeStandings = Boolean(options.canSeeStandings);
        const canSeeDraw = Boolean(options.canSeeDraw);

        if (canManage) {
          return [
            {
              label: "Build",
              status: summary.rooms.length ? "done" : "pending",
              value: summary.rooms.length ? summary.rooms.length + " rooms" : "Awaiting draw",
            },
            {
              label: "Release",
              status:
                summary.rooms.length && summary.published === summary.rooms.length
                  ? "done"
                  : summary.published
                    ? "active"
                    : "pending",
              value: summary.published + "/" + summary.rooms.length,
            },
            {
              label: "Check-In",
              status:
                summary.rooms.length && summary.fullyReady === summary.rooms.length
                  ? "done"
                  : summary.checkedInEntries || summary.checkedInJudges
                    ? "active"
                    : "pending",
              value: summary.fullyReady + "/" + summary.rooms.length + " ready",
            },
            {
              label: "Motion",
              status:
                getRoundMotionStatus(control).label === "Locked"
                  ? "pending"
                  : getRoundMotionStatus(control).label === "Prep Live"
                    ? "active"
                    : "done",
              value: getRoundMotionStatus(control).label,
            },
            {
              label: "Ballots",
              status:
                summary.rooms.length && summary.officialBallots === summary.rooms.length
                  ? "done"
                  : summary.officialBallots
                    ? "active"
                    : "pending",
              value: summary.officialBallots + "/" + summary.rooms.length,
            },
          ];
        }

        const publicRooms = canSeeDraw ? summary.published : 0;
        return [
          {
            label: "Posted",
            status: publicRooms ? "done" : "pending",
            value: canSeeDraw
              ? publicRooms
                ? publicRooms + " rooms"
                : "Awaiting release"
              : "Private",
          },
          {
            label: "Motion",
            status:
              !canSeeDraw
                ? "pending"
                : getRoundMotionStatus(control).label === "Locked"
                ? "pending"
                : getRoundMotionStatus(control).label === "Prep Live"
                  ? "active"
                  : "done",
            value: canSeeDraw ? getRoundMotionStatus(control).label : "Private",
          },
          {
            label: "Prep",
            status:
              !canSeeDraw
                ? "pending"
                : getRoundMotionStatus(control).label === "Prep Live"
                ? "active"
                : control.motionReleased && getRoundPrepEndKey(control)
                  ? "done"
                  : "pending",
            value: canSeeDraw ? getRoundPrepSummary(control) : "Private",
          },
          {
            label: "Ballots",
            status:
              publicRooms && summary.officialBallots >= publicRooms
                ? "done"
                : summary.officialBallots
                  ? "active"
                  : "pending",
            value: Math.min(summary.officialBallots, publicRooms) + "/" + publicRooms,
          },
          {
            label: "Boards",
            status:
              canSeeStandings && publicRooms && summary.officialBallots >= publicRooms
                ? "done"
                : canSeeStandings && summary.officialBallots
                  ? "active"
                  : "pending",
            value: canSeeStandings ? "Standings linked" : "Private",
          },
        ];
      }

      function getBreakProjection(tournament) {
        const breakSize = normalizeOptionalBreakSize(tournament?.config?.breakSize, null);
        const standings = getComputedStandings(tournament);
        if (!breakSize || !standings.length) {
          return null;
        }

        const cutIndex = Math.min(standings.length, breakSize) - 1;
        const cutStanding = standings[cutIndex] || null;
        const nextStanding = standings[cutIndex + 1] || null;
        const bubbleWindow = standings.slice(
          Math.max(0, cutIndex - 2),
          Math.min(standings.length, cutIndex + 3),
        );
        const ops = getTournamentOpsSnapshot(tournament);

        return {
          breakSize,
          cutStanding,
          nextStanding,
          bubbleWindow,
          provisional: ops.pendingBallotRooms > 0,
          lockLabel: ops.pendingBallotRooms > 0 ? "Provisional" : "Locked",
        };
      }

      function renderBreakBoardPanel(tournament, options = {}) {
        const board = getBreakBoard(tournament);
        if (!board) {
          return options.showEmpty
            ? `<div class="empty-state">${escapeHtml(
                options.emptyMessage ||
                  "Set a break size and collect standings to show which teams break and which teams miss.",
              )}</div>`
            : "";
        }

        return `
          <div class="flat-panel stack">
            <div class="section-heading">
              <div>
                <p class="eyebrow">Break Board</p>
                <h3>Who breaks and who misses</h3>
              </div>
              <span class="role-pill">${escapeHtml(
                board.breaking.length + " / " + board.total + " in break",
              )}</span>
            </div>
            <div class="leaderboard-grid">
              <div class="leaderboard-card">
                <div class="section-heading">
                  <h3>Breaking Teams</h3>
                  <span class="mini-pill success">${escapeHtml(
                    board.breaking.length + " qualified",
                  )}</span>
                </div>
                ${
                  board.breaking.length
                    ? `<div class="leaderboard-list">
                        ${board.breaking
                          .map(
                            (standing) => `
                              <div class="leaderboard-row">
                                <div class="stack">
                                  <strong>${escapeHtml(
                                    "#" +
                                      standing.rank +
                                      " " +
                                      getStandingDisplayName(tournament, standing, {
                                        forcePrivate: true,
                                      }),
                                  )}</strong>
                                  <span class="muted">${escapeHtml(
                                    getStandingSummaryText(tournament, standing),
                                  )}</span>
                                </div>
                                <span class="mini-pill success">Breaks</span>
                              </div>
                            `,
                          )
                          .join("")}
                      </div>`
                    : `<div class="empty-state">No teams currently break under this setting.</div>`
                }
              </div>
              <div class="leaderboard-card">
                <div class="section-heading">
                  <h3>Missing The Break</h3>
                  <span class="mini-pill warning">${escapeHtml(
                    board.missing.length + " outside",
                  )}</span>
                </div>
                ${
                  board.missing.length
                    ? `<div class="leaderboard-list">
                        ${board.missing
                          .map(
                            (standing) => `
                              <div class="leaderboard-row">
                                <div class="stack">
                                  <strong>${escapeHtml(
                                    "#" +
                                      standing.rank +
                                      " " +
                                      getStandingDisplayName(tournament, standing, {
                                        forcePrivate: true,
                                      }),
                                  )}</strong>
                                  <span class="muted">${escapeHtml(
                                    getStandingSummaryText(tournament, standing),
                                  )}</span>
                                </div>
                                <span class="mini-pill warning">Misses</span>
                              </div>
                            `,
                          )
                          .join("")}
                      </div>`
                    : `<div class="empty-state">Everyone currently breaks under this configuration.</div>`
                }
              </div>
            </div>
          </div>
        `;
      }

      function getInstitutionDashboardRecords(tournament) {
        const records = new Map();
        const teams = getTournamentTeams(tournament);
        const standings = getComputedStandings(tournament);
        const judges = getTournamentJudges(tournament);

        function getRecord(institution) {
          const key = String(institution || "").trim();
          if (!key) {
            return null;
          }
          if (!records.has(key)) {
            records.set(key, {
              institution: key,
              teams: 0,
              judges: 0,
              teamPoints: 0,
              speaks: 0,
              finish: null,
            });
          }
          return records.get(key);
        }

        teams.forEach((team) => {
          const institution = String(team.institution || "").trim();
          const record = getRecord(institution);
          if (!record) {
            return;
          }
          record.teams += 1;
          const standing = standings.find(
            (entry) => normalizeTextKey(entry.name) === normalizeTextKey(team.name),
          );
          if (standing) {
            record.teamPoints += Number(standing.points || 0);
            record.speaks += Number(standing.speaks || 0);
          }
        });

        judges.forEach((judge) => {
          const record = getRecord(judge.institution);
          if (record) {
            record.judges += 1;
          }
        });

        return applyCompetitionRanks(
          Array.from(records.values()).sort(
            (left, right) =>
              Number(right.teamPoints || 0) - Number(left.teamPoints || 0) ||
              Number(right.speaks || 0) - Number(left.speaks || 0) ||
              String(left.institution).localeCompare(String(right.institution)),
          ),
          (left, right) =>
            Number(left.teamPoints || 0) === Number(right.teamPoints || 0) &&
            Number(left.speaks || 0) === Number(right.speaks || 0),
          "finish",
        );
      }

      function getJudgeAnalytics(tournament) {
        const judges = getTournamentJudges(tournament);
        const allocations = getJudgeAllocationsForTournament(tournament);
        const managerFeedbackEntries = getTournamentFeedbackLedgerEntries(tournament);
        const records = judges.map((judge) => {
          const judgeAllocations = allocations.filter(
            (allocation) => normalizeEmail(allocation.judgeEmail) === normalizeEmail(judge.email),
          );
          const judgeFeedbackEntries = managerFeedbackEntries.filter(
            (entry) =>
              normalizeEmail(entry.targetEmail) === normalizeEmail(judge.email) &&
              entry.type === "team_to_judge",
          );
          const peerFeedbackEntries = managerFeedbackEntries.filter(
            (entry) =>
              normalizeEmail(entry.targetEmail) === normalizeEmail(judge.email) &&
              ["wing_to_chair", "chair_to_wing"].includes(String(entry.type || "").trim()),
          );
          const chairAssignments = judgeAllocations.filter(
            (allocation) => normalizeJudgeAllocationRole(allocation.panelRole, "panelist") === "chair",
          ).length;
          const submitted = judgeAllocations.filter((allocation) => allocation.submittedAt).length;
          const checkedIn = judgeAllocations.filter((allocation) => allocation.checkedIn).length;
          const avgPriority = judgeAllocations.length
            ? roundScoreValue(
                judgeAllocations.reduce((sum, allocation) => {
                  const drawEntry = getDrawEntryById(tournament, allocation.drawId);
                  return sum + Number(drawEntry?.priority || 3);
                }, 0) / judgeAllocations.length,
                0,
              )
            : 0;
          const turnaroundValues = judgeAllocations
            .map((allocation) => {
              const drawEntry = getDrawEntryById(tournament, allocation.drawId);
              const publishedKey = normalizeTimestampKey(
                drawEntry?.publishedAtKey,
                drawEntry?.publishedAt,
              );
              const submittedKey = normalizeTimestampKey(
                allocation.submittedAtKey,
                allocation.submittedAt,
              );
              if (!publishedKey || !submittedKey || submittedKey < publishedKey) {
                return null;
              }
              return Math.round((submittedKey - publishedKey) / 60000);
            })
            .filter((value) => value !== null);
          const improvementSamples = judgeAllocations
            .flatMap((allocation) => {
              const drawEntry = getDrawEntryById(tournament, allocation.drawId);
              const slots = Array.isArray(drawEntry?.slots) ? drawEntry.slots : [];
              return slots
                .map((slot) => {
                  const participantIds = Array.isArray(slot.participantIds) ? slot.participantIds : [];
                  const currentScores = participantIds
                    .map((participantId) =>
                      getParticipantAverageSpeakerScoreForDraw(tournament, participantId, drawEntry?.id),
                    )
                    .filter((value) => value !== null);
                  if (!currentScores.length) {
                    return null;
                  }
                  const priorScores = participantIds
                    .flatMap((participantId) => {
                      const participant = getParticipantById(tournament, participantId);
                      return getParticipantSpeakerScoreBreakdown(tournament, participant).filter(
                        (entry) => Number(entry.round || 0) < Number(allocation.round || 0),
                      );
                    })
                    .map((entry) => Number(entry.score || 0))
                    .filter((value) => Number.isFinite(value));
                  if (!priorScores.length) {
                    return null;
                  }
                  return (
                    currentScores.reduce((sum, value) => sum + Number(value || 0), 0) /
                      currentScores.length -
                    priorScores.reduce((sum, value) => sum + Number(value || 0), 0) /
                      priorScores.length
                  );
                })
                .filter((value) => value !== null);
            });

          return {
            judge,
            assigned: judgeAllocations.length,
            chairAssignments,
            panelAssignments: Math.max(0, judgeAllocations.length - chairAssignments),
            checkedIn,
            submitted,
            pending: Math.max(0, judgeAllocations.length - submitted),
            avgPriority,
            avgTurnaround: turnaroundValues.length
              ? roundScoreValue(
                  turnaroundValues.reduce((sum, value) => sum + Number(value || 0), 0) /
                    turnaroundValues.length,
                  0,
                )
              : 0,
            teamFeedbackCount: judgeFeedbackEntries.length,
            avgTeamFeedback: judgeFeedbackEntries.length
              ? roundScoreValue(
                  judgeFeedbackEntries.reduce((sum, entry) => sum + Number(entry.rating || 0), 0) /
                    judgeFeedbackEntries.length,
                  2,
                )
              : 0,
            peerFeedbackCount: peerFeedbackEntries.length,
            avgPeerFeedback: peerFeedbackEntries.length
              ? roundScoreValue(
                  peerFeedbackEntries.reduce((sum, entry) => sum + Number(entry.rating || 0), 0) /
                    peerFeedbackEntries.length,
                  2,
                )
              : 0,
            improvementSignal: improvementSamples.length
              ? roundScoreValue(
                  improvementSamples.reduce((sum, value) => sum + Number(value || 0), 0) /
                    improvementSamples.length,
                  2,
                )
              : 0,
            strengthLabel:
              judgeFeedbackEntries.length && judgeFeedbackEntries.length >= 2
                ? judgeFeedbackEntries.reduce((sum, entry) => sum + Number(entry.rating || 0), 0) /
                    judgeFeedbackEntries.length >=
                  4
                  ? "Strong"
                  : "Needs review"
                : "Building",
          };
        });

        return {
          records: records.sort(
            (left, right) =>
              Number(right.submitted || 0) - Number(left.submitted || 0) ||
              Number(right.assigned || 0) - Number(left.assigned || 0) ||
              String(left.judge.name || left.judge.email).localeCompare(
                String(right.judge.name || right.judge.email),
              ),
          ),
          submittedBallots: allocations.filter((allocation) => allocation.submittedAt).length,
          checkedInJudges: allocations.filter((allocation) => allocation.checkedIn).length,
          averageTurnaround: records.filter((record) => Number(record.avgTurnaround || 0) > 0).length
            ? roundScoreValue(
                records.reduce(
                  (sum, record) =>
                    sum + (Number(record.avgTurnaround || 0) > 0 ? Number(record.avgTurnaround) : 0),
                  0,
                ) /
                  records.filter((record) => Number(record.avgTurnaround || 0) > 0).length,
                0,
              )
            : 0,
        };
      }

      function getFeedbackAllocation(tournament, entry) {
        const allocationId = String(entry?.allocationId || "").trim();
        if (!allocationId) {
          return null;
        }
        return (
          getJudgeAllocationsForTournament(tournament).find(
            (allocation) => String(allocation.id) === allocationId,
          ) || null
        );
      }

      function isOfficialFeedbackEntry(tournament, entry) {
        const allocation = getFeedbackAllocation(tournament, entry);
        if (!allocation) {
          return true;
        }
        if (normalizeJudgeAllocationRole(allocation.panelRole, "chair") !== "chair") {
          return false;
        }
        const officialChair = getChairAllocationForDrawEntry(tournament, allocation.drawId);
        return !officialChair || String(officialChair.id) === String(allocation.id);
      }

      function getOfficialParticipantFeedbackEntries(tournament, participant) {
        return (participant?.feedback || []).filter((entry) =>
          isOfficialFeedbackEntry(tournament, entry),
        );
      }

      function getParticipantVisibleFeedbackEntries(tournament, participant) {
        return [...(participant?.feedback || [])].sort(
          (left, right) =>
            Number(normalizeTimestampKey(right?.createdAtKey, right?.createdAt) || 0) -
              Number(normalizeTimestampKey(left?.createdAtKey, left?.createdAt) || 0) ||
            String(right?.judgeEmail || "").localeCompare(String(left?.judgeEmail || "")),
        );
      }

      function normalizeTournamentFeedbackLedgerEntry(entry = {}) {
        const visibility = String(entry.visibility || "manager_only").trim() || "manager_only";
        return {
          id: String(entry.id || createId("ledger")).trim(),
          type: String(entry.type || "team_to_judge").trim(),
          tournamentId: String(entry.tournamentId || "").trim(),
          drawId: String(entry.drawId || "").trim(),
          allocationId: String(entry.allocationId || "").trim(),
          round: normalizeRoundCount(entry.round, 1),
          room: String(entry.room || "").trim(),
          sourceEmail: normalizeEmail(entry.sourceEmail),
          sourceName: String(entry.sourceName || "").trim(),
          targetEmail: normalizeEmail(entry.targetEmail),
          targetName: String(entry.targetName || "").trim(),
          participantId: String(entry.participantId || "").trim(),
          participantName: String(entry.participantName || "").trim(),
          teamName: String(entry.teamName || "").trim(),
          institution: String(entry.institution || "").trim(),
          rating: normalizeOptionalCount(entry.rating, null, 5),
          note: String(entry.note || "").trim(),
          visibility,
          createdAt: String(entry.createdAt || timestamp()).trim(),
          createdAtKey:
            normalizeTimestampKey(entry.createdAtKey, entry.createdAt) || Date.now(),
        };
      }

      function getTournamentFeedbackLedgerEntries(tournament, filters = {}) {
        return ((tournament?.feedbackLedger || []).map((entry) =>
          normalizeTournamentFeedbackLedgerEntry(entry),
        ))
          .filter((entry) => {
            if (filters.type && String(filters.type).trim() !== String(entry.type).trim()) {
              return false;
            }
            if (
              filters.targetEmail &&
              normalizeEmail(filters.targetEmail) !== normalizeEmail(entry.targetEmail)
            ) {
              return false;
            }
            if (
              filters.allocationId &&
              String(filters.allocationId).trim() !== String(entry.allocationId).trim()
            ) {
              return false;
            }
            if (filters.drawId && String(filters.drawId).trim() !== String(entry.drawId).trim()) {
              return false;
            }
            return true;
          })
          .sort(
            (left, right) =>
              Number(right.createdAtKey || 0) - Number(left.createdAtKey || 0) ||
              String(right.note || "").localeCompare(String(left.note || "")),
          );
      }

      function getExistingJudgeFeedback(participant, allocationId, judgeEmail) {
        return (participant.feedback || []).find(
          (entry) =>
            String(entry.allocationId || "") === String(allocationId || "") &&
            normalizeEmail(entry.judgeEmail) === normalizeEmail(judgeEmail),
        );
      }

      function getJudgeFieldToken(value) {
        return String(value || "")
          .trim()
          .toLowerCase()
          .replace(/[^a-z0-9]+/g, "_")
          .replace(/^_+|_+$/g, "");
      }

      function getJudgeScoreFieldName(participantId, category) {
        return "score_" + participantId + "_" + getJudgeFieldToken(category);
      }

      function getJudgeNoteFieldName(participantId) {
        return "note_" + participantId;
      }

      function getJudgeCrossQuestionFieldName(participantId) {
        return "cross_questions_" + participantId;
      }

      function getJudgeCrossResponseFieldName(participantId) {
        return "cross_responses_" + participantId;
      }

      function getJudgeRebuttalFieldName(participantId) {
        return "rebuttal_" + participantId;
      }

      function getJudgeRoomResultFieldName(slotKey) {
        return "room_result_" + getJudgeFieldToken(slotKey);
      }

      function getJudgeAssignments(email = session.userEmail) {
        const target = normalizeEmail(email);
        const assignments = [];
        state.tournaments.forEach((tournament) => {
          getJudgeAllocationsForTournament(tournament).forEach((allocation) => {
            if (normalizeEmail(allocation.judgeEmail) !== target) {
              return;
            }
            const drawEntry = getDrawEntryById(tournament, allocation.drawId);
            const participants =
              allocation.participantIds?.length
                ? (tournament.participants || [])
                    .map((participant) => normalizeParticipantRecord(participant))
                    .filter((participant) => (allocation.participantIds || []).includes(participant.id))
                : getParticipantsForDrawRecord(tournament, drawEntry);
            assignments.push({
              tournament,
              allocation,
              drawEntry,
              participants,
              judge: getJudgeByEmail(tournament, allocation.judgeEmail),
            });
          });
        });
        return assignments.sort(
          (left, right) =>
            Number(left.allocation.round) - Number(right.allocation.round) ||
          String(left.allocation.room).localeCompare(String(right.allocation.room)),
        );
      }

      function canJudgeAllocationSubmitBallot(tournament, allocation) {
        const normalizedRole = normalizeJudgeAllocationRole(allocation?.panelRole, "panelist");
        if (normalizedRole === "chair") {
          return true;
        }
        return allowsWingBallotsForFormat(getRoundFormat(tournament, allocation?.round));
      }

      function getPeerJudgeAllocationsForRoom(tournament, allocation, role = "panelist") {
        return getJudgeAllocationsForTournament(tournament).filter((entry) => {
          if (String(entry.drawId || "").trim() !== String(allocation?.drawId || "").trim()) {
            return false;
          }
          if (String(entry.id || "").trim() === String(allocation?.id || "").trim()) {
            return false;
          }
          return normalizeJudgeAllocationRole(entry.panelRole, "panelist") === role;
        });
      }

      function renderInternalJudgeFeedbackForms(tournament, allocation) {
        if (!canJudgeAllocationSubmitBallot(tournament, allocation)) {
          return "";
        }
        const role = normalizeJudgeAllocationRole(allocation.panelRole, "panelist");
        const feedbackTargets =
          role === "chair"
            ? getPeerJudgeAllocationsForRoom(tournament, allocation, "panelist").map((entry) => ({
                allocation: entry,
                judge: getJudgeByEmail(tournament, entry.judgeEmail),
                type: "chair_to_wing",
                title: "Manager-only wing feedback",
                prompt: "Share how the wing handled collaboration, reliability, and adjudication quality.",
              }))
            : (() => {
                const chair = getChairAllocationForDrawEntry(tournament, allocation.drawId);
                if (!chair || String(chair.id || "").trim() === String(allocation.id || "").trim()) {
                  return [];
                }
                return [
                  {
                    allocation: chair,
                    judge: getJudgeByEmail(tournament, chair.judgeEmail),
                    type: "wing_to_chair",
                    title: "Manager-only chair feedback",
                    prompt: "Share how the chair handled deliberation, leadership, and ballot quality.",
                  },
                ];
              })();

        if (!feedbackTargets.length) {
          return "";
        }

        return `
          <div class="stack">
            ${feedbackTargets
              .map(
                ({ allocation: targetAllocation, judge, type, title, prompt }) => `
                  <form class="flat-panel stack" data-form="submit-judge-peer-feedback" data-id="${escapeHtml(
                    tournament.id,
                  )}" data-allocation-id="${escapeHtml(allocation.id)}" data-target-allocation-id="${escapeHtml(
                    targetAllocation.id,
                  )}" data-feedback-type="${escapeHtml(type)}">
                    <div class="section-heading">
                      <div>
                        <strong>${escapeHtml(title)}</strong>
                        <p class="muted">${escapeHtml(
                          judge?.name || targetAllocation.judgeEmail,
                        )}</p>
                      </div>
                      <span class="mini-pill success">Managers only</span>
                    </div>
                    <p class="fine-print">${escapeHtml(prompt)}</p>
                    <div class="field-grid two">
                      <label>
                        Rating
                        <select name="rating">
                          <option value="5">5 • Excellent</option>
                          <option value="4">4 • Strong</option>
                          <option value="3">3 • Solid</option>
                          <option value="2">2 • Weak</option>
                          <option value="1">1 • Poor</option>
                        </select>
                      </label>
                      <label>
                        Subject
                        <input type="text" name="targetName" value="${escapeHtml(
                          judge?.name || targetAllocation.judgeEmail,
                        )}" />
                      </label>
                    </div>
                    <label>
                      Feedback
                      <textarea name="note" rows="3" placeholder="Add concise manager-only feedback."></textarea>
                    </label>
                    <button type="submit">Send to managers</button>
                  </form>
                `,
              )
              .join("")}
          </div>
        `;
      }

      function normalizeTournamentRegistrationSettings(record = {}) {
        const hasDebaterOpenSetting =
          Object.prototype.hasOwnProperty.call(record, "debaterOpen") ||
          Object.prototype.hasOwnProperty.call(record, "participantOpen") ||
          Object.prototype.hasOwnProperty.call(record, "debaterRegistrationOpen") ||
          Object.prototype.hasOwnProperty.call(record, "participantRegistrationOpen");
        const hasJudgeOpenSetting =
          Object.prototype.hasOwnProperty.call(record, "judgeOpen") ||
          Object.prototype.hasOwnProperty.call(record, "judgeRegistrationOpen");
        return {
          debaterOpen: hasDebaterOpenSetting
            ? Boolean(
                record.debaterOpen ||
                  record.participantOpen ||
                  record.debaterRegistrationOpen ||
                  record.participantRegistrationOpen,
              )
            : true,
          judgeOpen: hasJudgeOpenSetting
            ? Boolean(record.judgeOpen || record.judgeRegistrationOpen)
            : true,
          debaterNote: String(
            record.debaterNote || record.participantNote || record.debaterRegistrationNote || "",
          ).trim(),
          judgeNote: String(record.judgeNote || record.judgeRegistrationNote || "").trim(),
        };
      }

      function getTournamentRegistrationSettings(tournament) {
        return normalizeTournamentRegistrationSettings(tournament?.registration || {});
      }

      function getTournamentRegistrationAvailability(tournament, role = "debater") {
        const targetRole = String(role || "debater").trim().toLowerCase() === "judge"
          ? "judge"
          : "debater";
        const registration = getTournamentRegistrationSettings(tournament);
        const roleOpen = targetRole === "judge" ? registration.judgeOpen : registration.debaterOpen;
        const issues = [];

        if (String(tournament?.status || "").trim().toLowerCase() !== "open") {
          issues.push("Tournament is closed.");
        }
        if (!roleOpen) {
          issues.push(
            targetRole === "judge"
              ? "Judge registration is turned off in Setup."
              : "Debater registration is turned off in Setup.",
          );
        }

        return {
          role: targetRole,
          open: issues.length === 0,
          roleOpen,
          reason:
            issues[0] ||
            (targetRole === "judge"
              ? "Judge registration is live."
              : "Debater registration is live."),
        };
      }

      function getTournamentRegistrationLinks() {
        return {
          debater: getPublicScreenLink("register-debater"),
          judge: getPublicScreenLink("register-judge"),
        };
      }

      function getOpenRegistrationTournaments(role = "debater") {
        const targetRole = String(role || "debater").trim().toLowerCase();
        return (state.tournaments || [])
          .filter((tournament) => getTournamentRegistrationAvailability(tournament, targetRole).open)
          .sort(
            (left, right) =>
              String(left.name || "").localeCompare(String(right.name || "")) ||
              String(left.code || "").localeCompare(String(right.code || "")),
          );
      }

      function getRegistrationTournamentOptionsMarkup(role = "debater", currentId = "") {
        const tournaments = getOpenRegistrationTournaments(role);
        if (!tournaments.length) {
          return `<option value="">No open tournaments available</option>`;
        }

        return tournaments
          .map(
            (tournament) =>
              `<option value="${escapeHtml(tournament.id)}" ${selected(
                tournament.id,
                currentId,
              )}>${escapeHtml(
                tournament.name + " • " + tournament.code + " • " + getFormatLabel(tournament),
              )}</option>`,
          )
          .join("");
      }

      function createTournamentRecord(payload) {
        const defaults = clone(state.appSettings.defaults);
        const formatPreset = FORMAT_PRESETS[payload.format] || FORMAT_PRESETS["No Standard Format"];
        const participantModel = payload.participantModel || formatPreset.participantModel;
        const rounds = normalizeRoundCount(payload.rounds, defaults.rounds || 1);
        const teamsPerRoom = Object.prototype.hasOwnProperty.call(payload, "teamsPerRoom")
          ? normalizeOptionalCount(payload.teamsPerRoom, null)
          : normalizeOptionalCount(
              formatPreset.teamsPerRoom,
              normalizeOptionalCount(defaults.teamsPerRoom, null),
            );
        const teamSize = Object.prototype.hasOwnProperty.call(payload, "teamSize")
          ? normalizeOptionalCount(payload.teamSize, null)
          : normalizeOptionalCount(
              formatPreset.teamSize,
              normalizeOptionalCount(defaults.teamSize, null),
            );
        const speakersPerSide = Object.prototype.hasOwnProperty.call(payload, "speakersPerSide")
          ? normalizeOptionalCount(payload.speakersPerSide, null)
          : normalizeOptionalCount(
              formatPreset.speakersPerSide,
              normalizeOptionalCount(defaults.speakersPerSide, null),
            );
        const breakSize = Object.prototype.hasOwnProperty.call(payload, "breakSize")
          ? normalizeOptionalBreakSize(payload.breakSize, null)
          : normalizeOptionalBreakSize(defaults.breakSize, null);
        const scoringMethod = getScoringMethodValue(
          payload.format,
          participantModel,
          Object.prototype.hasOwnProperty.call(payload, "scoringMethod")
            ? payload.scoringMethod
            : formatPreset.scoringMethod,
          { preserveBlank: true },
        );

        return {
          id: createId("tournament"),
          code: payload.code || "TBD-" + Math.floor(Math.random() * 900 + 100),
          name: payload.name,
          createdAt: payload.createdAt || timestamp(),
          format: payload.format,
          customFormatName: payload.customFormatName || "",
          participantModel,
          rounds,
          status: "open",
          notes: payload.notes || "",
          announcement: payload.announcement || "",
          config: {
            teamsPerRoom,
            teamSize,
            speakersPerSide,
            randomTeamsAllowed: Object.prototype.hasOwnProperty.call(
              payload,
              "randomTeamsAllowed",
            )
              ? Boolean(payload.randomTeamsAllowed)
              : Boolean(formatPreset.randomTeamsAllowed),
            crossExaminationEnabled: Object.prototype.hasOwnProperty.call(
              payload,
              "crossExaminationEnabled",
            )
              ? Boolean(payload.crossExaminationEnabled)
              : Boolean(formatPreset.crossExaminationEnabled),
            rebuttalEnabled: Object.prototype.hasOwnProperty.call(payload, "rebuttalEnabled")
              ? Boolean(payload.rebuttalEnabled)
              : Boolean(formatPreset.rebuttalEnabled),
            scoringMethod,
            motionStyle: payload.motionStyle || formatPreset.motionStyle,
            breakSize,
            timezone: payload.timezone || "America/Jamaica",
            customRules: payload.customRules || "",
            roundProfiles: buildRoundProfiles(
              rounds,
              {
                teamsPerRoom,
                teamSize,
                speakersPerSide,
              },
              payload.roundProfiles || [],
            ),
          },
          publication: {
            dashboardListed: payload.dashboardListed,
            showPublicStandings: payload.publicStandings,
            showPublicDraw: payload.publicDraw,
            usePublicTeamAliases: Boolean(payload.usePublicTeamAliases),
            showStandingsInPrivatePortal: true,
            showDrawInPrivatePortal: true,
            showFeedbackInPrivatePortal: state.appSettings.portal.showFeedbackInPrivatePortal,
          },
          permissions: normalizeTournamentPermissions({
            managerEmails: [normalizeEmail(MANAGER_EMAIL)],
          }),
          settings: {
            feedbackCategories: clone(state.appSettings.feedback.categories),
          },
          notices: [],
          roundControls: buildRoundControls(rounds),
          registration: normalizeTournamentRegistrationSettings(payload.registration),
          feedbackLedger: Array.isArray(payload.feedbackLedger) ? clone(payload.feedbackLedger) : [],
          judges: [],
          judgeAllocations: [],
          teams: Array.isArray(payload.teams)
            ? payload.teams.map((team) => normalizeTeamRecord(team))
            : [],
          participants: [],
          standings: [],
          draw: [],
          auditLog: [
            {
              id: createId("audit"),
              actor: normalizeEmail(session.userEmail) || normalizeEmail(MANAGER_EMAIL),
              at: timestamp(),
              message: "Tournament created.",
            },
          ],
        };
      }

