        state.users = state.users.map((user) =>
          normalizeEmail(user.email) === normalizeEmail(currentUser.email)
            ? {
                ...user,
                themePreset: targetTheme,
              }
            : user,
        );

        persist("success", THEME_PRESETS[targetTheme].label + " applied to your workspace.");
