      function updateUserPreferences(formData) {
        const currentUser = getCurrentUser();
        if (!currentUser) {
          setFlash("error", "Sign in again before changing personal settings.");
          renderApp();
          return;
        }

        const selectedTheme = String(formData.get("themePreset") || "jade_classic").trim();
        const preferredLandingView = String(
          formData.get("preferredLandingView") || "overview",
        ).trim();
        const allowedLandingViews = getAllowedLandingViews(currentUser.email);

        state.users = state.users.map((user) =>
          normalizeEmail(user.email) === normalizeEmail(currentUser.email)
            ? {
                ...user,
                themePreset: THEME_PRESETS[selectedTheme] ? selectedTheme : "jade_classic",
                preferredLandingView: allowedLandingViews.includes(preferredLandingView)
                  ? preferredLandingView
                  : "overview",
              }
            : user,
        );

        persist("success", "Personal workspace settings saved.");
      }

      async function updateDevicePasswordPreference(formData) {
        const currentUser = getCurrentUser();
        if (!currentUser) {
          setFlash("error", "Sign in again before changing password-saving preferences.");
          renderApp();
          return;
        }

        const shouldSavePassword = boolFromForm(formData, "savePasswordOnDevice");
        const currentPassword = String(formData.get("currentPassword") || "");

        if (!shouldSavePassword) {
          updateAuthPrefsAfterCredentialChoice(currentUser.email, false);
          removePasswordFromDeviceVault(currentUser.email);
          await reduceDevicePasswordAutoSignIn();
          setFlash(
            "success",
            "JADE Hummingbird will stop remembering your device password preference for this account. If you want to fully delete a saved password, remove it from your browser or device password manager too.",
          );
          renderApp();
          return;
        }

        if (!supportsDevicePasswordSaving()) {
          setFlash(
            "error",
            "This browser does not support secure in-app device password saving.",
          );
          renderApp();
          return;
        }

        if (!currentPassword) {
          setFlash("error", "Enter your current password before saving it on this device.");
          renderApp();
          return;
        }

        const passwordCheck = await verifyUserPassword(currentUser, currentPassword);
        if (!passwordCheck.ok) {
          setFlash("error", "That current password is incorrect.");
          renderApp();
          return;
        }

        if (passwordCheck.needsUpgrade) {
          Object.assign(currentUser, await buildSecurePasswordRecord(currentPassword));
          saveState();
        }

        updateAuthPrefsAfterCredentialChoice(currentUser.email, true);
        await savePasswordToDeviceVault(currentUser.email, currentPassword);
        await saveBrowserCredential(currentUser.name, currentUser.email, currentPassword);
        setFlash(
          "success",
          "Your password-saving preference has been updated for this device.",
        );
        renderApp();
      }

      function updateSecurity(formData) {
        if (!canAccessGlobalSettings()) {
          setFlash("error", "Only System Managers can update security settings.");
          renderApp();
          return;
        }

        state.appSettings.auth.allowSelfSignup = boolFromForm(formData, "allowSelfSignup");
        state.appSettings.auth.allowPasswordResetRequests = boolFromForm(
          formData,
          "allowPasswordResetRequests",
        );
        state.appSettings.auth.minimumPasswordLength = numberFromForm(
          formData,
          "minimumPasswordLength",
          10,
        );
        state.appSettings.auth.minimumPasswordLength = Math.max(
          10,
          state.appSettings.auth.minimumPasswordLength,
        );
        persist("success", "Security settings saved.");
      }

